import { motion } from "framer-motion";
import { useNavigate } from "react-router-dom";
import { CreditCard, Calendar, Smartphone as PhoneIcon } from "lucide-react";
import { useProfile } from "@/hooks/useProfile";
import { cn } from "@/lib/utils";
import { formatCurrency } from "@/lib/balanceCalculations";
import type { CreditCard as CreditCardType } from "@/types/creditCard";
import { detectBank } from "@/lib/cardBranding";
import { BankLogo } from "@/components/BankLogo";
import { useCardUsedLimit } from "@/hooks/useCreditCards";

interface CreditCardsCarouselProps {
    cards: CreditCardType[];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    installments: any[];
    selectedMonth: Date;
}

export const CreditCardsCarousel = ({ cards, installments, selectedMonth }: CreditCardsCarouselProps) => {
    const { data: profile } = useProfile();
    const defaultCardId = (profile as any)?.wa_default_expense_card_id;

    if (cards.length === 0) return null;

    // Sort cards: Main first
    const sortedCards = [...cards].sort((a, b) => {
        const isAMain = a.id === defaultCardId;
        const isBMain = b.id === defaultCardId;
        if (isAMain && !isBMain) return -1;
        if (!isAMain && isBMain) return 1;
        return 0;
    });

    return (
        <div className="space-y-4">
            {/* Legend for Main Card */}
            <div className="px-4 pb-2">
                <p className="text-[10px] text-muted-foreground flex items-center gap-1.5 bg-muted/30 w-fit px-3 py-1 rounded-full border border-muted-foreground/10">
                    <span className="w-1.5 h-1.5 rounded-full bg-primary animate-pulse" />
                    Gastos enviados pelo WhatsApp s├úo registrados no cart├úo <span className="text-primary font-bold">Principal</span> por padr├úo.
                </p>
            </div>

            <div
                className="w-full max-w-full pb-6 pt-2 px-1"
                style={{
                    overflowX: 'auto',
                    WebkitOverflowScrolling: 'touch'
                }}
            >
                <div className="flex gap-4 snap-x snap-mandatory min-w-full w-max px-4 sm:px-0">
                    {sortedCards.map((card, index) => (
                        <CreditCardItem
                            key={card.id}
                            card={card}
                            index={index}
                            isMain={card.id === defaultCardId}
                            installments={installments}
                        />
                    ))}
                </div>
            </div>
        </div>
    );
};

interface CreditCardItemProps {
    card: CreditCardType;
    index: number;
    isMain: boolean;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    installments: any[];
}

const CreditCardItem = ({ card, index, isMain, installments }: CreditCardItemProps) => {
    const navigate = useNavigate();
    const { data: globalUsedLimit = 0 } = useCardUsedLimit(card.id);

    // Calculate invoice total for this card for the selected month
    const currentInvoice = installments
        .filter(inst => inst.purchase?.card_id === card.id)
        .reduce((sum, inst) => sum + Number(inst.amount), 0);

    const limit = card.credit_limit || 0;
    const usage = limit > 0 ? (currentInvoice / limit) * 100 : 0;
    const availableLimit = Math.max(0, limit - globalUsedLimit);

    // Detect bank theme for colors
    const bankTheme = detectBank(card.card_name, null);

    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: index * 0.1 }}
            onClick={() => navigate(`/cards/${card.id}`)}
            className="snap-center shrink-0 w-[280px] sm:w-[320px] h-[190px] rounded-[1.8rem] p-6 relative overflow-hidden shadow-large group cursor-pointer transition-all duration-500 border border-white/10"
        >
            {/* Card Dynamic Background with Texture */}
            <div className={cn(
                "absolute inset-0 bg-gradient-to-br transition-all duration-700 group-hover:scale-110",
                bankTheme.gradient || "from-slate-700 to-slate-900"
            )} />

            {/* Subtle Noise/Texture Overlay */}
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]" />

            {/* Premium Gloss Reflection */}
            <div className="absolute -inset-full bg-gradient-to-tr from-transparent via-white/5 to-transparent rotate-45 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000 ease-in-out" />

            {/* Inner Shadow for Depth */}
            <div className="absolute inset-0 shadow-[inset_0_0_40px_rgba(0,0,0,0.2)]" />

            {/* Content Container */}
            <div className="relative z-10 flex flex-col h-full justify-between text-white">
                {/* Top row: Bank Logo & Wireless Icon */}
                <div className="flex justify-between items-start">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-xl bg-white/20 backdrop-blur-md border border-white/30 shadow-soft">
                            <BankLogo
                                bankName={card.card_name}
                                className="w-8 h-8"
                                iconClassName="text-white"
                                size="md"
                            />
                        </div>
                        <div>
                            <p className="text-sm font-bold tracking-tight drop-shadow-md">
                                {card.card_name}
                            </p>
                            <p className="text-[9px] uppercase font-bold tracking-[0.1em] opacity-60">
                                {card.card_brand || "Cr├®dito"}
                            </p>
                        </div>
                    </div>

                    <div className="flex flex-col items-end gap-2">
                        {/* Wireless Icon */}
                        <div className="opacity-40 rotate-90">
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M5 8a10 10 0 0 1 14 0" /><path d="M8.5 11.5a5 5 0 0 1 7 0" /><path d="M12 15a1 1 0 0 1 0 0" />
                            </svg>
                        </div>
                        {isMain && (
                            <div className="flex items-center gap-1 bg-white/20 backdrop-blur-md rounded-full px-2 py-0.5 border border-white/10">
                                <PhoneIcon className="w-2.5 h-2.5 text-white" />
                                <span className="text-[7px] font-black uppercase tracking-widest">Principal</span>
                            </div>
                        )}
                    </div>
                </div>

                {/* Middle row: The metallic Chip */}
                <div className="mt-2 flex items-center justify-between">
                    <div className="w-10 h-8 rounded-md bg-gradient-to-br from-yellow-200 via-yellow-400 to-yellow-600 relative overflow-hidden shadow-inner border border-yellow-700/30">
                        <div className="absolute inset-x-0 top-1/2 h-[1px] bg-black/20" />
                        <div className="absolute inset-y-0 left-1/3 w-[1px] bg-black/20" />
                        <div className="absolute inset-y-0 right-1/3 w-[1px] bg-black/20" />
                    </div>

                    {/* Last 4 digits in monospace premium style */}
                    <div className="text-right">
                        <span className="text-[10px] font-mono tracking-[0.3em] opacity-60 mr-1">ÔÇóÔÇóÔÇóÔÇó</span>
                        <span className="text-sm font-mono font-bold tracking-widest drop-shadow-lg">{card.last_four_digits || "0000"}</span>
                    </div>
                </div>

                {/* Bottom row: Balance & Usage Bar */}
                <div className="mt-auto pt-3">
                    <div className="flex justify-between items-end mb-2">
                        <div className="flex flex-col">
                            <p className="text-[8px] uppercase font-black tracking-widest opacity-60 mb-1">Fatura Atual</p>
                            <p className="text-2xl font-bold tracking-tight drop-shadow-md text-white">
                                {formatCurrency(currentInvoice)}
                            </p>
                        </div>
                        <div className="text-right pb-1">
                            <p className="text-[9px] font-bold opacity-80 mb-0.5">Vence {card.due_day}</p>
                            <p className="text-[8px] opacity-70 uppercase tracking-tighter font-bold text-white/90">
                                Dispon├¡vel: {formatCurrency(availableLimit).split(',')[0]}
                            </p>
                        </div>
                    </div>

                    {/* Visual Usage Bar with Glow */}
                    <div className="h-1.5 w-full bg-black/20 rounded-full overflow-hidden backdrop-blur-sm border border-white/5">
                        <motion.div
                            initial={{ width: 0 }}
                            animate={{ width: `${Math.min(usage, 100)}%` }}
                            transition={{ duration: 1.2, ease: "easeOut" }}
                            className={cn(
                                "h-full rounded-full relative",
                                usage > 90 ? "bg-destructive shadow-[0_0_8px_rgba(239,68,68,0.5)]" : "bg-white/80 shadow-[0_0_8px_rgba(255,255,255,0.3)]"
                            )}
                        >
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent to-white/20" />
                        </motion.div>
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-lg text-base font-medium ring-offset-background transition-all duration-200 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-5 [&_svg]:shrink-0 active:scale-[0.98]",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90 shadow-soft",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90 shadow-soft",
        outline: "border-2 border-input bg-background hover:bg-secondary hover:text-secondary-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-secondary hover:text-secondary-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        // Custom variants for the app
        warm: "gradient-warm text-primary-foreground shadow-medium hover:shadow-large hover:scale-[1.02]",
        calm: "gradient-calm text-essential-foreground shadow-medium hover:shadow-large hover:scale-[1.02]",
        essential: "bg-essential text-essential-foreground hover:bg-essential/90 shadow-soft",
        obligation: "bg-obligation text-obligation-foreground hover:bg-obligation/90 shadow-soft",
        pleasure: "bg-pleasure text-pleasure-foreground hover:bg-pleasure/90 shadow-soft",
        impulse: "bg-impulse text-impulse-foreground hover:bg-impulse/90 shadow-soft",
        soft: "bg-card text-card-foreground border border-border hover:bg-secondary shadow-soft",
      },
      size: {
        default: "h-12 px-6 py-3",
        sm: "h-10 rounded-md px-4 text-sm",
        lg: "h-14 rounded-xl px-8 text-lg",
        xl: "h-16 rounded-xl px-10 text-xl",
        icon: "h-12 w-12",
        "icon-lg": "h-16 w-16 rounded-full",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    );
  }
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";

import { cn } from "@/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";

const cardVariants = cva(
  "rounded-xl border bg-card text-card-foreground transition-all duration-200",
  {
    variants: {
      variant: {
        default: "shadow-soft",
        elevated: "shadow-medium hover:shadow-large",
        glass: "bg-card/80 backdrop-blur-md border-border/50",
        flat: "shadow-none border-0",
        interactive: "shadow-soft hover:shadow-medium hover:scale-[1.01] cursor-pointer",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
);

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, variant, ...props }, ref) => (
    <div
      ref={ref}
      className={cn(cardVariants({ variant, className }))}
      {...props}
    />
  )
);
Card.displayName = "Card";

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex flex-col space-y-1.5 p-6", className)}
    {...props}
  />
));
CardHeader.displayName = "CardHeader";

const CardTitle = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn(
      "font-serif text-2xl font-semibold leading-none tracking-tight",
      className
    )}
    {...props}
  />
));
CardTitle.displayName = "CardTitle";

const CardDescription = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    {...props}
  />
));
CardDescription.displayName = "CardDescription";

const CardContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div ref={ref} className={cn("p-6 pt-0", className)} {...props} />
));
CardContent.displayName = "CardContent";

const CardFooter = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex items-center p-6 pt-0", className)}
    {...props}
  />
));
CardFooter.displayName = "CardFooter";

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent, cardVariants };

import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
));
Command.displayName = CommandPrimitive.displayName;

interface CommandDialogProps extends DialogProps {}

const CommandDialog = ({ children, ...props }: CommandDialogProps) => {
  return (
    <Dialog {...props}>
      <DialogContent className="overflow-hidden p-0 shadow-lg">
        <Command className="[&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground [&_[cmdk-group]:not([hidden])_~[cmdk-group]]:pt-0 [&_[cmdk-group]]:px-2 [&_[cmdk-input-wrapper]_svg]:h-5 [&_[cmdk-input-wrapper]_svg]:w-5 [&_[cmdk-input]]:h-12 [&_[cmdk-item]]:px-2 [&_[cmdk-item]]:py-3 [&_[cmdk-item]_svg]:h-5 [&_[cmdk-item]_svg]:w-5">
          {children}
        </Command>
      </DialogContent>
    </Dialog>
  );
};

const CommandInput = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Input>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Input>
>(({ className, ...props }, ref) => (
  <div className="flex items-center border-b px-3" cmdk-input-wrapper="">
    <Search className="mr-2 h-4 w-4 shrink-0 opacity-50" />
    <CommandPrimitive.Input
      ref={ref}
      className={cn(
        "flex h-11 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50",
        className,
      )}
      {...props}
    />
  </div>
));

CommandInput.displayName = CommandPrimitive.Input.displayName;

const CommandList = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.List>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.List
    ref={ref}
    className={cn("max-h-[300px] overflow-y-auto overflow-x-hidden", className)}
    {...props}
  />
));

CommandList.displayName = CommandPrimitive.List.displayName;

const CommandEmpty = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Empty>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Empty>
>((props, ref) => <CommandPrimitive.Empty ref={ref} className="py-6 text-center text-sm" {...props} />);

CommandEmpty.displayName = CommandPrimitive.Empty.displayName;

const CommandGroup = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Group>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Group>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Group
    ref={ref}
    className={cn(
      "overflow-hidden p-1 text-foreground [&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:py-1.5 [&_[cmdk-group-heading]]:text-xs [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground",
      className,
    )}
    {...props}
  />
));

CommandGroup.displayName = CommandPrimitive.Group.displayName;

const CommandSeparator = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Separator>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Separator>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Separator ref={ref} className={cn("-mx-1 h-px bg-border", className)} {...props} />
));
CommandSeparator.displayName = CommandPrimitive.Separator.displayName;

const CommandItem = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Item>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Item
    ref={ref}
    className={cn(
      "relative flex cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none data-[disabled=true]:pointer-events-none data-[selected='true']:bg-accent data-[selected=true]:text-accent-foreground data-[disabled=true]:opacity-50",
      className,
    )}
    {...props}
  />
));

CommandItem.displayName = CommandPrimitive.Item.displayName;

const CommandShortcut = ({ className, ...props }: React.HTMLAttributes<HTMLSpanElement>) => {
  return <span className={cn("ml-auto text-xs tracking-widest text-muted-foreground", className)} {...props} />;
};
CommandShortcut.displayName = "CommandShortcut";

export {
  Command,
  CommandDialog,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
  CommandShortcut,
  CommandSeparator,
};

import * as React from "react";
import * as LabelPrimitive from "@radix-ui/react-label";
import { Slot } from "@radix-ui/react-slot";
import { Controller, ControllerProps, FieldPath, FieldValues, FormProvider, useFormContext } from "react-hook-form";

import { cn } from "@/lib/utils";
import { Label } from "@/components/ui/label";

const Form = FormProvider;

type FormFieldContextValue<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
  name: TName;
};

const FormFieldContext = React.createContext<FormFieldContextValue>({} as FormFieldContextValue);

const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  ...props
}: ControllerProps<TFieldValues, TName>) => {
  return (
    <FormFieldContext.Provider value={{ name: props.name }}>
      <Controller {...props} />
    </FormFieldContext.Provider>
  );
};

const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext);
  const itemContext = React.useContext(FormItemContext);
  const { getFieldState, formState } = useFormContext();

  const fieldState = getFieldState(fieldContext.name, formState);

  if (!fieldContext) {
    throw new Error("useFormField should be used within <FormField>");
  }

  const { id } = itemContext;

  return {
    id,
    name: fieldContext.name,
    formItemId: `${id}-form-item`,
    formDescriptionId: `${id}-form-item-description`,
    formMessageId: `${id}-form-item-message`,
    ...fieldState,
  };
};

type FormItemContextValue = {
  id: string;
};

const FormItemContext = React.createContext<FormItemContextValue>({} as FormItemContextValue);

const FormItem = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const id = React.useId();

    return (
      <FormItemContext.Provider value={{ id }}>
        <div ref={ref} className={cn("space-y-2", className)} {...props} />
      </FormItemContext.Provider>
    );
  },
);
FormItem.displayName = "FormItem";

const FormLabel = React.forwardRef<
  React.ElementRef<typeof LabelPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root>
>(({ className, ...props }, ref) => {
  const { error, formItemId } = useFormField();

  return <Label ref={ref} className={cn(error && "text-destructive", className)} htmlFor={formItemId} {...props} />;
});
FormLabel.displayName = "FormLabel";

const FormControl = React.forwardRef<React.ElementRef<typeof Slot>, React.ComponentPropsWithoutRef<typeof Slot>>(
  ({ ...props }, ref) => {
    const { error, formItemId, formDescriptionId, formMessageId } = useFormField();

    return (
      <Slot
        ref={ref}
        id={formItemId}
        aria-describedby={!error ? `${formDescriptionId}` : `${formDescriptionId} ${formMessageId}`}
        aria-invalid={!!error}
        {...props}
      />
    );
  },
);
FormControl.displayName = "FormControl";

const FormDescription = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, ...props }, ref) => {
    const { formDescriptionId } = useFormField();

    return <p ref={ref} id={formDescriptionId} className={cn("text-sm text-muted-foreground", className)} {...props} />;
  },
);
FormDescription.displayName = "FormDescription";

const FormMessage = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, children, ...props }, ref) => {
    const { error, formMessageId } = useFormField();
    const body = error ? String(error?.message) : children;

    if (!body) {
      return null;
    }

    return (
      <p ref={ref} id={formMessageId} className={cn("text-sm font-medium text-destructive", className)} {...props}>
        {body}
      </p>
    );
  },
);
FormMessage.displayName = "FormMessage";

export { useFormField, Form, FormItem, FormLabel, FormControl, FormDescription, FormMessage, FormField };

import React from "react";
import { motion, HTMLMotionProps } from "framer-motion";
import { cn } from "@/lib/utils";

interface PageTransitionProps extends HTMLMotionProps<"div"> {
  children: React.ReactNode;
  className?: string;
}

export const PageTransition = React.forwardRef<HTMLDivElement, PageTransitionProps>(
  ({ children, className, ...props }, ref) => {
    return (
      <motion.div
        ref={ref}
