      if (!user) return null;

      const { data, error } = await supabase.rpc("get_monthly_expenses_stats", {
        year_input: targetYear,
        month_input: targetMonth,
      });

      if (error) {
        console.error("Error fetching expense stats:", error);
        throw error;
