        impulse_percentage: 0,
        count: 0,
      };

      return {
        total: Number(stats.total) || 0,
        impulseTotal: Number(stats.impulse_total) || 0,
        impulsePercentage: Number(stats.impulse_percentage) || 0,
        count: Number(stats.count) || 0,
