/**
 * Hook para processar gera├º├Áes autom├íticas de assinaturas
 */
export const useSubscriptionAutoLauncher = () => {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const { data: subs } = useSubscriptions();

    const launch = async () => {
        if (!subs || !user) return;

        const today = new Date();
        const currentMonthStr = format(startOfMonth(today), "yyyy-MM-dd");

        for (const sub of subs) {
            if (sub.status !== 'active') continue;

            // Se j├í foi gerado este m├¬s, pula
            if (sub.last_generated_date && sub.last_generated_date >= currentMonthStr) {
                continue;
            }

            // Se o dia de cobran├ºa j├í passou ou ├® hoje (no m├¬s atual)
            if (today.getDate() >= sub.billing_date) {
                try {
                    if (sub.card_id) {
                        // Lan├ºar no cart├úo
                        await db.from("credit_card_purchases").insert({
                            user_id: user.id,
                            card_id: sub.card_id,
                            description: `Assinatura: ${sub.name}`,
                            total_amount: sub.amount,
                            purchase_date: format(today, "yyyy-MM-dd"),
                            total_installments: 1
                        });
                        // Nota: No mundo ideal, isso geraria as parcelas automaticamente via trigger no banco, 
                        // mas aqui seguimos a l├│gica do hook useCreateCreditCardPurchase.
                        // Para simplicidade, vamos atualizar apenas a sub aqui.
                    } else if (sub.bank_account_id) {
                        // Lan├ºar na conta banc├íria
                        await db.from("expenses").insert({
                            user_id: user.id,
                            bank_account_id: sub.bank_account_id,
                            description: `Assinatura: ${sub.name}`,
                            amount: sub.amount,
                            date: format(today, "yyyy-MM-dd"),
                            category_id: sub.category_id,
                            status: 'confirmed'
                        });
                    }

                    // Marcar como gerada
                    await db
                        .from("subscriptions")
                        .update({ last_generated_date: currentMonthStr })
                        .eq("id", sub.id);

                } catch (err) {
                    console.error(`Falha ao processar assinatura ${sub.name}:`, err);
                }
            }
        }

        queryClient.invalidateQueries({ queryKey: ["subscriptions"] });
        queryClient.invalidateQueries({ queryKey: ["expenses"] });
        queryClient.invalidateQueries({ queryKey: ["cc-purchases"] });
    };

    return { launch };
};

import { useState, useEffect, useCallback, useRef } from "react";
import { UserPreferences } from "@/types/expense";
import { supabase } from "@/lib/backendClient";

const DEFAULT_PREFERENCES: UserPreferences = {
  aiName: "Assistente",
  userChallenge: undefined,
  darkMode: false,
  alertFrequency: "normal",
  connectedBanks: [],
  whatsappConnected: false,
  onboardingCompleted: false,
  fixedIncome: 0,
  variableIncome: 0,
  cryptoEnabled: false,
};

// Keys that are persisted to the backend (profiles table)
const DB_SYNCED_KEYS: (keyof UserPreferences)[] = ["darkMode", "cryptoEnabled"];

// Map frontend key names to DB column names
const KEY_TO_COLUMN: Record<string, string> = {
  darkMode: "dark_mode",
  cryptoEnabled: "crypto_enabled",
};

export function useUserPreferences() {
  const [preferences, setPreferences] = useState<UserPreferences>(() => {
    const stored = localStorage.getItem("user_preferences");
    if (stored) {
      try {
        return { ...DEFAULT_PREFERENCES, ...JSON.parse(stored) };
      } catch {
        return DEFAULT_PREFERENCES;
      }
    }

    // Migrate from old keys if present
    const aiName = localStorage.getItem("ai_name");
    const challenge = localStorage.getItem("user_challenge");
    const completed = localStorage.getItem("onboarding_completed") === "true";
    const fixedIncome = parseFloat(localStorage.getItem("fixed_income") || "0");
    const variableIncome = parseFloat(localStorage.getItem("variable_income") || "0");

    return {
      ...DEFAULT_PREFERENCES,
      aiName: aiName || DEFAULT_PREFERENCES.aiName,
      userChallenge: challenge || undefined,
      onboardingCompleted: completed,
      fixedIncome,
      variableIncome,
    };
  });

  const hasSyncedFromDb = useRef(false);

  // Persist to localStorage on change and sync dark mode class
  useEffect(() => {
    localStorage.setItem("user_preferences", JSON.stringify(preferences));
    document.documentElement.classList.toggle("dark", preferences.darkMode);
  }, [preferences]);

  // On mount (and when auth changes), fetch settings from DB
  useEffect(() => {
    const fetchFromDb = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user?.id) return;

      const { data, error } = await supabase
        .from("profiles")
        .select("dark_mode, crypto_enabled")
        .eq("user_id", session.user.id)
        .maybeSingle() as { data: { dark_mode?: boolean; crypto_enabled?: boolean } | null; error: any };

      if (error) {
        console.error("Error fetching user settings:", error);
        return;
      }

      if (data) {
        hasSyncedFromDb.current = true;
        setPreferences((prev) => ({
          ...prev,
          darkMode: data.dark_mode ?? prev.darkMode,
          cryptoEnabled: data.crypto_enabled ?? prev.cryptoEnabled,
        }));
      }
    };

    fetchFromDb();

    // Also listen for auth changes (login)
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event) => {
        if (event === "SIGNED_IN") {
          hasSyncedFromDb.current = false;
          fetchFromDb();
        }
      }
    );

    return () => subscription.unsubscribe();
  }, []);

  // Save a DB-synced preference to the backend
  const saveToDb = useCallback(async (key: keyof UserPreferences, value: unknown) => {
    const column = KEY_TO_COLUMN[key];
    if (!column) return;

    const { data: { session } } = await supabase.auth.getSession();
    if (!session?.user?.id) return;

    const { error } = await supabase
      .from("profiles")
      .update({ [column]: value } as any)
      .eq("user_id", session.user.id);

    if (error) {
      console.error(`Error saving ${key} to DB:`, error);
    }
  }, []);

  const updatePreference = useCallback(<K extends keyof UserPreferences>(
    key: K,
    value: UserPreferences[K]
  ) => {
    setPreferences((prev) => ({ ...prev, [key]: value }));

    // If this is a DB-synced key, persist to backend
    if (DB_SYNCED_KEYS.includes(key)) {
      saveToDb(key, value);
    }
  }, [saveToDb]);

  const resetPreferences = useCallback(() => {
    // Preserve DB-synced settings during logout
    setPreferences((prev) => ({
      ...DEFAULT_PREFERENCES,
      darkMode: prev.darkMode,
      cryptoEnabled: prev.cryptoEnabled,
    }));
    // Clean up old migration keys only
    localStorage.removeItem("onboarding_completed");
    localStorage.removeItem("ai_name");
    localStorage.removeItem("user_challenge");
    localStorage.removeItem("fixed_income");
    localStorage.removeItem("variable_income");
  }, []);

  return {
    preferences,
    updatePreference,
    resetPreferences,
  };
}

// C├ílculos de saldo do Saldin
// Implementa os 3 tipos de saldo: Bruto, Comprometido e Livre

import { ExpenseRow } from "@/hooks/useExpenses";
import { IncomeRow } from "@/hooks/useIncomes";
import { DebtRow } from "@/hooks/useDebts";
import { Subscription } from "@/types/subscription";
import { startOfMonth, endOfMonth, isWithinInterval, isBefore, isAfter, addMonths, isEqual, format } from "date-fns";
import { getExpensesForMonth } from "@/lib/recurringExpenses";

export interface BalanceBreakdown {
  // Saldo Bruto = Receitas - Gastos j├í pagos
  saldoBruto: number;

  // Saldo Comprometido = Parcelas futuras + D├¡vidas ativas + Contas recorrentes
  saldoComprometido: number;

  // Dinheiro guardado em metas
  saldoGuardado: number;

  // Saldo Livre = Saldo Bruto - Saldo Comprometido - Saldo Guardado
  saldoLivre: number;

  // Detalhamento
  detalhes: {
    receitasTotal: number;
    gastosTotal: number;
    dividasAtivas: number;
    parcelasFuturas: number;
    contasRecorrentes: number;
    assinaturas: number;
    valoresParaTerceiros: number;
    metasGuardadas: number;
  };
}

export interface MonthlyProjection {
  month: Date;
  label: string;
  saldoProjetado: number;
  compromissos: number;
  isNegative: boolean;
}

// Calcular os 3 saldos para um per├¡odo
// Nota: goalsSaved ├® passado como par├ómetro opcional para n├úo acoplar a lib aos hooks
// ccInstallmentsTotal: total de parcelas de cart├úo de cr├®dito no m├¬s (compromisso futuro)
// bankTotal: somat├│rio dos saldos reais das contas banc├írias (base para saldo bruto)
export function calculateBalances(
  incomes: IncomeRow[],
  expenses: ExpenseRow[],
  debts: DebtRow[],
  selectedMonth: Date,
  subscriptions: Subscription[] = [],
  goalsSaved: number = 0,
  ccInstallmentsTotal: number = 0,
  bankTotal?: number
): BalanceBreakdown {
  const monthStart = startOfMonth(selectedMonth);
  const monthEnd = endOfMonth(selectedMonth);

  // Filtrar receitas do m├¬s (incluindo recorrentes)
  // Nota: j├í recebemos os dados filtrados, apenas garantimos a l├│gica aqui tamb├®m
  const filteredIncomes = incomes.filter(income => {
    const incomeDate = new Date(income.date || income.created_at);

    if (income.is_recurring) {
      // Show in all months from the start date onwards
      const incomeStart = startOfMonth(incomeDate);
      return !isBefore(monthStart, incomeStart);
    }

    return isWithinInterval(incomeDate, { start: monthStart, end: monthEnd });
  });

  // Filtrar gastos do m├¬s (incluindo parcelas futuras)
  const filteredExpenses = getExpensesForMonth(expenses, selectedMonth);

  // Calcular d├¡vidas ativas no m├¬s
  const activeDebts = debts.filter(debt => {
    const debtStart = new Date(debt.created_at);
    if (isAfter(debtStart, monthEnd)) return false;

    if (debt.is_installment && debt.total_installments) {
      const monthsFromStart = Math.floor(
        (monthStart.getTime() - debtStart.getTime()) / (30 * 24 * 60 * 60 * 1000)
      );
      return monthsFromStart < debt.total_installments;
    }

    return true;
  });

  // Totais
  const receitasTotal = filteredIncomes.reduce((sum, i) => sum + Number(i.amount), 0);
  const gastosTotal = filteredExpenses.reduce((sum, e) => sum + Number(e.amount), 0);
  const dividasAtivas = activeDebts.reduce((sum, d) => {
    if (d.is_installment) return sum + Number(d.installment_amount || 0);
    return sum + Number(d.total_amount || 0);
  }, 0);

  // Contas recorrentes PENDENTES (compromissos que ainda v├úo sair)
  const contasRecorrentesPendentes = filteredExpenses
    .filter(e => (e.emotion === "essencial" || e.emotion === "pilar") && e.status === "pending")
    .reduce((sum, e) => sum + Number(e.amount), 0);

  // Somar assinaturas ativas que ainda n├úo foram lan├ºadas para este m├¬s ou s├úo meses futuros
  const monthStartStr = format(monthStart, "yyyy-MM-dd");
  const assinaturasPendentes = subscriptions
    .filter(s => s.status === 'active')
    .filter(s => {
      // Se a ├║ltima gera├º├úo foi antes do in├¡cio deste m├¬s selecionado, 
      // significa que ainda n├úo foi lan├ºada/paga para este per├¡odo
      if (!s.last_generated_date) return true;
      return isBefore(startOfMonth(new Date(s.last_generated_date)), monthStart);
    })
    .reduce((sum, s) => {
      if (s.frequency === 'monthly') return sum + Number(s.amount);
      if (s.frequency === 'yearly') {
        // Se for anual, s├│ somamos no m├¬s da cobran├ºa ou dividimos? 
        // Para impacto de saldo comprometido mensal, o ideal ├® o valor real no m├¬s real.
        // Mas como o app usa last_generated_date, vamos considerar o m├¬s da billing_date.
        const billingMonthMatch = true; // Por enquanto simplificado como mensal para proje├º├úo
        return sum + Number(s.amount) / 12; // Seguindo a l├│gica de "custo mensal" do Subscriptions.tsx
      }
      return sum + Number(s.amount);
    }, 0);

  // Calcular parcelas futuras (pr├│ximos 3 meses)
  let parcelasFuturas = 0;
  const futureMonths = [1, 2, 3].map(n => addMonths(selectedMonth, n));

  debts.forEach(debt => {
    if (debt.is_installment && debt.total_installments) {
      const debtStart = new Date(debt.created_at);
      const remainingInstallments = debt.total_installments - (debt.current_installment || 0);

      futureMonths.forEach((futureMonth, index) => {
        if (index < remainingInstallments) {
          parcelasFuturas += Number(debt.installment_amount || 0);
        }
      });
    }
  });

  // Valores para terceiros (placeholder - pode ser expandido)
  const valoresParaTerceiros = 0;

  // C├ílculos principais
  if (bankTotal !== undefined) {
    const confirmedUnlinkedIncome = filteredIncomes
      .filter(i => !(i as any).bank_account_id && (i.status === "received" || i.status === "confirmed" || !i.status))
      .reduce((sum, i) => sum + Number(i.amount), 0);
    const confirmedUnlinkedExpenses = filteredExpenses
      .filter(e => !(e as any).bank_account_id && e.status === "confirmed")
      .reduce((sum, e) => sum + Number(e.amount), 0);
    var saldoBruto = bankTotal + confirmedUnlinkedIncome - confirmedUnlinkedExpenses;
  } else {
    var saldoBruto = receitasTotal - gastosTotal;
  }
  // Saldo Comprometido = o que ainda vai sair este m├¬s
  const saldoComprometido = dividasAtivas + valoresParaTerceiros + ccInstallmentsTotal + contasRecorrentesPendentes + assinaturasPendentes;
  const saldoGuardado = goalsSaved;
  const saldoLivre = saldoBruto - saldoComprometido - saldoGuardado;

  return {
    saldoBruto,
    saldoComprometido,
    saldoGuardado,
    saldoLivre,
    detalhes: {
      receitasTotal,
      gastosTotal,
      dividasAtivas,
      parcelasFuturas,
      contasRecorrentes: contasRecorrentesPendentes,
      assinaturas: assinaturasPendentes,
      valoresParaTerceiros,
      metasGuardadas: goalsSaved,
    },
  };
}

// Calcular proje├º├úo para os pr├│ximos meses
export function calculateMonthlyProjection(
  incomes: IncomeRow[],
  expenses: ExpenseRow[],
  debts: DebtRow[],
  subscriptions: Subscription[],
  startMonth: Date,
  monthsAhead: number = 6
): MonthlyProjection[] {
  const projections: MonthlyProjection[] = [];

  for (let i = 0; i <= monthsAhead; i++) {
    const targetMonth = addMonths(startMonth, i);
    const balance = calculateBalances(incomes, expenses, debts, targetMonth, subscriptions);

    projections.push({
      month: targetMonth,
      label: targetMonth.toLocaleDateString("pt-BR", { month: "short", year: "2-digit" }),
      saldoProjetado: balance.saldoLivre,
      compromissos: balance.saldoComprometido,
      isNegative: balance.saldoLivre < 0,
    });
  }

  return projections;
}

// Formatar moeda
export function formatCurrency(value: number): string {
  return new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(value);
}

// Formatar moeda curta (para cards compactos)
export function formatShortCurrency(value: number): string {
  if (Math.abs(value) >= 1000) {
    return `R$ ${(value / 1000).toFixed(1).replace(".", ",")}k`;
  }
  return formatCurrency(value);
}

import { format } from "date-fns";

interface ExportDataParams {
    incomes: any[];
    expenses: any[];
    debts: any[];
    receivables: any[];
    goals: any[];
    bankAccounts: any[];
    creditCards: any[];
}

export const exportToCSV = ({ incomes, expenses, debts, receivables, goals, bankAccounts, creditCards }: ExportDataParams) => {
    // Helper to escape CSV fields for Excel (PT-BR)
    const escape = (value: any) => {
        if (value === null || value === undefined) return "";
        let stringValue = String(value);

        // Format numbers to PT-BR (comma as decimal)
        if (typeof value === 'number') {
            stringValue = value.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
        }

        // Escape if contains delimiter or quotes or newlines
        if (stringValue.includes(";") || stringValue.includes('"') || stringValue.includes("\n")) {
            return `"${stringValue.replace(/"/g, '""')}"`;
        }
        return stringValue;
    };

    const formatDate = (date: string | Date | undefined) => {
        if (!date) return "";
        return format(new Date(date), "dd/mm/yyyy");
    };

    const rows: string[][] = [];

    // HEADER DA EMPRESA/APP
    rows.push(["SALDIN - RELAT├ôRIO FINANCEIRO COMPLETO"]);
    rows.push([`Gerado em: ${format(new Date(), "dd/mm/yyyy HH:mm")}`]);
    rows.push([]);

    // SECTION 1: CONTAS BANC├üRIAS
    rows.push(["----- RESUMO DE CONTAS BANC├üRIAS -----"]);
    rows.push(["Banco", "Tipo de Conta", "Saldo Atual"]);

    if (bankAccounts.length === 0) {
        rows.push(["Nenhuma conta cadastrada"]);
    } else {
        bankAccounts.forEach(b => {
            rows.push([
                escape(b.bank_name),
                escape(b.account_type === 'checking' ? 'Corrente' : b.account_type === 'savings' ? 'Poupan├ºa' : 'Investimento'),
                escape(Number(b.current_balance))
            ]);
        });
    }
    rows.push([]); // Empty row

    // SECTION 2: CART├òES DE CR├ëDITO
    rows.push(["----- CART├òES DE CR├ëDITO -----"]);
    rows.push(["Nome/Bandeira", "Dia Fechamento", "Dia Vencimento", "Limite Total"]);

    if (creditCards.length === 0) {
        rows.push(["Nenhum cart├úo cadastrado"]);
    } else {
        creditCards.forEach(c => {
            rows.push([
                escape(c.name),
                escape(c.closing_day),
                escape(c.due_day),
                escape(Number(c.limit_amount))
            ]);
        });
    }
    rows.push([]); // Empty row

    // SECTION 3: METAS
    rows.push(["----- METAS FINANCEIRAS -----"]);
    rows.push(["Nome da Meta", "Alvo", "Guardado", "Prazo", "Status"]);

    if (goals.length === 0) {
        rows.push(["Nenhuma meta cadastrada"]);
    } else {
        goals.forEach(g => {
            rows.push([
                escape(g.name),
                escape(Number(g.target_amount)),
                escape(Number(g.current_amount)),
                formatDate(g.target_date),
                escape(g.status === 'completed' ? 'Conclu├¡da' : 'Em andamento')
            ]);
        });
    }
    rows.push([]); // Empty row

    // SECTION 4: EXTRATO (Transa├º├Áes)
    rows.push(["----- EXTRATO DE MOVIMENTA├ç├òES (Receitas, Despesas, D├¡vidas) -----"]);
    rows.push(["Data", "Tipo", "Descri├º├úo", "Categoria", "Valor", "Status", "Detalhes"]);

    // Merge and Sort Transactions
    const transactions = [
        ...incomes.map(i => ({
            date: new Date(i.date || i.created_at),
            type: "Receita",
            desc: i.description,
            cat: i.category?.name || "Outros",
            val: Number(i.amount),
            status: i.status === 'received' ? "Recebido" : "Pendente",
            details: i.is_recurring ? "Recorrente" : ""
        })),
        ...expenses.map(e => ({
            date: new Date(e.date || e.created_at),
            type: "Despesa",
            desc: e.description,
            cat: e.category?.name || "Outros",
            val: -Number(e.amount), // Negative for expenses
            status: e.status === 'paid' ? "Pago" : "Pendente",
            details: e.payment_method
        })),
        ...debts.map(d => ({
            date: new Date(d.created_at),
            type: "D├¡vida",
            desc: d.description,
            cat: "D├¡vidas",
            val: -Number(d.total_amount || 0),
            status: "Ativo",
            details: d.total_installments ? `${d.total_installments}x de R$ ${d.installment_amount}` : 'Valor ├║nico'
        })),
        ...receivables.map(r => ({
            date: new Date(r.created_at),
            type: "A Receber",
            desc: r.description,
            cat: "Empr├®stimos",
            val: Number(r.amount),
            status: r.status === 'received' ? "Recebido" : "Pendente",
            details: r.person_name
        }))
    ].sort((a, b) => b.date.getTime() - a.date.getTime()); // Sort newest first

    if (transactions.length === 0) {
        rows.push(["Nenhuma movimenta├º├úo registrada"]);
    } else {
        transactions.forEach(t => {
            rows.push([
                formatDate(t.date),
                escape(t.type),
                escape(t.desc),
                escape(t.cat),
                escape(t.val),
                escape(t.status),
                escape(t.details)
            ]);
        });
    }

    // Generate CSV content with SEMICOLON for PT-BR Excel compatibility
    const csvContent = rows.map(r => r.join(";")).join("\n");

    // Download with BOM for UTF-8 fix in Excel
    const blob = new Blob(["\ufeff" + csvContent], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `saldin_balanco_${format(new Date(), "yyyy-MM-dd")}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

