  ];

  const cardH = 16;
  const cardGap = 3;

  for (let i = 0; i < summaryItems.length; i += 2) {
    y = pageCheck(doc, y, cardH + 4);
    for (let j = 0; j < 2 && i + j < summaryItems.length; j++) {
