    label: "M├¡nimo de 8 caracteres",
    test: (password: string) => password.length >= 8,
  },
  {
    id: "uppercase",
    label: "Pelo menos 1 letra mai├║scula",
    test: (password: string) => /[A-Z]/.test(password),
  },
  {
    id: "lowercase",
