          <div className="flex items-center justify-between p-4 rounded-xl bg-card border border-border shadow-soft">
            <div>
              <p className="text-sm font-medium">Definir como conta principal</p>
              <p className="text-xs text-muted-foreground">Usar para transa├º├Áes autom├íticas via WhatsApp</p>
            </div>
            <Switch
              checked={isMainAccount}
              onCheckedChange={(checked) => {
                if (checked && existingIncomeAccId) {
                  setShowConfirm(true);
                } else {
                  setIsMainAccount(checked);
                }
              }}
            />
          </div>
        </FadeIn>

        <AlertDialog open={showConfirm} onOpenChange={setShowConfirm}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Substituir conta principal?</AlertDialogTitle>
              <AlertDialogDescription>
                A conta <strong>{existingIncomeAcc?.bank_name}</strong> j├í est├í definida como principal.
                Deseja que esta nova conta passe a ser a padr├úo para o WhatsApp?
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel onClick={() => setIsMainAccount(false)}>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={() => {
                setIsMainAccount(true);
                setShowConfirm(false);
              }}>
                Sim, substituir
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
