              <div className="mt-4 flex justify-between text-sm">
                <div>
                  <p className="text-xs opacity-60">Limite</p>
                  <p className="font-semibold">{limit ? `R$ ${limit}` : "ÔÇö"}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs opacity-60">Vencimento</p>
                  <p className="font-medium">{dueDay ? `Dia ${dueDay}` : "ÔÇö"}</p>
                </div>
              </div>
            </div>
          </div>

          {/* Bank Selector */}
          <div className="space-y-3">
            <label className="text-sm text-muted-foreground">Banco emissor</label>
            <div
              className="flex gap-4 overflow-x-auto pb-4 snap-x snap-mandatory no-scrollbar"
              style={{ WebkitOverflowScrolling: 'touch' }}
            >
              {BANK_LIST.filter(b => b.key !== "outros").map(bank => (
                <button
                  key={bank.key}
                  onClick={() => handleBankSelect(bank.key)}
                  className="flex flex-col items-center gap-2 min-w-[64px] snap-center group"
                >
                  <div className={cn(
                    "w-14 h-14 rounded-full flex items-center justify-center transition-all border-2 shadow-sm",
                    selectedBank === bank.key
                      ? "border-primary ring-2 ring-primary/20 ring-offset-2 scale-110"
                      : "border-border bg-card group-hover:border-primary/50"
                  )}
                    style={{ backgroundColor: selectedBank === bank.key ? bank.color : "#ffffff" }}
                  >
                    {selectedBank === bank.key ? (
                      <Check className="w-6 h-6 text-white" />
                    ) : (
                      <BankLogo bankName={bank.name} color={bank.color} size="lg" />
                    )}
                  </div>
                  <span className={cn(
                    "text-[10px] font-medium text-center truncate w-full transition-colors",
                    selectedBank === bank.key ? "text-primary" : "text-muted-foreground"
                  )}>
                    {bank.name}
                  </span>
                </button>
              ))}

              <button
                onClick={() => handleBankSelect("outros")}
                className="flex flex-col items-center gap-2 min-w-[64px] snap-center group"
              >
                <div className={cn(
                  "w-12 h-12 rounded-full flex items-center justify-center transition-all border-2 shadow-sm bg-muted",
                  selectedBank === "outros"
                    ? "border-primary ring-2 ring-primary/20 ring-offset-2 scale-110"
                    : "border-border group-hover:border-primary/50"
                )}>
                  {selectedBank === "outros" ? (
                    <Check className="w-5 h-5 text-primary" />
                  ) : (
                    <span className="text-[10px] font-bold text-muted-foreground">...</span>
                  )}
                </div>
                <span className={cn(
                  "text-[10px] font-medium text-center truncate w-full transition-colors",
                  selectedBank === "outros" ? "text-primary" : "text-muted-foreground"
                )}>
                  Outro
                </span>
              </button>
            </div>
          </div>

          {/* Name */}
          <div className="space-y-2">
            <label className="text-sm text-muted-foreground">Nome do cart├úo *</label>
            <Input
              placeholder="Ex: Nubank ÔÇô Compras, Ita├║ ÔÇô Viagens"
              value={cardName}
              onChange={e => setCardName(e.target.value)}
              maxLength={30}
            />
          </div>

          {/* Brand - Horizontal Scroll */}
          <div className="space-y-3">
            <label className="text-sm text-muted-foreground">Bandeira</label>
            <div
              className="flex gap-4 overflow-x-auto pb-4 snap-x snap-mandatory no-scrollbar"
              style={{ WebkitOverflowScrolling: 'touch' }}
            >
              {BRAND_LIST.map(brand => (
                <button
                  key={brand.key}
                  onClick={() => setCardBrand(brand.name)}
                  className="flex flex-col items-center gap-2 min-w-[64px] snap-center group"
                >
                  <div className={cn(
                    "w-12 h-12 rounded-full flex items-center justify-center transition-all border-2 shadow-sm font-bold text-white",
                    cardBrand === brand.name
                      ? "ring-2 ring-primary/20 ring-offset-2 scale-110"
                      : "border-border bg-card group-hover:border-primary/50"
                  )}
                    style={{ backgroundColor: brand.color }}
                  >
                    {cardBrand === brand.name ? (
                      <Check className="w-5 h-5 text-white" />
                    ) : (
                      <span className="text-xs">{brand.abbr}</span>
                    )}
                  </div>
                  <span className={cn(
                    "text-[10px] font-medium text-center truncate w-full transition-colors",
                    cardBrand === brand.name ? "text-primary" : "text-muted-foreground"
                  )}>
                    {brand.name}
                  </span>
                </button>
              ))}

              {/* Other Brand */}
              <button
                onClick={() => setCardBrand("Outra")}
                className="flex flex-col items-center gap-2 min-w-[64px] snap-center group"
              >
                <div className={cn(
                  "w-12 h-12 rounded-full flex items-center justify-center transition-all border-2 shadow-sm font-bold bg-muted",
                  cardBrand === "Outra"
                    ? "ring-2 ring-primary/20 ring-offset-2 scale-110 border-primary"
                    : "border-border group-hover:border-primary/50"
                )}>
                  {cardBrand === "Outra" ? (
                    <Check className="w-5 h-5 text-primary" />
                  ) : (
                    <span className="text-xs text-muted-foreground">...</span>
                  )}
                </div>
                <span className={cn(
                  "text-[10px] font-medium text-center truncate w-full transition-colors",
                  cardBrand === "Outra" ? "text-primary" : "text-muted-foreground"
                )}>
                  Outra
                </span>
              </button>
            </div>
          </div>

          {/* Last 4 digits */}
          <div className="space-y-2">
            <label className="text-sm text-muted-foreground">├Ültimos 4 d├¡gitos</label>
            <Input
              placeholder="1234"
              value={lastFour}
              onChange={e => {
                const v = e.target.value.replace(/\D/g, "").slice(0, 4);
                setLastFour(v);
              }}
              maxLength={4}
              inputMode="numeric"
            />
          </div>

          {/* Limit */}
          <div className="space-y-2">
            <label className="text-sm text-muted-foreground">Limite total</label>
            <Input
              placeholder="5.000,00"
              value={limit}
              onChange={e => {
                const digits = e.target.value.replace(/[^\d]/g, "");
                setLimit(digits ? formatCurrencyInput(digits) : "");
              }}
              inputMode="numeric"
            />
          </div>

          {/* Closing & Due days */}
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-2">
              <label className="text-sm text-muted-foreground">Dia de fechamento *</label>
              <Input
                placeholder="Ex: 15"
                value={closingDay}
                onChange={e => {
                  const v = e.target.value.replace(/\D/g, "");
                  if (!v || (parseInt(v) >= 1 && parseInt(v) <= 31)) setClosingDay(v);
                }}
                inputMode="numeric"
                maxLength={2}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm text-muted-foreground">Dia de vencimento *</label>
              <Input
                placeholder="Ex: 25"
                value={dueDay}
                onChange={e => {
                  const v = e.target.value.replace(/\D/g, "");
                  if (!v || (parseInt(v) >= 1 && parseInt(v) <= 31)) setDueDay(v);
                }}
                inputMode="numeric"
                maxLength={2}
              />
            </div>
          </div>

          {/* Main card toggle */}
          <div className="flex items-center justify-between p-4 rounded-xl bg-card border border-border shadow-soft">
            <div>
              <p className="text-sm font-medium">Definir como cart├úo principal</p>
              <p className="text-xs text-muted-foreground">Usar para gastos autom├íticos via WhatsApp</p>
            </div>
            <Switch
              checked={isMainCard}
              onCheckedChange={(checked) => {
                if (checked && existingCardId) {
                  setShowConfirm(true);
                } else {
                  setIsMainCard(checked);
                }
              }}
            />
          </div>
        </FadeIn>

        <AlertDialog open={showConfirm} onOpenChange={setShowConfirm}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Substituir cart├úo principal?</AlertDialogTitle>
              <AlertDialogDescription>
                O cart├úo <strong>{existingCard?.card_name}</strong> j├í est├í definido como principal.
                Deseja que este novo cart├úo passe a ser o padr├úo para o WhatsApp?
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel onClick={() => setIsMainCard(false)}>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={() => {
                setIsMainCard(true);
                setShowConfirm(false);
              }}>
                Sim, substituir
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </main>

      {/* Footer */}
      <div className="px-5 pb-safe-bottom">
        <div className="pb-4 flex gap-3">
          <Button variant="outline" size="lg" className="flex-1 h-14" onClick={handleCancel}>
            Cancelar
          </Button>
          <Button
            variant="warm"
            size="lg"
            className="flex-1 h-14 gap-2"
            onClick={handleSubmit}
            disabled={!canSubmit || createCard.isPending}
          >
            {createCard.isPending ? <Loader2 className="w-5 h-5 animate-spin" /> : <Check className="w-5 h-5" />}
            Salvar
          </Button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import {
    ChevronLeft,
    CreditCard,
    Landmark,
    Calendar as CalendarIcon,
    DollarSign,
    Tag,
    Loader2,
    CheckCircle2,
    Sparkles,
    Search,
    Info,
    ArrowRight
} from "lucide-react";
import { FadeIn, PageTransition } from "@/components/ui/motion";
import { useCreateSubscription } from "@/hooks/useSubscriptions";
import { useCreditCards } from "@/hooks/useCreditCards";
import { useBankAccounts } from "@/hooks/useBankAccounts";
import { useAllCategories } from "@/hooks/useCategories";
import { cn } from "@/lib/utils";
import { formatCurrency, parseCurrency, formatCurrencyInput } from "@/lib/currency";
import { BankLogo } from "@/components/BankLogo";

const vibrate = () => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        navigator.vibrate(10);
    }
};

const STEPS = {
    BASIC_INFO: 1,
    PAYMENT: 2,
    REVIEW: 3
};

const SERVICE_CATEGORIES: Record<string, string> = {
    "netflix": "assinaturas_lazer",
    "spotify": "assinaturas_lazer",
    "prime video": "assinaturas_lazer",
    "amazon prime": "assinaturas_lazer",
    "hbo": "assinaturas_lazer",
    "disney": "assinaturas_lazer",
    "youtube": "assinaturas_lazer",
    "apple": "assinaturas_lazer",
    "globo": "assinaturas_lazer",
    "smartfit": "academia",
    "bluefit": "academia",
    "totalpass": "academia",
    "gympass": "academia",
    "vivo": "internet_tv_tel",
    "claro": "internet_tv_tel",
    "tim": "internet_tv_tel",
    "oi": "internet_tv_tel",
    "sabesp": "agua_saneamento",
    "enel": "energia_eletrica",
    "cpfl": "energia_eletrica",
    "sem parar": "transporte_publico",
    "veloe": "transporte_publico",
    "conectcar": "transporte_publico",
    "chatgpt": "educacao_geral",
    "midjourney": "educacao_geral",
    "adobe": "educacao_geral",
};

export default function AddSubscription() {
    const navigate = useNavigate();
    const createSub = useCreateSubscription();
    const { data: cards = [] } = useCreditCards();
    const { data: accounts = [] } = useBankAccounts();
    const { allCategories } = useAllCategories();

    const [currentStep, setCurrentStep] = useState(STEPS.BASIC_INFO);
    const [formData, setFormData] = useState({
        name: "",
        amount: "",
        billing_date: new Date().getDate(),
        frequency: "monthly" as any,
        payment_type: "card" as "card" | "account",
        payment_id: "",
        category_id: ""
    });

    // Auto-select category
    useEffect(() => {
        if (!formData.name) return;

        const lowerName = formData.name.toLowerCase();
        // Check for exact headers or partial matches
        for (const [key, catId] of Object.entries(SERVICE_CATEGORIES)) {
            if (lowerName.includes(key)) {
                // Determine if we should override. Only if category is empty or was auto-set (we'd need to track that, but for now simple overwrite if empty)
                if (!formData.category_id) {
                    // Start search in all categories to find the ID (some might be custom)
                    const category = allCategories.find(c => c.id === catId || c.name.toLowerCase() === key);
                    if (category) {
                        setFormData(prev => ({ ...prev, category_id: category.id }));
                    } else {
                        // Default fallback ids
                        const defaultCat = allCategories.find(c => c.id === catId);
                        if (defaultCat) setFormData(prev => ({ ...prev, category_id: defaultCat.id }));
                    }
                }
                break;
            }
        }
    }, [formData.name, allCategories]);

    const selectedPayment = formData.payment_type === 'card'
        ? cards.find(c => c.id === formData.payment_id)
        : accounts.find(a => a.id === formData.payment_id);

    const selectedCategory = allCategories.find(c => c.id === formData.category_id);

    const isStep1Valid = formData.name && formData.amount && formData.billing_date;
    const isStep2Valid = formData.payment_id;

    const handleSubmit = (e?: React.FormEvent) => {
        if (e) e.preventDefault();
        if (!formData.name || !formData.amount || !formData.payment_id) return;

        createSub.mutate({
            name: formData.name,
            amount: parseCurrency(formData.amount),
            billing_date: Number(formData.billing_date),
            frequency: formData.frequency,
            category_id: formData.category_id || undefined,
            card_id: formData.payment_type === 'card' ? formData.payment_id : undefined,
            bank_account_id: formData.payment_type === 'account' ? formData.payment_id : undefined,
            status: 'active'
        }, {
            onSuccess: () => navigate("/subscriptions")
        });
    };

    const nextStep = () => {
        if (currentStep === STEPS.BASIC_INFO && isStep1Valid) setCurrentStep(STEPS.PAYMENT);
        else if (currentStep === STEPS.PAYMENT && isStep2Valid) setCurrentStep(STEPS.REVIEW);
    };

    const prevStep = () => {
        if (currentStep === STEPS.PAYMENT) setCurrentStep(STEPS.BASIC_INFO);
        else if (currentStep === STEPS.REVIEW) setCurrentStep(STEPS.PAYMENT);
        else navigate("/subscriptions");
    };

    return (
        <PageTransition>
            <div className="min-h-screen bg-background pb-32">
                {/* Header Premium */}
                <header className="px-5 pt-safe-top bg-background/80 backdrop-blur-xl sticky top-0 z-30 border-b border-border/50">
                    <div className="py-4 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={prevStep}
                                className="rounded-full hover:bg-muted"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </Button>
                            <div>
                                <h1 className="font-serif text-lg font-bold">Assinatura</h1>
                                <p className="text-[10px] text-muted-foreground uppercase tracking-widest leading-none">
                                    Passo {currentStep} de 3
                                </p>
                            </div>
                        </div>
                        <div className="flex gap-1">
                            {[1, 2, 3].map(s => (
                                <div
                                    key={s}
                                    className={cn(
                                        "h-1 rounded-full transition-all duration-300",
                                        currentStep === s ? "w-6 bg-primary" : "w-1.5 bg-muted"
                                    )}
                                />
                            ))}
                        </div>
                    </div>
                </header>

                <main className="px-6 pt-8 max-w-lg mx-auto">
                    <AnimatePresence mode="wait">
                        {currentStep === STEPS.BASIC_INFO && (
                            <motion.div
                                key="step1"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                className="space-y-8"
                            >
                                <div className="space-y-2">
                                    <h2 className="text-2xl font-serif font-bold tracking-tight">O que vamos assinar hoje?</h2>
                                    <p className="text-sm text-muted-foreground">Preencha os detalhes b├ísicos do servi├ºo.</p>
                                </div>

                                <div className="space-y-6">
                                    <div className="flex justify-center">
                                        <div className="relative group">
                                            <div className="absolute inset-0 bg-primary/10 blur-2xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity" />
                                            <div className="w-24 h-24 rounded-[2rem] bg-card border-2 border-dashed border-muted flex items-center justify-center relative overflow-hidden ring-offset-background transition-all group-hover:border-primary/50">
                                                {formData.name ? (
                                                    <div className="p-4">
                                                        <BankLogo bankName={formData.name} className="w-16 h-16 scale-125" />
                                                    </div>
                                                ) : (
                                                    <Sparkles className="w-8 h-8 text-muted-foreground/30 animate-pulse" />
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <Label className="text-xs font-bold uppercase tracking-widest text-muted-foreground ml-1">Servi├ºo</Label>
                                            <div className="relative">
                                                <Input
                                                    placeholder="Netflix, Spotify, Academia..."
                                                    value={formData.name}
                                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                                    className="h-16 rounded-2xl bg-card border-muted-foreground/10 text-lg px-12 focus:ring-primary/20"
                                                />
                                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground/50" />
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-2">
                                                <Label className="text-xs font-bold uppercase tracking-widest text-muted-foreground ml-1">Valor</Label>
                                                <div className="relative">
                                                    <Input
                                                        type="text"
                                                        inputMode="numeric"
                                                        placeholder="0,00"
                                                        value={formData.amount}
                                                        onChange={(e) => {
                                                            vibrate();
                                                            setFormData({ ...formData, amount: formatCurrencyInput(e.target.value) });
                                                        }}
                                                        className="h-16 rounded-2xl bg-card border-muted-foreground/10 text-lg px-12"
                                                    />
                                                    <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground/50" />
                                                </div>
                                            </div>
                                            <div className="space-y-2">
                                                <Label className="text-xs font-bold uppercase tracking-widest text-muted-foreground ml-1">Vencimento</Label>
                                                <div className="relative">
                                                    <Input
                                                        type="number"
                                                        min="1"
                                                        max="31"
                                                        value={formData.billing_date}
                                                        onChange={(e) => {
                                                            vibrate();
                                                            setFormData({ ...formData, billing_date: Number(e.target.value) });
                                                        }}
                                                        className="h-16 rounded-2xl bg-card border-muted-foreground/10 text-lg px-12 text-center"
                                                    />
                                                    <CalendarIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground/50" />
                                                </div>
                                            </div>
                                        </div>

                                        <Label className="text-xs font-bold uppercase tracking-widest text-muted-foreground ml-1">Categoria</Label>

                                        {selectedCategory ? (
                                            <div className="flex items-center gap-2 p-3 bg-card border border-primary/20 rounded-xl shadow-sm">
                                                <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                                                    <selectedCategory.icon className="w-5 h-5" />
                                                </div>
                                                <div className="flex-1">
                                                    <p className="text-sm font-bold">{selectedCategory.name}</p>
                                                    <p className="text-[10px] text-muted-foreground">Selecionada automaticamente</p>
                                                </div>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="text-xs h-8"
                                                    onClick={() => setFormData({ ...formData, category_id: "" })}
                                                >
                                                    Alterar
                                                </Button>
                                            </div>
                                        ) : (
                                            <div className="relative">
                                                <select
                                                    className="w-full h-12 pl-4 pr-10 rounded-xl bg-card border-border appearance-none text-sm font-medium focus:ring-primary/20 focus:border-primary transition-all"
                                                    value={formData.category_id}
                                                    onChange={(e) => setFormData({ ...formData, category_id: e.target.value })}
                                                >
                                                    <option value="">Selecionar categoria...</option>
                                                    {allCategories.map((cat) => (
                                                        <option key={cat.id} value={cat.id}>
                                                            {cat.name}
                                                        </option>
                                                    ))}
                                                </select>
                                                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-muted-foreground">
                                                    <Tag className="w-4 h-4" />
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </motion.div>
                        )}

                        {currentStep === STEPS.PAYMENT && (
                            <motion.div
                                key="step2"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                className="space-y-8"
                            >
                                <div className="space-y-2">
                                    <h2 className="text-2xl font-serif font-bold tracking-tight">Qual a origem do pagamento?</h2>
                                    <p className="text-sm text-muted-foreground">Escolha o cart├úo ou conta banc├íria.</p>
                                </div>

                                <div className="space-y-6">
                                    <div className="flex p-1 bg-muted/30 rounded-2xl">
                                        <button
                                            type="button"
                                            onClick={() => setFormData({ ...formData, payment_type: 'card', payment_id: "" })}
                                            className={cn(
                                                "flex-1 flex items-center justify-center gap-2 h-12 rounded-xl text-sm font-bold transition-all",
                                                formData.payment_type === 'card' ? "bg-card shadow-sm text-foreground" : "text-muted-foreground"
                                            )}
                                        >
                                            <CreditCard className="w-4 h-4" />
                                            Cart├úo
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => setFormData({ ...formData, payment_type: 'account', payment_id: "" })}
                                            className={cn(
                                                "flex-1 flex items-center justify-center gap-2 h-12 rounded-xl text-sm font-bold transition-all",
                                                formData.payment_type === 'account' ? "bg-card shadow-sm text-foreground" : "text-muted-foreground"
                                            )}
                                        >
                                            <Landmark className="w-4 h-4" />
                                            Conta
                                        </button>
                                    </div>

                                    <div className="space-y-3">
                                        {formData.payment_type === 'card' ? (
                                            cards.length === 0 ? (
                                                <div className="text-center py-12 bg-muted/10 rounded-3xl border-2 border-dashed border-muted">
                                                    <CreditCard className="w-10 h-10 text-muted/30 mx-auto mb-3" />
                                                    <p className="text-sm text-muted-foreground">Nenhum cart├úo cadastrado</p>
                                                    <Button variant="link" className="mt-2 text-primary" onClick={() => navigate("/cards/add")}>
                                                        Adicionar Cart├úo
                                                    </Button>
                                                </div>
                                            ) : (
                                                cards.map((card) => (
                                                    <motion.div
                                                        key={card.id}
                                                        whileTap={{ scale: 0.98 }}
                                                        onClick={() => setFormData({ ...formData, payment_id: card.id })}
                                                        className={cn(
                                                            "p-5 rounded-3xl border-2 cursor-pointer transition-all flex items-center gap-4 relative overflow-hidden",
                                                            formData.payment_id === card.id
                                                                ? "border-primary bg-primary/5 shadow-md"
                                                                : "border-muted bg-card hover:border-muted-foreground/30"
                                                        )}
                                                    >
                                                        <div className={cn(
                                                            "w-12 h-12 rounded-2xl flex items-center justify-center shrink-0 transition-colors",
                                                            formData.payment_id === card.id ? "bg-primary/20 text-primary" : "bg-muted text-muted-foreground"
                                                        )}>
                                                            <CreditCard className="w-6 h-6" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <p className="font-bold">{card.card_name}</p>
                                                            <p className="text-xs text-muted-foreground">Final {card.last_four_digits} ┬À Vence dia {card.due_day}</p>
                                                        </div>
                                                        {formData.payment_id === card.id && (
                                                            <div className="w-6 h-6 rounded-full bg-primary flex items-center justify-center text-primary-foreground">
                                                                <CheckCircle2 className="w-4 h-4" />
                                                            </div>
                                                        )}
                                                    </motion.div>
                                                ))
                                            )
                                        ) : (
                                            accounts.length === 0 ? (
                                                <div className="text-center py-12 bg-muted/10 rounded-3xl border-2 border-dashed border-muted">
                                                    <Landmark className="w-10 h-10 text-muted/30 mx-auto mb-3" />
                                                    <p className="text-sm text-muted-foreground">Nenhuma conta cadastrada</p>
                                                    <Button variant="link" className="mt-2 text-primary" onClick={() => navigate("/banks")}>
                                                        Adicionar Conta
                                                    </Button>
                                                </div>
                                            ) : (
                                                accounts.map((acc) => (
                                                    <motion.div
                                                        key={acc.id}
                                                        whileTap={{ scale: 0.98 }}
                                                        onClick={() => setFormData({ ...formData, payment_id: acc.id })}
                                                        className={cn(
                                                            "p-5 rounded-3xl border-2 cursor-pointer transition-all flex items-center gap-4 relative overflow-hidden",
                                                            formData.payment_id === acc.id
                                                                ? "border-primary bg-primary/5 shadow-md"
                                                                : "border-muted bg-card hover:border-muted-foreground/30"
                                                        )}
                                                    >
                                                        <div className={cn(
                                                            "w-12 h-12 rounded-2xl flex items-center justify-center shrink-0 transition-colors",
                                                            formData.payment_id === acc.id ? "bg-primary/20 text-primary" : "bg-muted text-muted-foreground"
                                                        )}>
                                                            <Landmark className="w-6 h-6" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <p className="font-bold">{acc.bank_name}</p>
                                                            <p className="text-xs text-muted-foreground">{acc.account_type === 'checking' ? 'Conta Corrente' : 'Poupan├ºa'}</p>
                                                        </div>
                                                        {formData.payment_id === acc.id && (
                                                            <div className="w-6 h-6 rounded-full bg-primary flex items-center justify-center text-primary-foreground">
                                                                <CheckCircle2 className="w-4 h-4" />
                                                            </div>
                                                        )}
                                                    </motion.div>
                                                ))
                                            )
                                        )}
                                    </div>
                                </div>
                            </motion.div>
                        )}

                        {currentStep === STEPS.REVIEW && (
                            <motion.div
                                key="step3"
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="space-y-8"
                            >
                                <div className="space-y-2 text-center">
                                    <div className="inline-flex p-3 rounded-full bg-essential/10 text-essential mb-2">
                                        <Sparkles className="w-6 h-6" />
                                    </div>
                                    <h2 className="text-2xl font-serif font-bold tracking-tight">Tudo pronto!</h2>
                                    <p className="text-sm text-muted-foreground px-8">Revise os detalhes antes de confirmar sua nova assinatura.</p>
                                </div>

                                <Card className="overflow-hidden border-2 border-primary/20 shadow-xl bg-card">
                                    <div className="bg-primary/5 p-6 flex flex-col items-center border-b border-primary/10">
                                        <div className="w-20 h-20 rounded-3xl bg-white shadow-lg flex items-center justify-center mb-4 ring-4 ring-primary/5">
                                            <BankLogo bankName={formData.name} className="w-14 h-14" />
                                        </div>
                                        <h3 className="text-xl font-bold">{formData.name}</h3>
                                        <p className="text-primary font-serif text-2xl font-bold mt-1">
                                            {formatCurrency(parseCurrency(formData.amount))}
                                            <span className="text-xs font-sans text-muted-foreground ml-1">/m├¬s</span>
                                        </p>
                                    </div>

                                    <div className="p-6 space-y-4">
                                        <div className="flex items-center justify-between py-2 border-b border-muted">
                                            <div className="flex items-center gap-2 text-muted-foreground">
                                                <CalendarIcon className="w-4 h-4" />
                                                <span className="text-sm">Vencimento</span>
                                            </div>
                                            <span className="font-bold">Todo dia {formData.billing_date}</span>
                                        </div>

                                        <div className="flex items-center justify-between py-2 border-b border-muted">
                                            <div className="flex items-center gap-2 text-muted-foreground">
                                                <CreditCard className="w-4 h-4" />
                                                <span className="text-sm">Pagamento</span>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-sm font-bold">
                                                    {(selectedPayment as any)?.card_name || (selectedPayment as any)?.bank_name}
                                                </p>
                                                <p className="text-[10px] text-muted-foreground">
                                                    {formData.payment_type === 'card' ? 'Cart├úo de Cr├®dito' : 'D├®bito em Conta'}
                                                </p>
                                            </div>
                                        </div>

                                        {selectedCategory && (
                                            <div className="flex items-center justify-between py-2">
                                                <div className="flex items-center gap-2 text-muted-foreground">
                                                    <Tag className="w-4 h-4" />
                                                    <span className="text-sm">Categoria</span>
                                                </div>
                                                <span className="px-3 py-1 bg-muted rounded-full text-[10px] font-bold">
                                                    {selectedCategory.name}
                                                </span>
                                            </div>
                                        )}
                                    </div>
                                </Card>

                                <div className="p-4 bg-muted/30 rounded-2xl flex gap-3 items-start">
                                    <Info className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                                    <p className="text-xs text-muted-foreground leading-relaxed">
                                        Lan├ºaremos este gasto automaticamente na sua conta todo dia {formData.billing_date},
                                        mantendo seu saldo sempre atualizado sem que voc├¬ precise fazer nada.
                                    </p>
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </main>

                {/* Footer Fixo */}
                <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-background via-background/95 to-transparent z-40">
                    <div className="max-w-lg mx-auto flex gap-3">
                        {currentStep > 1 && (
                            <Button
                                variant="outline"
                                size="lg"
                                className="h-16 w-20 rounded-2xl border-2"
                                onClick={prevStep}
                            >
                                <ChevronLeft className="w-6 h-6" />
                            </Button>
                        )}

                        <Button
                            size="lg"
                            className={cn(
                                "h-16 rounded-2xl text-lg font-bold shadow-large transition-all flex-1",
                                currentStep === STEPS.REVIEW ? "gradient-warm" : "gradient-primary"
                            )}
                            disabled={
                                (currentStep === STEPS.BASIC_INFO && !isStep1Valid) ||
                                (currentStep === STEPS.PAYMENT && !isStep2Valid) ||
                                createSub.isPending
                            }
                            onClick={currentStep === STEPS.REVIEW ? () => handleSubmit() : nextStep}
                        >
                            {createSub.isPending ? (
                                <Loader2 className="w-6 h-6 animate-spin" />
                            ) : currentStep === STEPS.REVIEW ? (
                                "Confirmar Assinatura"
                            ) : (
                                <span className="flex items-center gap-2">
                                    Pr├│ximo Passo
                                    <ArrowRight className="w-5 h-5" />
                                </span>
                            )}
                        </Button>
                    </div>
                </div>
            </div>
        </PageTransition >
    );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Eye, EyeOff, Mail, Lock, User, Fingerprint } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { useWebAuthn } from "@/hooks/useWebAuthn";
import { validatePassword } from "@/lib/passwordValidation";
import { PasswordStrengthChecklist } from "@/components/PasswordStrengthChecklist";
import { BiometricSetupDialog } from "@/components/auth/BiometricSetupDialog";
import { supabase } from "@/lib/backendClient";
import logoSaldin from "@/assets/logo-saldin-final.png";


type AuthView = "login" | "signup" | "recovery";

export const Auth = () => {
  const navigate = useNavigate();
  const { toast } = useToast();
  const { user, loading: authLoading, signIn, signUp, resetPassword } = useAuth();
  const {
    isSupported: isBiometricSupported,
    isEnabled: isBiometricEnabled,
    authenticateWithBiometric,
    isEnabledForUser,
    isLoading: isBiometricLoading,
  } = useWebAuthn();

  const [view, setView] = useState<AuthView>("login");

  // Form states
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [name, setName] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [autoBiometricTriggered, setAutoBiometricTriggered] = useState(false);

  // Biometric states
  const [showBiometricSetup, setShowBiometricSetup] = useState(false);
  const [pendingBiometricUser, setPendingBiometricUser] = useState<{
    userId: string;
    userEmail: string;
  } | null>(null);


  // Redirect is handled by PublicRoute wrapper in App.tsx
  // Biometric lock screen is now handled by OnboardingRoute in RouteGuards.tsx

  const resetForm = () => {
    setEmail("");
    setPassword("");
    setConfirmPassword("");
    setName("");
    setShowPassword(false);
    setShowConfirmPassword(false);
  };

  const handleViewChange = (newView: AuthView) => {
    resetForm();
    setView(newView);
  };

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!email || !password) {
      toast({
        title: "Campos obrigat├│rios",
        description: "Preencha email e senha para continuar.",
        variant: "destructive",
      });
      return;
    }

    if (!validateEmail(email)) {
      toast({
        title: "Email inv├ílido",
        description: "Digite um email v├ílido.",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);

    const { data, error } = await signIn(email, password);

    setIsLoading(false);

    if (error) {
      console.error("Login error:", error);
      let message = error.message; // Default to showing the actual error

      if (error.message.includes("Invalid login credentials")) {
        message = "Email ou senha incorretos.";
      } else if (error.message.includes("Email not confirmed")) {
        message = "Confirme seu email antes de fazer login (ou desative a confirma├º├úo no Supabase).";
      }

      toast({
        title: "Erro no login",
        description: message,
        variant: "destructive",
      });
      return;
    }

    // Check if we should offer biometric setup
    const userId = data?.user?.id;
    const userEmail = data?.user?.email;

    if (userId && userEmail && isBiometricSupported && !isEnabledForUser(userId)) {
      // Check if user dismissed the prompt before - unify to localStorage
      const dismissed = localStorage.getItem("biometric_prompt_dismissed");
      if (!dismissed) {
        setPendingBiometricUser({ userId, userEmail });
        setShowBiometricSetup(true);
        return; // Don't show success toast yet, wait for biometric decision
      }
    }

    toast({
      title: "Login realizado",
      description: "Bem-vindo de volta!",
    });
    // Navigation is handled by the auth state change in PublicRoute
  };

  // Auto-trigger biometric login on mount if enabled
  useEffect(() => {
    if (view === "login" && isBiometricSupported && isBiometricEnabled && !autoBiometricTriggered && !authLoading) {
      setAutoBiometricTriggered(true);
      const timer = setTimeout(() => {
        handleBiometricLogin();
      }, 800);
      return () => clearTimeout(timer);
    }
  }, [view, isBiometricSupported, isBiometricEnabled, autoBiometricTriggered, authLoading]);

  // Handle manual biometric login button click
  const handleBiometricLogin = async () => {
    if (!isBiometricSupported || !isBiometricEnabled) return;

    setIsLoading(true);

    const result = await authenticateWithBiometric();

    if (result.success && result.userEmail && result.userId) {
      // Biometric verified - check/refresh session
      const { data: { session } } = await supabase.auth.getSession();

      if (session) {
        toast({
          title: "Login realizado",
          description: "Bem-vindo de volta!",
        });
      } else {
        // Try to restore session
        const { data, error } = await supabase.auth.refreshSession();

        if (data?.session) {
          toast({
            title: "Login realizado",
            description: "Bem-vindo de volta!",
          });
        } else {
          // No valid session - user needs to re-authenticate with password
          setEmail(result.userEmail);
          toast({
            title: "Sess├úo expirada",
            description: "Digite sua senha para reconectar.",
          });
        }
      }
    } else {
      toast({
        title: "Falha na autentica├º├úo",
        description: "N├úo foi poss├¡vel verificar sua biometria. Use email e senha.",
        variant: "destructive",
      });
    }

    setIsLoading(false);
  };

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!name || !email || !password || !confirmPassword) {
      toast({
        title: "Campos obrigat├│rios",
        description: "Preencha todos os campos para continuar.",
        variant: "destructive",
      });
      return;
    }

    if (!validateEmail(email)) {
      toast({
        title: "Email inv├ílido",
        description: "Digite um email v├ílido.",
        variant: "destructive",
      });
      return;
    }

    const passwordValidation = validatePassword(password);
    if (!passwordValidation.isValid) {
      let message = "A senha n├úo atende aos requisitos de seguran├ºa.";
      if (passwordValidation.isCommonPassword) {
        message = "Esta senha ├® muito comum. Escolha uma senha mais forte.";
      }
      toast({
        title: "Senha inv├ílida",
        description: message,
        variant: "destructive",
      });
      return;
    }

    if (password !== confirmPassword) {
      toast({
        title: "Senhas n├úo conferem",
        description: "A confirma├º├úo de senha deve ser igual ├á senha.",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);

    const { data, error } = await signUp(email, password, name);

    setIsLoading(false);

    if (error) {
      let message = "Ocorreu um erro ao criar a conta.";
      if (error.message.includes("User already registered")) {
        message = "Este email j├í est├í cadastrado.";
      } else if (error.message.includes("Password should be")) {
        message = "A senha deve ter pelo menos 6 caracteres.";
      }
      toast({
        title: "Erro no cadastro",
        description: message,
        variant: "destructive",
      });
      return;
    }

    // Check if session was created immediately (Email Confirmation Disabled)
    if (data?.session) {
      // Check if we should offer biometric setup for new user
      const userId = data?.user?.id;
      const userEmail = data?.user?.email;

      if (userId && userEmail && isBiometricSupported && !isEnabledForUser(userId)) {
        setPendingBiometricUser({ userId, userEmail });
        setShowBiometricSetup(true);
        // Toast is shown inside Dialog or after it
        return;
      }

      toast({
        title: "Conta criada",
        description: "Bem-vindo ao Saldin!",
      });
      // Auth listener in App.tsx/RouteGuards will handle navigation
      return;
    }

    toast({
      title: "Conta criada",
      description: "Verifique seu email para confirmar o cadastro.",
    });
    handleViewChange("login");
  };

  const handleRecovery = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!email) {
      toast({
        title: "Campo obrigat├│rio",
        description: "Digite seu email para recuperar a senha.",
        variant: "destructive",
      });
      return;
    }

    if (!validateEmail(email)) {
      toast({
        title: "Email inv├ílido",
        description: "Digite um email v├ílido.",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);

    const { error } = await resetPassword(email);

    setIsLoading(false);

    if (error) {
      toast({
        title: "Erro",
        description: "Ocorreu um erro ao enviar o email de recupera├º├úo.",
        variant: "destructive",
      });
      return;
    }

    toast({
      title: "Email enviado",
      description: "Verifique sua caixa de entrada para redefinir a senha.",
    });
    handleViewChange("login");
  };


  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-3 flex items-center gap-4">
          {view !== "login" && (
            <Button
              variant="ghost"
              size="icon"
              onClick={() => handleViewChange("login")}
            >
              <ArrowLeft className="w-5 h-5" />
            </Button>
          )}
        </div>
      </header>

      <main className="flex-1 flex flex-col px-6 pb-20 pt-8 overflow-y-auto no-scrollbar">
        <FadeIn key={view}>
          {view === "login" && (
            <LoginForm
              email={email}
              setEmail={setEmail}
              password={password}
              setPassword={setPassword}
              showPassword={showPassword}
              setShowPassword={setShowPassword}
              isLoading={isLoading}
              onSubmit={handleLogin}
              onForgotPassword={() => handleViewChange("recovery")}
              onCreateAccount={() => handleViewChange("signup")}
              showBiometricButton={isBiometricSupported && isBiometricEnabled}
              onBiometricLogin={handleBiometricLogin}
              isBiometricLoading={isBiometricLoading}
            />
          )}

          {view === "signup" && (
            <SignupForm
              name={name}
              setName={setName}
              email={email}
              setEmail={setEmail}
              password={password}
              setPassword={setPassword}
              confirmPassword={confirmPassword}
              setConfirmPassword={setConfirmPassword}
              showPassword={showPassword}
              setShowPassword={setShowPassword}
              showConfirmPassword={showConfirmPassword}
              setShowConfirmPassword={setShowConfirmPassword}
              isLoading={isLoading}
              onSubmit={handleSignup}
              onBackToLogin={() => handleViewChange("login")}
            />
          )}

          {view === "recovery" && (
            <RecoveryForm
              email={email}
              setEmail={setEmail}
              isLoading={isLoading}
              onSubmit={handleRecovery}
              onBackToLogin={() => handleViewChange("login")}
            />
          )}
        </FadeIn>
      </main>

      {/* Biometric Setup Dialog */}
      {pendingBiometricUser && (
        <BiometricSetupDialog
          open={showBiometricSetup}
          onOpenChange={(open) => {
            setShowBiometricSetup(open);
            if (!open) {
              toast({
                title: view === "signup" ? "Conta criada" : "Login realizado",
                description: view === "signup" ? "Bem-vindo ao Saldin!" : "Bem-vindo de volta!",
              });
              setPendingBiometricUser(null);
            }
          }}
          userId={pendingBiometricUser.userId}
          userEmail={pendingBiometricUser.userEmail}
          onSuccess={() => {
            toast({
              title: view === "signup" ? "Conta criada" : "Login realizado",
              description: view === "signup" ? "Bem-vindo ao Saldin!" : "Bem-vindo de volta!",
            });
            setPendingBiometricUser(null);
          }}
        />
      )}
    </div>
  );
};

// Login Form Component
interface LoginFormProps {
  email: string;
  setEmail: (value: string) => void;
  password: string;
  setPassword: (value: string) => void;
  showPassword: boolean;
  setShowPassword: (value: boolean) => void;
  isLoading: boolean;
  onSubmit: (e: React.FormEvent) => void;
  onForgotPassword: () => void;
  onCreateAccount: () => void;
  showBiometricButton?: boolean;
  onBiometricLogin?: () => void;
  isBiometricLoading?: boolean;
}

const LoginForm = ({
  email,
  setEmail,
  password,
  setPassword,
  showPassword,
  setShowPassword,
  isLoading,
  onSubmit,
  onForgotPassword,
  onCreateAccount,
  showBiometricButton,
  onBiometricLogin,
  isBiometricLoading,
}: LoginFormProps) => (
  <form onSubmit={onSubmit} className="space-y-6 max-w-sm mx-auto w-full">
    <div className="text-center mb-8">
      <img src={logoSaldin} alt="Saldin" className="h-20 mx-auto mb-4" />
      <h1 className="font-serif text-3xl font-semibold tracking-tight">Entrar</h1>
      <p className="text-muted-foreground mt-2">
        Acesse seu painel financeiro
      </p>
    </div>

    {/* Biometric Login Button */}
    {showBiometricButton && (
      <div className="space-y-4">
        <Button
          type="button"
          className="w-full h-14 gap-3 bg-primary/10 hover:bg-primary/20 text-primary border-primary/20 transition-all duration-300"
          variant="outline"
          onClick={onBiometricLogin}
          disabled={isBiometricLoading || isLoading}
        >
          <Fingerprint className="w-6 h-6 animate-pulse-slow" />
          <span className="text-base font-medium">
            {isBiometricLoading ? "Verificando..." : "Entrar com biometria"}
          </span>
        </Button>

        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t" />
          </div>
          <div className="relative flex justify-center text-xs uppercase">
            <span className="bg-background px-2 text-muted-foreground">
              ou
            </span>
          </div>
        </div>
      </div>
    )}

    <div className="space-y-4">
      <div className="space-y-2">
        <Label htmlFor="email" className="text-foreground/80 ml-1">Email</Label>
        <div className="relative">
          <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/60" />
          <Input
            id="email"
            type="email"
            placeholder="seu@email.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="pl-10 h-12 rounded-xl focus:ring-primary/20 transition-all"
            autoComplete="email"
            data-testid="login-email"
          />
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="password" className="text-foreground/80 ml-1">Senha</Label>
        <div className="relative">
          <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/60" />
          <Input
            id="password"
            type={showPassword ? "text" : "password"}
            placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="pl-10 pr-10 h-12 rounded-xl focus:ring-primary/20 transition-all"
            autoComplete="current-password"
            data-testid="login-password"
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-primary transition-colors pr-1"
          >
            {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>

    <Button
      type="submit"
      className="w-full"
      size="lg"
      disabled={isLoading}
      data-testid="login-submit"
    >
      {isLoading ? "Entrando..." : "Entrar"}
    </Button>

    <div className="flex flex-col items-center gap-3 pt-4">
      <button
        type="button"
        onClick={onForgotPassword}
        className="text-sm text-muted-foreground hover:text-foreground transition-colors"
      >
        Esqueci minha senha
      </button>
      <button
        type="button"
        onClick={onCreateAccount}
        className="text-sm text-primary hover:text-primary/80 font-medium transition-colors"
      >
        Criar conta
      </button>
    </div>
  </form>
);

// Signup Form Component
interface SignupFormProps {
  name: string;
  setName: (value: string) => void;
  email: string;
  setEmail: (value: string) => void;
  password: string;
  setPassword: (value: string) => void;
