export default Auth;

import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { BottomNav } from "@/components/BottomNav";
import { FadeIn } from "@/components/ui/motion";
import { ChevronLeft, Plus, Landmark, ArrowLeftRight, Loader2, Smartphone as PhoneIcon } from "lucide-react";
import { useProfile } from "@/hooks/useProfile";
import { useBankAccounts } from "@/hooks/useBankAccounts";
import { detectBank } from "@/lib/cardBranding";
import { formatCurrency } from "@/lib/balanceCalculations";
import { accountTypeLabels } from "@/types/bankAccount";
import { motion } from "framer-motion";
import { BankLogo } from "@/components/BankLogo";


export const BankAccounts = () => {
  const navigate = useNavigate();
  const { data: accounts = [], isLoading } = useBankAccounts();
  const { data: profile } = useProfile();

  const defaultIncomeId = (profile as any)?.wa_default_income_account_id;
  const defaultExpenseId = (profile as any)?.wa_default_expense_account_id;

  const totalBalance = accounts.reduce((sum, a) => sum + Number(a.current_balance), 0);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-24">
      <header className="px-5 pt-safe-top sticky top-0 bg-background/95 backdrop-blur-sm z-10 border-b border-border">
        <div className="pt-4 pb-3 flex items-center justify-between gap-2">
          <div className="flex items-center gap-1 min-w-0">
            <Button variant="ghost" size="icon" onClick={() => navigate("/")} className="shrink-0 -ml-2">
              <ChevronLeft className="w-5 h-5" />
            </Button>
            <h1 className="font-serif text-lg sm:text-xl font-semibold truncate">Contas</h1>
          </div>
          <div className="flex gap-2 shrink-0">
            {accounts.length >= 2 && (
              <Button variant="outline" size="sm" className="px-3" onClick={() => navigate("/banks/transfer")}>
                <ArrowLeftRight className="w-4 h-4 sm:mr-1" />
                <span className="hidden sm:inline">Transferir</span>
              </Button>
            )}
            <Button variant="warm" size="sm" className="px-3" onClick={() => navigate("/banks/add")}>
              <Plus className="w-4 h-4 sm:mr-1" />
              <span className="hidden sm:inline">Nova</span>
              <span className="sm:hidden">Nova</span>
            </Button>
          </div>
        </div>
      </header>

      <main className="px-5 pt-4 space-y-4">
        {/* Total balance */}
        {accounts.length > 0 && (
          <FadeIn>
            <div className="p-5 rounded-2xl bg-card border border-border shadow-medium text-center">
              <p className="text-sm text-muted-foreground mb-1">Saldo total em contas</p>
              <p className="font-serif text-2xl font-semibold">{formatCurrency(totalBalance)}</p>
            </div>
          </FadeIn>
        )}

        {/* Account list */}
        {accounts.length === 0 ? (
          <FadeIn delay={0.1}>
            <div className="text-center py-12">
              <div className="w-16 h-16 rounded-full bg-muted mx-auto mb-4 flex items-center justify-center">
                <Landmark className="w-8 h-8 text-muted-foreground" />
              </div>
              <h3 className="font-serif text-lg font-semibold mb-2">Nenhuma conta cadastrada</h3>
              <p className="text-sm text-muted-foreground mb-6">
                Adicione suas contas banc├írias para acompanhar seus saldos
              </p>
              <Button variant="warm" onClick={() => navigate("/banks/add")}>
                <Plus className="w-4 h-4 mr-2" />
                Cadastrar conta
              </Button>
            </div>
          </FadeIn>
        ) : (
          <div className="space-y-3">
            {accounts.map((account, index) => {
              const bankTheme = detectBank(account.bank_name, account.bank_key);
              const color = account.color || bankTheme.color;

              return (
                <FadeIn key={account.id} delay={0.05 * index}>
                  <motion.button
                    whileTap={{ scale: 0.98 }}
                    onClick={() => navigate(`/banks/${account.id}`)}
                    className="w-full p-3 sm:p-4 rounded-xl bg-card border border-border shadow-soft hover:shadow-medium transition-all text-left"
                  >
                    <div className="flex items-center gap-3 sm:gap-4">
                      <BankLogo
                        bankName={account.bank_name}
                        color={color}
                        size="md"
                        className="sm:w-12 sm:h-12"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="font-medium text-sm sm:text-base truncate">{account.bank_name}</p>
                        <div className="flex items-center gap-2">
                          <p className="text-[10px] sm:text-xs text-muted-foreground truncate">
                            {accountTypeLabels[account.account_type] || "Corrente"}
                          </p>
                          {(account.id === defaultIncomeId || account.id === defaultExpenseId) && (
                            <div className="flex items-center gap-1 bg-primary/10 text-primary rounded-full px-2 py-0.5 border border-primary/10">
                              <PhoneIcon className="w-2.5 h-2.5" />
                              <span className="text-[8px] font-bold uppercase tracking-tight">Bot WhatsApp</span>
                            </div>
                          )}
                        </div>
                      </div>

                      <div className="text-right shrink-0">
                        <p className="font-semibold text-sm sm:text-base tabular-nums">
                          {formatCurrency(Number(account.current_balance))}
                        </p>
                        {Number(account.initial_balance) !== Number(account.current_balance) && (
                          <p className="text-[10px] sm:text-xs text-muted-foreground">
                            {formatCurrency(Number(account.initial_balance))}
                          </p>
                        )}
                      </div>
                    </div>
                  </motion.button>
                </FadeIn>
              );
            })}
          </div>
        )}
      </main>

      <BottomNav />
    </div>
  );
};

export default BankAccounts;

// Tela de categorias com CRUD para categorias personalizadas

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { BottomNav } from "@/components/BottomNav";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Plus, Tag, Pencil, Trash2, Check, X } from "lucide-react";
import { motion } from "framer-motion";
import {
  defaultCategories,
  categoryGroups,
  getGroupedCategories,
  type CategoryGroup,
  type CategoryNature
} from "@/lib/categories";
import { useCustomCategories, useCreateCategory, useUpdateCategory, useDeleteCategory } from "@/hooks/useCategories";
import { DeleteConfirmDialog } from "@/components/shared/DeleteConfirmDialog";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

const colorOptions = [
  { value: "#3B82F6", label: "Azul" },
  { value: "#10B981", label: "Verde" },
  { value: "#EF4444", label: "Vermelho" },
  { value: "#8B5CF6", label: "Roxo" },
  { value: "#F59E0B", label: "Laranja" },
  { value: "#EC4899", label: "Rosa" },
  { value: "#14B8A6", label: "Turquesa" },
  { value: "#F59E0B", label: "├émbar" },
  { value: "#6366F1", label: "├ìndigo" },
  { value: "#94A3B8", label: "Neutro" },
];

const natureOptions: { value: CategoryNature; label: string }[] = [
  { value: "Fixo", label: "Fixo" },
  { value: "Vari├ível", label: "Vari├ível" },
  { value: "Financeiro", label: "Financeiro" },
  { value: "Investimento", label: "Investimento" },
  { value: "Renda", label: "Renda" },
];

export default function Categories() {
  const navigate = useNavigate();
  const groupedCategories = getGroupedCategories();
  const { data: customCategories = [], isLoading } = useCustomCategories();
  const createCategory = useCreateCategory();
  const updateCategory = useUpdateCategory();
  const deleteCategory = useDeleteCategory();

  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<{ id: string; name: string; color: string; group: CategoryGroup; nature: CategoryNature } | null>(null);
  const [newName, setNewName] = useState("");
  const [newColor, setNewColor] = useState("#94A3B8");
  const [newGroup, setNewGroup] = useState<CategoryGroup>("outros");
  const [newNature, setNewNature] = useState<CategoryNature>("Vari├ível");
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const groupOrder: CategoryGroup[] = [
    "contas_fixas", "impostos", "financeiro", "consumo",
    "moradia", "saude", "transporte", "educacao", "pessoal", "outros",
  ];

  const openCreateDialog = () => {
    setEditingCategory(null);
    setNewName("");
    setNewColor("#3B82F6");
    setNewGroup("outros");
    setNewNature("Vari├ível");
    setDialogOpen(true);
  };

  const openEditDialog = (cat: any) => {
    setEditingCategory({
      id: cat.id,
      name: cat.name,
      color: cat.color || "#94A3B8",
      group: cat.group_name as CategoryGroup || "outros",
      nature: cat.nature as CategoryNature || "Vari├ível"
    });
    setNewName(cat.name);
    setNewColor(cat.color || "#94A3B8");
    setNewGroup(cat.group_name as CategoryGroup || "outros");
    setNewNature(cat.nature as CategoryNature || "Vari├ível");
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!newName.trim()) return;

    if (editingCategory) {
      await updateCategory.mutateAsync({
        id: editingCategory.id,
        name: newName.trim(),
        color: newColor,
        group_name: newGroup,
        nature: newNature,
      } as any);
    } else {
      await createCategory.mutateAsync({
        name: newName.trim(),
        type: "expense",
        color: newColor,
        group_name: newGroup,
        nature: newNature,
      } as any);
    }
    setDialogOpen(false);
    setNewName("");
    setEditingCategory(null);
  };

  const handleDelete = async () => {
    if (!deleteId) return;
    await deleteCategory.mutateAsync(deleteId);
    setDeleteId(null);
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      {/* Header */}
      <header className="px-5 pt-safe-top sticky top-0 bg-background/95 backdrop-blur-sm z-10 border-b border-border">
        <div className="pt-4 pb-3">
          <FadeIn>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-9 w-9"
                  onClick={() => navigate("/")}
                >
                  <ArrowLeft className="h-5 w-5" />
                </Button>
                <div>
                  <h1 className="font-serif text-xl font-semibold">Categorias</h1>
                  <p className="text-xs text-muted-foreground">
                    Organize seus gastos por categoria
                  </p>
                </div>
              </div>
              <Button variant="warm" size="sm" className="gap-1.5" onClick={openCreateDialog}>
                <Plus className="w-4 h-4" />
                Nova
              </Button>
            </div>
          </FadeIn>
        </div>
      </header>

      <main className="px-5 space-y-6 pt-4">
        {/* Custom Categories Section */}
        {customCategories.length > 0 && (
          <FadeIn>
            <div>
              <div className="flex items-center gap-2 mb-3">
                <Tag className="w-4 h-4 text-primary" />
                <h2 className="font-serif text-lg font-semibold">Minhas Categorias</h2>
              </div>

              <div className="grid grid-cols-1 gap-2">
                {customCategories.map((cat, index) => (
                  <motion.div
                    key={cat.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.02 * index }}
                    className="p-3 rounded-xl bg-card border border-primary/20 flex items-center gap-3"
                  >
                    <div
                      className="w-9 h-9 rounded-lg flex items-center justify-center"
                      style={{ backgroundColor: `${cat.color}20`, color: cat.color || "#3B82F6" }}
                    >
                      <Tag className="w-4 h-4" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <span className="text-sm font-medium truncate block">{cat.name}</span>
                      <div className="flex gap-1.5 mt-0.5">
                        <span className="text-[9px] uppercase tracking-wider px-1 bg-muted rounded text-muted-foreground">
                          {categoryGroups[cat.group_name as CategoryGroup]?.name || "Outros"}
                        </span>
                        <span className="text-[9px] uppercase tracking-wider px-1 bg-muted rounded text-muted-foreground">
                          {cat.nature}
                        </span>
                      </div>
                    </div>
                    <div className="flex items-center gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => openEditDialog(cat)}
                      >
                        <Pencil className="w-3.5 h-3.5 text-muted-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => setDeleteId(cat.id)}
                      >
                        <Trash2 className="w-3.5 h-3.5 text-impulse" />
                      </Button>
                    </div>
                  </motion.div>
                ))}
              </div>
            </div>
          </FadeIn>
        )}

        {/* Default Category Groups */}
        {groupOrder.map((groupKey, groupIndex) => {
          const group = categoryGroups[groupKey];
          const categories = groupedCategories[groupKey];

          if (categories.length === 0) return null;

          const GroupIcon = group.icon;

          return (
            <FadeIn key={groupKey} delay={0.03 * (groupIndex + 1)}>
              <div>
                <div className="flex items-center gap-2 mb-3">
                  <GroupIcon className="w-4 h-4 text-muted-foreground" />
                  <h2 className="font-serif text-lg font-semibold">{group.name}</h2>
                </div>

                <div className="grid grid-cols-2 gap-2">
                  {categories.map((category, index) => {
                    const Icon = category.icon;

                    return (
                      <motion.div
                        key={category.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.02 * index }}
                        className="p-3 rounded-xl bg-card border border-border flex items-center gap-3"
                      >
                        <div
                          className="w-9 h-9 rounded-lg flex items-center justify-center"
                          style={{ backgroundColor: `${category.color}20`, color: category.color }}
                        >
                          <Icon className="w-4 h-4" />
                        </div>
                        <span className="text-sm font-medium truncate">{category.name}</span>
                      </motion.div>
                    );
                  })}
                </div>
              </div>
            </FadeIn>
          );
        })}
      </main>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>
              {editingCategory ? "Editar categoria" : "Nova categoria"}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4 pt-2">
            <div>
              <label className="text-sm font-medium mb-2 block">Nome</label>
              <Input
                placeholder="Ex: Assinatura, Streaming..."
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                maxLength={30}
                autoFocus
              />
            </div>
            <div>
              <label className="text-sm font-medium mb-2 block">Grupo</label>
              <Select value={newGroup} onValueChange={(val) => setNewGroup(val as CategoryGroup)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(categoryGroups).map(([key, group]) => (
                    <SelectItem key={key} value={key}>
                      <div className="flex items-center gap-2">
                        <group.icon className="w-4 h-4" />
                        {group.name}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-sm font-medium mb-2 block">Natureza</label>
              <Select value={newNature} onValueChange={(val) => setNewNature(val as CategoryNature)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {natureOptions.map((opt) => (
                    <SelectItem key={opt.value} value={opt.value}>
                      {opt.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-sm font-medium mb-2 block">Cor</label>
              <Select value={newColor} onValueChange={setNewColor}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {colorOptions.map((opt) => (
                    <SelectItem key={opt.value} value={opt.value}>
                      <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: opt.value }} />
                        {opt.label}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex gap-3 pt-2">
              <Button variant="outline" className="flex-1" onClick={() => setDialogOpen(false)}>
                Cancelar
              </Button>
              <Button
                variant="warm"
                className="flex-1"
                onClick={handleSave}
                disabled={!newName.trim() || createCategory.isPending || updateCategory.isPending}
              >
                {editingCategory ? "Salvar" : "Criar"}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <DeleteConfirmDialog
        open={!!deleteId}
        onOpenChange={(open) => !open && setDeleteId(null)}
        onConfirm={handleDelete}
        title="Excluir categoria"
        description="Essa categoria ser├í removida. Registros que a utilizam n├úo ser├úo afetados."
      />

      <BottomNav />
    </div>
  );
}

import { useState, useEffect } from "react";
import { supabase } from "@/lib/backendClient";
import { toLocalDateString } from "@/lib/dateUtils";
import { useNavigate, useLocation, useParams } from "react-router-dom";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { FadeIn } from "@/components/ui/motion";
import {
  ArrowLeft, Check, Utensils, Car, Gamepad2, Home, CreditCard,
  MoreHorizontal, RefreshCw, Calendar, Users, User, ChevronDown,
  Banknote, Smartphone, CreditCard as CreditCardIcon, Loader2, QrCode,
  Search, Plus, AlertTriangle
} from "lucide-react";
import { formatCurrency } from "@/lib/balanceCalculations";
import { cn } from "@/lib/utils";
import { useCreateExpense, useCreateBulkExpenses, useUpdateExpense, useExpenseById } from "@/hooks/useExpenses";
import { addMonths, format } from "date-fns";
import { useCreateCreditCardPurchase, useCreditCards } from "@/hooks/useCreditCards";
import { useCreateReceivable } from "@/hooks/useReceivables";
import { useBankAccounts, useUpdateBankBalance } from "@/hooks/useBankAccounts";
import { useCashAccount } from "@/hooks/useCashAccount";
import { useSubscriptions } from "@/hooks/useSubscriptions";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";
import {
  defaultCategories,
  categoryGroups,
  getGroupedCategories,
  type CategoryConfig,
  type CategoryGroup
} from "@/lib/categories";
import { useAllCategories } from "@/hooks/useCategories";
import { Tag } from "lucide-react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";

type Step = "expense" | "recurring" | "reimbursement" | "confirm";
type PaymentMethod = "cash" | "debit" | "credit" | "pix";
type EmotionType = "pilar" | "essencial" | "impulso";

interface PaymentOption {
  value: PaymentMethod;
  label: string;
  icon: React.ReactNode;
}

// Categorias r├ípidas para exibir na tela inicial (6 mais usadas)
const quickCategories = [
  "alimentacao",
  "transporte_publico",
  "lazer",
  "mercado",
  "delivery",
  "outros",
];

const paymentOptions: PaymentOption[] = [
  { value: "pix", label: "PIX", icon: <QrCode className="w-5 h-5" /> },
  { value: "cash", label: "Dinheiro", icon: <Banknote className="w-5 h-5" /> },
  { value: "debit", label: "D├®bito", icon: <Smartphone className="w-5 h-5" /> },
  { value: "credit", label: "Cr├®dito", icon: <CreditCardIcon className="w-5 h-5" /> },
];

const emotionIcons: Record<EmotionType, React.ElementType> = {
  pilar: Home,
  essencial: Check,
  impulso: CreditCard,
};

const emotionOptions = [
  { value: "pilar" as EmotionType, label: "Pilar", description: "Essencial para viver" },
  { value: "essencial" as EmotionType, label: "Essencial", description: "Necess├írio" },
  { value: "impulso" as EmotionType, label: "Impulso", description: "Compra por impulso" },
];

const confirmationIcons = {
  yes: Check,
  no: MoreHorizontal,
};

const confirmationOptions = [
  { value: true, label: "Sim", iconKey: "yes" as const },
  { value: false, label: "N├úo", iconKey: "no" as const },
];

export const ConfirmExpense = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { id } = useParams();
  const { user } = useAuth();
  const createExpense = useCreateExpense();
  const updateExpense = useUpdateExpense();
  const createBulkExpenses = useCreateBulkExpenses();
  const createCreditCardPurchase = useCreateCreditCardPurchase();
  const { data: creditCards = [] } = useCreditCards();
  const { data: bankAccounts = [] } = useBankAccounts();
  const updateBankBalance = useUpdateBankBalance();
  const createReceivable = useCreateReceivable();
  const { ensureCashAccount, cashAccountId, isCreating: isCreatingCash } = useCashAccount();

  // Hooks
  const { data: existingExpense, isLoading: isLoadingExpense } = useExpenseById(id && !id.startsWith("proj-") && id !== "new" ? id : undefined);
  const { data: subscriptions = [] } = useSubscriptions();
  const { allCategories, customCategories } = useAllCategories();
  const isNew = id === "new" || (id?.startsWith("proj-"));

  const [amount, setAmount] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [categorySheetOpen, setCategorySheetOpen] = useState(false);
  const [categorySearch, setCategorySearch] = useState("");

  const [step, setStep] = useState<Step>("expense");

  // Layer 1 - Basic expense info
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState<string | undefined>();
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod | undefined>();
  const [selectedCardId, setSelectedCardId] = useState<string | undefined>();
  const [selectedBankId, setSelectedBankId] = useState<string | undefined>();

  // Layer 2 - Time behavior
  const [isRecurring, setIsRecurring] = useState<boolean | undefined>();
  const [installments, setInstallments] = useState<string>("");

  // Layer 3 - Reimbursement
  const [isForOtherPerson, setIsForOtherPerson] = useState<boolean | undefined>();
  const [reimbursementPersonName, setReimbursementPersonName] = useState("");

  // Confirmation
  const [selectedEmotion, setSelectedEmotion] = useState<EmotionType | undefined>();
  const [wouldDoAgain, setWouldDoAgain] = useState<boolean | undefined>();

  // Sync state when existingExpense or subscription projection loads
  useEffect(() => {
    if (existingExpense) {
      setAmount(Number(existingExpense.amount));
      setDescription(existingExpense.description || "");
      if (existingExpense.category_id) setCategory(existingExpense.category_id);
      if (existingExpense.bank_account_id) setSelectedBankId(existingExpense.bank_account_id);
      if (existingExpense.payment_method) setPaymentMethod(existingExpense.payment_method as PaymentMethod);
      if (existingExpense.emotion) setSelectedEmotion(existingExpense.emotion as EmotionType);
    } else if (id?.startsWith("proj-")) {
      const subId = id.replace("proj-", "");
      const sub = subscriptions.find(s => s.id === subId);
      if (sub) {
        setAmount(Number(sub.amount));
        setDescription(`Assinatura: ${sub.name}`);
        if (sub.category_id) setCategory(sub.category_id);
        setIsRecurring(true);
      }
    } else if (location.state?.amount) {
      setAmount(location.state.amount);
    } else if (isNew) {
      setAmount(0);
    }
  }, [existingExpense, subscriptions, id, location.state, isNew]);

  const isLoading = isLoadingExpense || isCreatingCash;

  // Insufficient funds check
  const selectedAccountBalance = (() => {
    if (paymentMethod === "credit" && selectedCardId) {
      const card = creditCards.find(c => c.id === selectedCardId);
      return card ? Number(card.credit_limit) : Infinity;
    }
    if ((paymentMethod === "debit" || paymentMethod === "pix" || paymentMethod === "cash") && selectedBankId) {
      const bank = bankAccounts.find(b => b.id === selectedBankId);
      return bank ? Number(bank.current_balance) : Infinity;
    }
    return Infinity;
  })();

  const isInsufficient = amount > selectedAccountBalance;


  // Filtered categories for search
  const filteredCategories = categorySearch.trim()
    ? allCategories.filter(c =>
      c.name.toLowerCase().includes(categorySearch.toLowerCase())
    )
    : allCategories;

  // Get selected category object
  const selectedCategory = category
    ? allCategories.find(c => c.id === category)
    : undefined;

  // Quick categories to show
  const quickCategoryObjects = quickCategories
    .map(id => allCategories.find(c => c.id === id))
    .filter((c): c is CategoryConfig => c !== undefined);

  const formattedAmount = new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(amount);

  const handleBack = () => {
    if (step === "confirm") {
      setStep("reimbursement");
    } else if (step === "reimbursement") {
      setStep("recurring");
    } else if (step === "recurring") {
      setStep("expense");
    } else {
      navigate("/");
    }
  };

  const canContinueExpense = () => {
    if (!description.trim() || !category || !paymentMethod) return false;
    if (paymentMethod === "credit" && !selectedCardId) return false;
    if (paymentMethod === "cash") return true; // Cash account will be auto-created
    if (paymentMethod !== "credit" && bankAccounts.length > 0 && !selectedBankId) return false;
    return true;
  };

  const canContinueRecurring = () => {
    if (paymentMethod === "credit") {
      // For credit card, installments default to 1 (├á vista) if empty
      return true;
    }
    if (isRecurring === undefined) return false;
    if (isRecurring === true && (!installments || parseInt(installments) < 1)) return false;
    return true;
  };

  const canContinueReimbursement = () => {
    if (isForOtherPerson === undefined) return false;
    if (isForOtherPerson && !reimbursementPersonName.trim()) return false;
    return true;
  };

  const handleComplete = async () => {
    if (!user || isSubmitting) return;

    setIsSubmitting(true);

    try {
      // ----------------------------------------------------------------------
      // FIX: Ensure Category has a valid UUID (Handle Default Categories)
      // ----------------------------------------------------------------------
      let finalCategoryId = selectedCategory?.id;

      // Check if ID is a UUID. If not (e.g. "outros"), we must resolve it.
      const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(finalCategoryId || "");

      if (finalCategoryId && !isUuid && selectedCategory) {
        console.log("Resolving static category ID:", finalCategoryId);

        // 1. Try to find existing category by name for this user
        const { data: existing } = await supabase
          .from("categories")
          .select("id")
          .ilike("name", selectedCategory.name)
          .eq("user_id", user.id)
          .maybeSingle();

        if (existing) {
          finalCategoryId = existing.id;
        } else {
          // 2. Create the category in DB if it doesn't exist
          console.log("Creating missing default category:", selectedCategory.name);
          const { data: newCat, error: createError } = await supabase
            .from("categories")
            .insert({
              user_id: user.id,
              name: selectedCategory.name,
              icon: "Tag", // Default string, local config overrides this based on name
              color: selectedCategory.color,
              type: "expense",
              group_name: selectedCategory.group,
              nature: selectedCategory.nature as any, // Cast to match DB enum/text
              is_default: true, // Mark as default so it maps back to local config
              allow_expense: selectedCategory.allowExpense ?? true,
              allow_card: selectedCategory.allowCard ?? true,
              allow_subscription: selectedCategory.allowSubscription ?? true,
            })
            .select()
            .single();

          if (createError) {
            console.error("Error creating category:", createError);
            finalCategoryId = null;
          } else if (newCat) {
            finalCategoryId = newCat.id;
          }
        }
      }

      // FINAL SAFETY CHECK: If it's still not a valid UUID, force it to null
      const isFinalUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(finalCategoryId || "");
      if (!isFinalUuid) {
        console.warn("Invalid Category ID detected. Forcing to NULL.", finalCategoryId);
        finalCategoryId = null;
      }

      // EXTRA SAFE: If finalCategoryId is "outros" or any string length < 30, kill it.
      if (typeof finalCategoryId === "string" && finalCategoryId.length < 30) {
        finalCategoryId = null;
      }

      const isCreditCard = paymentMethod === "credit" && selectedCardId;

      if (isCreditCard) {
        // CART├âO DE CR├ëDITO: Criar compra + parcelas (N├âO criar gasto)
        const totalInstallments = isRecurring && installments ? parseInt(installments) : 1;
        await createCreditCardPurchase.mutateAsync({
          card_id: selectedCardId,
          description: description || selectedCategory?.name || "Compra no cart├úo",
          total_amount: amount,
          total_installments: totalInstallments,
          category_id: finalCategoryId || null,
          purchase_date: toLocalDateString(),
        });

        // Se era um gasto existente (ex: vindo do WhatsApp), deletar o gasto original
        // j├í que agora ele ├® uma compra no cart├úo.
        if (!isNew && id) {
          await supabase.from("expenses").delete().eq("id", id);
        }
      } else {
        // For cash payments, ensure the cash account exists
        let bankId = selectedBankId;
        if (paymentMethod === "cash") {
          bankId = await ensureCashAccount();
        }

        // GASTO NORMAL: Criar ou Atualizar expense
        const totalInstallments = isRecurring && installments ? parseInt(installments) : 1;
        const purchaseDate = new Date();

        if (totalInstallments > 1 && isNew) {
          const installmentGroupId = crypto.randomUUID();
          const bulkExpenses = Array.from({ length: totalInstallments }, (_, i) => {
            const date = addMonths(purchaseDate, i);
            return {
              amount: amount,
              description: description || selectedCategory?.name || "Gasto registrado",
              emotion: selectedEmotion,
              status: "confirmed" as const,
              source: "manual" as const,
              is_installment: false,
              total_installments: totalInstallments,
              installment_number: i + 1,
              installment_group_id: installmentGroupId,
              bank_account_id: bankId || undefined,
              date: format(date, "yyyy-MM-dd"),
              category_id: finalCategoryId || null,
            };
          });
          await createBulkExpenses.mutateAsync(bulkExpenses as any);
        } else if (!isNew && id) {
          // UPDATE EXISTING
          await updateExpense.mutateAsync({
            id,
            amount,
            description: description || selectedCategory?.name || "Gasto confirmado",
            emotion: selectedEmotion,
            status: "confirmed",
            bank_account_id: bankId || undefined,
            category_id: finalCategoryId || null,
          });
        } else {
          // CREATE NEW SINGLE
          await createExpense.mutateAsync({
            amount,
            description: description || selectedCategory?.name || "Gasto registrado",
            emotion: selectedEmotion,
            status: "confirmed",
            source: "manual",
            is_installment: false,
            installment_number: 1,
            bank_account_id: bankId || undefined,
            date: toLocalDateString(),
            category_id: finalCategoryId || null,
          } as any);
        }

        // Update bank balance if a bank was selected
        if (bankId) {
          await updateBankBalance.mutateAsync({
            accountId: bankId,
            delta: -amount,
          });
        }
      }

      // Se h├í reembolso, criar receivable em ambos os casos
      if (isForOtherPerson && reimbursementPersonName) {
        const futureDate = new Date();
        futureDate.setMonth(futureDate.getMonth() + 1);
        const dueDate = toLocalDateString(futureDate);

        await createReceivable.mutateAsync({
          debtor_name: reimbursementPersonName.trim(),
          amount,
          description: `Reembolso de gasto - ${description || 'Gasto'}`,
          due_date: dueDate,
          status: "pending",
        });
      }

      toast.success(isCreditCard ? "Compra registrada no cart├úo!" : "Gasto confirmado com sucesso!");
      navigate("/", { state: { success: true } });
    } catch (error: any) {
      console.error("Failed to save:", error);

      // RETRY LOGIC: If the error is specifically about invalid UUID (which often means category ID is bad),
      // retry saving without the category as a fallback.
      if (error?.message?.includes("invalid input syntax for type uuid")) {
        console.warn("Caught UUID error. Retrying without category...");
        try {
          // Re-run the save logic but force category to null
          // Since we can't easily re-call this function recursively with different state, 
          // we will manually call the mutation that likely failed.
          // However, identifying WHICH mutation failed is hard. 
          // We will try to create a standard expense as fallback if it wasn't a credit card

          const isCreditCard = paymentMethod === "credit" && selectedCardId;
          if (!isCreditCard) {
            // Retry standard expense
            let bankId = selectedBankId;
            if (paymentMethod === "cash") {
              bankId = await ensureCashAccount();
            }

            // Simplified retry for single expense (bulk complex to retry inline)
            await createExpense.mutateAsync({
              amount,
              description: description || "Gasto (Recuperado)",
              emotion: selectedEmotion,
              status: "confirmed",
              source: "manual",
              is_installment: false,
              installment_number: 1,
              bank_account_id: bankId || undefined,
              date: toLocalDateString(),
              category_id: null, // FORCE NULL
            } as any);

            if (bankId) {
              await updateBankBalance.mutateAsync({ accountId: bankId, delta: -amount });
            }

            toast.success("Gasto salvo (sem categoria) ap├│s erro.");
            navigate("/", { state: { success: true } });
            return; // Exit success
          }
        } catch (retryError) {
          console.error("Retry failed:", retryError);
        }
      }

      // Show more detailed error message to help debugging
      toast.error(error?.message || "Erro ao salvar. Tente novamente.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const getStepNumber = () => {
    switch (step) {
      case "expense": return 1;
      case "recurring": return 2;
      case "reimbursement": return 3;
      case "confirm": return 4;
    }
  };

  const totalSteps = 4;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-2 flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={handleBack}>
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <div className="flex-1">
            <p className="text-sm text-muted-foreground">
              Passo {getStepNumber()} de {totalSteps}
            </p>
            <h1 className="font-serif text-xl font-semibold">Novo Gasto</h1>
          </div>
        </div>
      </header>

      {/* Progress */}
      <div className="px-5 py-2">
        <div className="flex gap-2">
          {[1, 2, 3, 4].map((s) => (
            <div
              key={s}
              className={cn(
                "h-1 flex-1 rounded-full transition-all duration-300",
                getStepNumber() >= s ? "gradient-warm" : "bg-muted"
              )}
            />
          ))}
        </div>
      </div>

      <main className="flex-1 flex flex-col px-5 py-6 overflow-y-auto">
        {/* Amount Display */}
        <FadeIn className="text-center mb-6">
          <p className="text-muted-foreground mb-1">Valor do gasto</p>
          <p className="font-serif text-4xl font-semibold">{formattedAmount}</p>
          {!isNew && (
            <p className="text-sm text-muted-foreground mt-2">
              Mercado Central ┬À Importado do banco
            </p>
          )}
        </FadeIn>

        {/* LAYER 1 - Basic Expense Info */}
        {step === "expense" && (
          <FadeIn key="expense" className="flex-1 flex flex-col">
            <h2 className="text-center text-xl font-medium mb-6">
              Detalhes do gasto
            </h2>

            {/* Description input */}
            <div className="mb-5">
              <label className="text-sm text-muted-foreground mb-2 block">
                Onde foi esse gasto?
              </label>
              <Input
                placeholder="Ex: Restaurante, Supermercado, Uber..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                maxLength={50}
                className="text-base"
              />
            </div>

            {/* Category selector */}
            <div className="mb-5">
              <label className="text-sm text-muted-foreground mb-3 block">
                Categoria
              </label>

              {/* Quick Categories Grid */}
              <div className="grid grid-cols-3 gap-2 mb-3">
                {quickCategoryObjects.map((cat) => {
                  const Icon = cat.icon;
                  return (
                    <motion.button
                      key={cat.id}
                      whileTap={{ scale: 0.95 }}
                      onClick={() => setCategory(cat.id)}
                      className={cn(
                        "flex flex-col items-center gap-2 p-3 rounded-xl border transition-all",
                        category === cat.id
                          ? "border-primary bg-primary/10 text-primary"
                          : "border-border bg-card hover:bg-secondary"
                      )}
                    >
                      <Icon className={cn("w-5 h-5", category === cat.id ? "text-primary" : cat.color)} />
                      <span className="text-xs font-medium truncate w-full text-center">{cat.name}</span>
                    </motion.button>
                  );
                })}
              </div>

              {/* See All Categories Button */}
              <Sheet open={categorySheetOpen} onOpenChange={setCategorySheetOpen}>
                <SheetTrigger asChild>
                  <Button
                    variant="outline"
                    className="w-full justify-between"
                    size="sm"
                  >
                    {selectedCategory && !quickCategories.includes(selectedCategory.id) ? (
                      <div className="flex items-center gap-2">
                        <selectedCategory.icon className={cn("w-4 h-4", selectedCategory.color)} />
                        <span>{selectedCategory.name}</span>
                      </div>
                    ) : (
                      <span className="text-muted-foreground">Ver todas as categorias</span>
                    )}
                    <ChevronDown className="w-4 h-4 text-muted-foreground" />
                  </Button>
                </SheetTrigger>
                <SheetContent side="bottom" className="h-[80vh]">
                  <SheetHeader className="pb-4">
                    <SheetTitle>Escolher Categoria</SheetTitle>
                  </SheetHeader>

                  {/* Search */}
                  <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      placeholder="Buscar categoria..."
                      value={categorySearch}
                      onChange={(e) => setCategorySearch(e.target.value)}
                      className="pl-9"
                    />
                  </div>

                  <ScrollArea className="h-[calc(80vh-140px)]">
                    <div className="space-y-4 pr-4">
                      {/* Custom categories first */}
                      {customCategories.length > 0 && (() => {
                        const customFiltered = filteredCategories.filter(c => c.isCustom);
                        if (customFiltered.length === 0) return null;
                        return (
                          <div>
                            <div className="flex items-center gap-2 mb-2">
                              <Tag className="w-4 h-4 text-primary" />
                              <span className="text-sm font-medium text-primary">
                                Minhas Categorias
                              </span>
                            </div>
                            <div className="grid grid-cols-2 gap-2">
                              {customFiltered.map((cat) => {
                                const Icon = cat.icon;
                                return (
                                  <motion.button
                                    key={cat.id}
                                    whileTap={{ scale: 0.98 }}
                                    onClick={() => {
                                      setCategory(cat.id);
                                      setCategorySheetOpen(false);
                                      setCategorySearch("");
                                    }}
                                    className={cn(
                                      "flex items-center gap-2 p-3 rounded-xl border transition-all text-left",
                                      category === cat.id
                                        ? "border-primary bg-primary/10"
                                        : "border-primary/20 bg-card hover:bg-secondary"
                                    )}
                                  >
                                    <div className={cn(
                                      "w-8 h-8 rounded-lg flex items-center justify-center",
                                      category === cat.id ? "bg-primary/20" : "bg-primary/10"
                                    )}>
                                      <Icon className={cn("w-4 h-4", category === cat.id ? "text-primary" : cat.color)} />
                                    </div>
                                    <span className="text-sm font-medium truncate">{cat.name}</span>
                                  </motion.button>
                                );
                              })}
                            </div>
                          </div>
                        );
                      })()}

                      {/* Default category groups */}
                      {Object.entries(categoryGroups).map(([groupKey, groupInfo]) => {
                        const groupCategories = filteredCategories.filter(
                          c => c.group === groupKey && !c.isCustom
                        );

                        if (groupCategories.length === 0) return null;

                        const GroupIcon = groupInfo.icon;

                        return (
                          <div key={groupKey}>
                            <div className="flex items-center gap-2 mb-2">
                              <GroupIcon className="w-4 h-4 text-muted-foreground" />
                              <span className="text-sm font-medium text-muted-foreground">
                                {groupInfo.name}
                              </span>
                            </div>
                            <div className="grid grid-cols-2 gap-2">
                              {groupCategories.map((cat) => {
                                const Icon = cat.icon;
                                return (
                                  <motion.button
                                    key={cat.id}
                                    whileTap={{ scale: 0.98 }}
                                    onClick={() => {
                                      setCategory(cat.id);
                                      setCategorySheetOpen(false);
                                      setCategorySearch("");
                                    }}
                                    className={cn(
                                      "flex items-center gap-2 p-3 rounded-xl border transition-all text-left",
                                      category === cat.id
                                        ? "border-primary bg-primary/10"
                                        : "border-border bg-card hover:bg-secondary"
                                    )}
                                  >
                                    <div className={cn(
                                      "w-8 h-8 rounded-lg flex items-center justify-center",
                                      category === cat.id ? "bg-primary/20" : "bg-muted/50"
                                    )}>
                                      <Icon className={cn(
                                        "w-4 h-4",
                                        category === cat.id ? "text-primary" : cat.color
                                      )} />
                                    </div>
                                    <span className="text-sm font-medium truncate">
                                      {cat.name}
                                    </span>
                                  </motion.button>
                                );
                              })}
                            </div>
                          </div>
                        );
                      })}

                      {/* Create new category link */}
                      <Button
                        variant="outline"
                        className="w-full gap-2"
                        onClick={() => {
                          setCategorySheetOpen(false);
                          navigate("/categories");
                        }}
                      >
                        <Plus className="w-4 h-4" />
                        Criar nova categoria
                      </Button>
                    </div>
                  </ScrollArea>
                </SheetContent>
              </Sheet>
            </div>

            {/* Payment Method selector */}
            <div className="mb-5">
              <label className="text-sm text-muted-foreground mb-3 block">
                Forma de pagamento
              </label>
              <div className="grid grid-cols-4 gap-2">
                {paymentOptions.map((opt) => (
                  <motion.button
                    key={opt.value}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => {
                      setPaymentMethod(opt.value);
                      if (opt.value !== "credit") setSelectedCardId(undefined);
                      if (opt.value === "cash" && cashAccountId) {
                        setSelectedBankId(cashAccountId);
                      } else if (opt.value === "cash" && !cashAccountId) {
                        setSelectedBankId("__cash_pending__");
                      } else if (opt.value !== "cash" && (selectedBankId === "__cash_pending__" || selectedBankId === cashAccountId)) {
                        setSelectedBankId(undefined);
                      }
                    }}
                    className={cn(
                      "flex flex-col items-center gap-2 p-3 rounded-xl border transition-all",
                      paymentMethod === opt.value
                        ? "border-primary bg-primary/10 text-primary"
                        : "border-border bg-card hover:bg-secondary"
                    )}
                  >
                    {opt.icon}
                    <span className="text-xs font-medium">{opt.label}</span>
                  </motion.button>
                ))}
              </div>
            </div>

            {/* Cash account indicator */}
            {paymentMethod === "cash" && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                className="mb-5"
              >
                <div className="flex items-center gap-3 p-3 rounded-xl border-2 border-primary bg-primary/10">
                  <div className="w-8 h-8 rounded-lg bg-muted flex items-center justify-center">
                    <Banknote className="w-4 h-4 text-muted-foreground" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium">Dinheiro em m├úos</p>
                    <p className="text-xs text-muted-foreground">Conta criada automaticamente</p>
                  </div>
                </div>
              </motion.div>
            )}

            {/* Credit Card Selector (only when credit is selected) */}
            {paymentMethod === "credit" && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                className="mb-5"
              >
                <label className="text-sm text-muted-foreground mb-3 block">
                  Qual cart├úo? *
                </label>
                {creditCards.length === 0 ? (
                  <div className="p-4 rounded-xl border border-dashed border-border text-center">
                    <p className="text-sm text-muted-foreground mb-2">Nenhum cart├úo cadastrado</p>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => navigate("/cards/add")}
                    >
                      Cadastrar cart├úo
                    </Button>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {creditCards.map((card) => (
                      <motion.button
                        key={card.id}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => setSelectedCardId(card.id)}
                        className={cn(
                          "w-full flex items-center gap-3 p-3 rounded-xl border-2 transition-all text-left",
                          selectedCardId === card.id
                            ? "border-primary bg-primary/10"
                            : "border-border bg-card hover:bg-secondary"
                        )}
                      >
                        <div
                          className="w-8 h-8 rounded-lg flex items-center justify-center"
                          style={{ backgroundColor: card.color + "30" }}
                        >
                          <CreditCardIcon className="w-4 h-4" style={{ color: card.color }} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-medium truncate">{card.card_name}</p>
                          {card.last_four_digits && (
                            <p className="text-xs text-muted-foreground">
                              ÔÇóÔÇóÔÇóÔÇó {card.last_four_digits}
                            </p>
                          )}
                        </div>
                      </motion.button>
                    ))}
                  </div>
                )}
              </motion.div>
            )}

            {/* Bank Account Selector (for non-credit, non-cash payments) */}
            {paymentMethod && paymentMethod !== "credit" && paymentMethod !== "cash" && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                className="mb-5"
              >
                <label className="text-sm text-muted-foreground mb-3 block">
                  Conta de origem *
                </label>
                <div className="space-y-2">
                  {bankAccounts.map((account) => (
                    <motion.button
                      key={account.id}
                      whileTap={{ scale: 0.98 }}
                      onClick={() => setSelectedBankId(selectedBankId === account.id ? undefined : account.id)}
                      className={cn(
                        "w-full flex items-center gap-3 p-3 rounded-xl border-2 transition-all text-left",
                        selectedBankId === account.id
                          ? "border-primary bg-primary/10"
                          : "border-border bg-card hover:bg-secondary"
                      )}
                    >
                      <div className="w-8 h-8 rounded-lg bg-muted flex items-center justify-center">
                        <Banknote className="w-4 h-4 text-muted-foreground" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{account.bank_name}</p>
                      </div>
                    </motion.button>
                  ))}
                </div>
              </motion.div>
            )}
          </FadeIn>
        )}

        {/* LAYER 2 - Time Behavior */}
        {step === "recurring" && (
          <FadeIn key="recurring" className="flex-1 flex flex-col">
            <h2 className="text-center text-xl font-medium mb-2">
              {paymentMethod === "credit" ? "Quantas parcelas?" : "Esse gasto se repete?"}
            </h2>
            <p className="text-center text-sm text-muted-foreground mb-8">
              {paymentMethod === "credit"
                ? "Informe o n├║mero de parcelas da compra"
                : "Ex: academia, streaming, financiamento"}
            </p>

            {/* For credit card: just show installments input directly */}
            {paymentMethod === "credit" ? (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
              >
                <label className="text-sm text-muted-foreground mb-3 block text-center">
                  N├║mero de parcelas
                </label>
                <div className="flex justify-center">
                  <div className="w-32">
                    <Input
                      type="number"
                      inputMode="numeric"
                      placeholder="Ex: 3"
                      min={1}
                      max={48}
                      value={installments}
                      onChange={(e) => {
                        const val = e.target.value;
                        if (val === "" || (parseInt(val) >= 1 && parseInt(val) <= 48)) {
                          setInstallments(val);
                        }
                      }}
                      className="h-12 text-base text-center"
                      autoFocus
                    />
                  </div>
                </div>
                <p className="text-xs text-muted-foreground text-center mt-3">
                  {installments && parseInt(installments) > 0
                    ? `${installments}x de ${new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(amount / parseInt(installments))}`
                    : "1x (├á vista)"}
                </p>
              </motion.div>
            ) : (
              <>
                {/* Yes/No Options for recurring */}
                <div className="grid grid-cols-2 gap-3 mb-6">
                  <motion.button
                    whileTap={{ scale: 0.98 }}
                    onClick={() => setIsRecurring(true)}
                    className={cn(
                      "p-4 rounded-xl border-2 flex flex-col items-center gap-3 transition-all",
                      isRecurring === true
                        ? "border-primary bg-primary/10"
                        : "border-border bg-card hover:border-muted-foreground/30"
                    )}
                  >
                    <div className={cn(
                      "w-12 h-12 rounded-full flex items-center justify-center",
                      isRecurring === true ? "bg-primary/20" : "bg-muted"
                    )}>
                      <RefreshCw className={cn(
                        "w-6 h-6",
                        isRecurring === true ? "text-primary" : "text-muted-foreground"
                      )} />
                    </div>
                    <div className="text-center">
                      <p className="font-semibold">Sim</p>
                      <p className="text-xs text-muted-foreground mt-1">
                        Gasto recorrente
                      </p>
                    </div>
                  </motion.button>

                  <motion.button
                    whileTap={{ scale: 0.98 }}
                    onClick={() => setIsRecurring(false)}
                    className={cn(
                      "p-4 rounded-xl border-2 flex flex-col items-center gap-3 transition-all",
                      isRecurring === false
                        ? "border-muted-foreground bg-secondary"
                        : "border-border bg-card hover:border-muted-foreground/30"
                    )}
                  >
                    <div className={cn(
                      "w-12 h-12 rounded-full flex items-center justify-center",
                      isRecurring === false ? "bg-muted-foreground/20" : "bg-muted"
                    )}>
                      <Calendar className={cn(
                        "w-6 h-6",
                        isRecurring === false ? "text-muted-foreground" : "text-muted-foreground"
                      )} />
                    </div>
                    <div className="text-center">
                      <p className="font-semibold">N├úo</p>
                      <p className="text-xs text-muted-foreground mt-1">
                        Gasto ├║nico
                      </p>
                    </div>
                  </motion.button>
                </div>

                {/* Installments (only if recurring) */}
                {isRecurring === true && (
                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="mt-4"
                  >
                    <label className="text-sm text-muted-foreground mb-3 block text-center">
                      Por quantos meses esse gasto se repete?
                    </label>
                    <div className="flex justify-center">
                      <div className="w-32">
                        <Input
                          type="number"
                          inputMode="numeric"
                          placeholder="Ex: 12"
                          min={1}
                          max={120}
                          value={installments}
                          onChange={(e) => {
                            const val = e.target.value;
                            if (val === "" || (parseInt(val) >= 1 && parseInt(val) <= 120)) {
                              setInstallments(val);
                            }
                          }}
                          className="h-12 text-base text-center"
                        />
                      </div>
                    </div>
                  </motion.div>
                )}
              </>
            )}
          </FadeIn>
        )}

        {/* LAYER 3 - Reimbursement */}
        {step === "reimbursement" && (
          <FadeIn key="reimbursement" className="flex-1 flex flex-col">
            <h2 className="text-center text-xl font-medium mb-2">
              Foi para outra pessoa?
            </h2>
            <p className="text-center text-sm text-muted-foreground mb-8">
              Algu├®m vai te reembolsar por esse gasto?
            </p>

            {/* Yes/No Options */}
            <div className="grid grid-cols-2 gap-3 mb-6">
              <motion.button
                whileTap={{ scale: 0.98 }}
                onClick={() => setIsForOtherPerson(true)}
                className={cn(
                  "p-4 rounded-xl border-2 flex flex-col items-center gap-3 transition-all",
                  isForOtherPerson === true
                    ? "border-essential bg-essential/10"
                    : "border-border bg-card hover:border-muted-foreground/30"
                )}
              >
                <div className={cn(
                  "w-12 h-12 rounded-full flex items-center justify-center",
                  isForOtherPerson === true ? "bg-essential/20" : "bg-muted"
                )}>
                  <Users className={cn(
                    "w-6 h-6",
                    isForOtherPerson === true ? "text-essential" : "text-muted-foreground"
                  )} />
                </div>
                <div className="text-center">
                  <p className="font-semibold">Sim</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    Vou ser reembolsado
                  </p>
                </div>
              </motion.button>

              <motion.button
                whileTap={{ scale: 0.98 }}
                onClick={() => setIsForOtherPerson(false)}
                className={cn(
                  "p-4 rounded-xl border-2 flex flex-col items-center gap-3 transition-all",
                  isForOtherPerson === false
                    ? "border-muted-foreground bg-secondary"
                    : "border-border bg-card hover:border-muted-foreground/30"
                )}
              >
                <div className={cn(
                  "w-12 h-12 rounded-full flex items-center justify-center",
                  isForOtherPerson === false ? "bg-muted-foreground/20" : "bg-muted"
                )}>
                  <User className={cn(
                    "w-6 h-6",
                    isForOtherPerson === false ? "text-muted-foreground" : "text-muted-foreground"
                  )} />
                </div>
                <div className="text-center">
                  <p className="font-semibold">N├úo</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    Gasto meu
                  </p>
                </div>
              </motion.button>
            </div>

            {/* Person Name Input */}
            {isForOtherPerson === true && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-4"
              >
                <label className="text-sm text-muted-foreground mb-3 block text-center">
                  Quem vai te reembolsar?
                </label>
                <Input
                  placeholder="Nome da pessoa"
                  value={reimbursementPersonName}
                  onChange={(e) => setReimbursementPersonName(e.target.value)}
                  maxLength={30}
                  className="text-base text-center"
                />
              </motion.div>
            )}
          </FadeIn>
        )}

        {/* LAYER 4 - Confirmation */}
        {step === "confirm" && (
          <FadeIn key="confirm" className="flex-1 flex flex-col">
            <h2 className="text-center text-xl font-medium mb-2">
              Como voc├¬ se sente sobre esse gasto?
            </h2>
            <p className="text-center text-sm text-muted-foreground mb-8">
              Isso ajuda a entender seu comportamento financeiro
            </p>

            {/* Emotion Selector */}
            <div className="mb-6">
              <label className="text-sm text-muted-foreground mb-3 block">
                Tipo de gasto
              </label>
              <div className="grid grid-cols-3 gap-2">
                {emotionOptions.map((opt) => (
                  <motion.button
                    key={opt.value}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => setSelectedEmotion(opt.value)}
                    className={cn(
                      "flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition-all",
                      selectedEmotion === opt.value
                        ? "border-primary bg-primary/10"
                        : "border-border bg-card hover:bg-secondary"
                    )}
                  >
                    <div className={cn(
                      "w-10 h-10 rounded-full flex items-center justify-center mb-1",
                      selectedEmotion === opt.value ? "bg-white/20" : "bg-muted"
                    )}>
                      {(() => { const Icon = emotionIcons[opt.value]; return <Icon className="w-5 h-5" />; })()}
                    </div>
                    <span className="text-sm font-medium">{opt.label}</span>
                    <span className="text-xs text-muted-foreground">{opt.description}</span>
                  </motion.button>
                ))}
              </div>
            </div>

            {/* Would Do Again */}
            <div className="mb-6">
              <label className="text-sm text-muted-foreground mb-3 block">
                Faria de novo?
              </label>
              <div className="grid grid-cols-2 gap-3">
                {confirmationOptions.map((opt) => (
                  <motion.button
                    key={String(opt.value)}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => setWouldDoAgain(opt.value)}
                    className={cn(
                      "flex items-center justify-center gap-2 p-4 rounded-xl border-2 transition-all",
                      wouldDoAgain === opt.value
                        ? "border-primary bg-primary/10"
                        : "border-border bg-card hover:bg-secondary"
                    )}
                  >
                    {(() => { const Icon = confirmationIcons[opt.iconKey]; return <Icon className="w-5 h-5" />; })()}
                    <span className="font-medium">{opt.label}</span>
                  </motion.button>
                ))}
              </div>
            </div>

            {/* Socratic Feedback - Insufficient Funds Warning */}
            {isInsufficient && (
              <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="p-4 rounded-xl bg-impulse/10 border border-impulse/20 mb-6"
              >
                <div className="flex items-start gap-3">
                  <AlertTriangle className="w-5 h-5 text-impulse shrink-0 mt-0.5" />
                  <div>
                    <p className="text-sm font-semibold text-impulse">Aten├º├úo: Dinheiro insuficiente</p>
                    <p className="text-xs text-muted-foreground mt-1">
                      Este valor de {formattedAmount} ├® maior do que o seu {paymentMethod === "credit" ? "limite dispon├¡vel" : "saldo atual"} ({formatCurrency(selectedAccountBalance)}).
                    </p>
                    <p className="text-xs font-medium text-impulse/80 mt-2">
                      Deseja prosseguir mesmo ficando no vermelho?
                    </p>
                  </div>
                </div>
              </motion.div>
            )}
          </FadeIn>
        )}
      </main>

      {/* Footer Button */}
      <div className="px-5 pb-safe-bottom">
        <div className="pb-4">
          {step === "expense" && (
            <div className="flex gap-3">
              <Button
                variant="outline"
                size="lg"
                className="flex-1 h-14 text-base"
                onClick={() => navigate("/")}
              >
                Cancelar
              </Button>
              <Button
                variant="warm"
                size="lg"
                className="flex-1 h-14 text-base"
                onClick={() => setStep("recurring")}
                disabled={!canContinueExpense()}
              >
                Continuar
              </Button>
            </div>
          )}
          {step === "recurring" && (
            <Button
              variant="warm"
              size="lg"
              className="w-full h-14 text-base"
              onClick={() => setStep("reimbursement")}
              disabled={!canContinueRecurring()}
            >
              Continuar
            </Button>
          )}
          {step === "reimbursement" && (
            <Button
              variant="warm"
              size="lg"
              className="w-full h-14 text-base"
              onClick={() => setStep("confirm")}
              disabled={!canContinueReimbursement()}
            >
              Continuar
            </Button>
          )}
          {step === "confirm" && (
            <div className="flex gap-3">
              <Button
                variant="outline"
                size="lg"
                className="flex-1 h-14 text-base"
                onClick={() => navigate("/")}
              >
                Cancelar
              </Button>
              <Button
                variant="warm"
                size="lg"
                className="flex-1 h-14 text-base gap-2"
                onClick={handleComplete}
                disabled={!selectedEmotion || wouldDoAgain === undefined || isSubmitting}
              >
                {isSubmitting ? (
                  <Loader2 className="w-5 h-5 animate-spin" />
                ) : (
                  <Check className="w-5 h-5" />
                )}
                Confirmar
              </Button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ConfirmExpense;

