  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

// Map to database income_type enum
type IncomeTypeDB = "salary" | "freelance" | "investment" | "gift" | "other";

const incomeTypes: { id: IncomeTypeDB; label: string; description: string; icon: React.ElementType; isRecurring: boolean }[] = [
  {
    id: "salary",
    label: "Fixa",
    description: "Sal├írio, aposentadoria, benef├¡cios",
    icon: RefreshCw,
    isRecurring: true,
  },
  {
    id: "freelance",
    label: "Vari├ível",
    description: "Freelance, comiss├úo, b├┤nus",
    icon: Zap,
    isRecurring: false,
  },
];

const paymentDays = Array.from({ length: 31 }, (_, i) => i + 1);

function getNextPaymentDate(day: number): Date {
  const now = new Date();
  const target = new Date(now.getFullYear(), now.getMonth(), day);
  if (target <= now) {
    target.setMonth(target.getMonth() + 1);
  }
  return target;
}

export const ConfirmIncome = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const createIncome = useCreateIncome();
  const { data: bankAccounts = [] } = useBankAccounts();
  const updateBankBalance = useUpdateBankBalance();
  
  const amount = location.state?.amount || 0;
  const preSelectedBankId = location.state?.preSelectedBankId as string | undefined;
  
  const [description, setDescription] = useState(location.state?.description || "");
  const [selectedType, setSelectedType] = useState<IncomeTypeDB | null>(location.state?.selectedType || null);
  const [isRecurring, setIsRecurring] = useState(location.state?.isRecurring || false);
  const [selectedBankId, setSelectedBankId] = useState<string>("");
  const [paymentDay, setPaymentDay] = useState<string>(location.state?.paymentDay || "");

  // Auto-select bank account when returning from create flow
  useEffect(() => {
    if (preSelectedBankId && bankAccounts.length > 0 && !selectedBankId) {
      if (preSelectedBankId === "latest") {
        const sorted = [...bankAccounts].sort((a, b) => 
          new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
        );
        setSelectedBankId(sorted[0].id);
      } else {
        setSelectedBankId(preSelectedBankId);
      }
    }
  }, [preSelectedBankId, bankAccounts, selectedBankId]);

  const formattedAmount = new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(amount);

  const handleTypeSelect = (typeId: IncomeTypeDB, recurring: boolean) => {
    setSelectedType(typeId);
    setIsRecurring(recurring);
    if (!recurring) {
      setPaymentDay("");
    }
  };

  // Check if payment date is today or past (within the month)
  const isFutureIncome = isRecurring && paymentDay ? getNextPaymentDate(Number(paymentDay)) > new Date() : false;

  const handleSave = async () => {
    if (!user) return;
    
    if (amount <= 0 || !description.trim() || !selectedType) {
      toast.error("Preencha todos os campos");
      return;
    }

    if (!selectedBankId) {
      toast.error("Selecione uma conta banc├íria de destino");
      return;
    }

    if (isRecurring && !paymentDay) {
      toast.error("Informe o dia do recebimento");
      return;
    }

    try {
      // Calculate income date
      let incomeDate: string;
      if (isRecurring && paymentDay) {
        const nextDate = getNextPaymentDate(Number(paymentDay));
        incomeDate = toLocalDateString(nextDate);
      } else {
        // Non-recurring: always use today's date explicitly
        incomeDate = toLocalDateString();
      }

      await createIncome.mutateAsync({
        amount,
        description: description.trim(),
        type: selectedType,
        is_recurring: isRecurring,
        bank_account_id: selectedBankId || undefined,
        date: incomeDate,
        ...(paymentDay ? { notes: `payment_day:${paymentDay}` } : {}),
      } as any);

      // Only update bank balance for non-future incomes
      if (selectedBankId && !isFutureIncome) {
        await updateBankBalance.mutateAsync({
          accountId: selectedBankId,
          delta: amount,
        });
      }
      
      toast.success(isFutureIncome 
        ? "Receita agendada! Ser├í registrada no dia do recebimento." 
        : "Receita adicionada!"
      );
      navigate("/");
    } catch (error) {
      console.error("Failed to save income:", error);
      toast.error("Erro ao salvar receita");
    }
  };

  const canSave = amount > 0 && description.trim() && selectedType && selectedBankId && (!isRecurring || paymentDay) && !createIncome.isPending;

  // Redirect if no amount
  if (!amount) {
    navigate("/income/add");
    return null;
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-3 flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/")}>
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="font-serif text-xl font-semibold">Nova Receita</h1>
        </div>
      </header>

      <main className="flex-1 px-5 space-y-6 overflow-y-auto pb-32">
        {/* Amount Display */}
        <FadeIn>
          <div className="text-center py-4">
            <p className="text-sm text-muted-foreground mb-1">Valor</p>
            <p className="font-serif text-4xl font-semibold">{formattedAmount}</p>
          </div>
        </FadeIn>

        {/* Description */}
        <FadeIn delay={0.1}>
          <div>
            <p className="text-sm font-medium mb-2">Descri├º├úo</p>
            <Input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Ex: Sal├írio, Freelance, B├┤nus..."
              className="h-12"
              maxLength={50}
            />
          </div>
        </FadeIn>

        {/* Type Selection */}
        <FadeIn delay={0.2}>
          <div>
            <p className="text-sm font-medium mb-3">Tipo de receita</p>
            <div className="grid grid-cols-2 gap-3">
              {incomeTypes.map((type) => {
                const Icon = type.icon;
                const isSelected = selectedType === type.id;
                return (
                  <motion.button
                    key={type.id}
                    whileTap={{ scale: 0.98 }}
                    onClick={() => handleTypeSelect(type.id, type.isRecurring)}
                    className={`p-4 rounded-xl border-2 text-left transition-all ${
                      isSelected
                        ? "border-primary bg-primary/5"
                        : "border-border hover:border-muted-foreground/30"
                    }`}
                  >
                    <div className="flex items-center gap-3 mb-2">
                      <div
                        className={`w-10 h-10 rounded-full flex items-center justify-center ${
                          isSelected ? "bg-primary/20" : "bg-muted"
                        }`}
                      >
                        <Icon
                          className={`w-5 h-5 ${
                            isSelected ? "text-primary" : "text-muted-foreground"
                          }`}
                        />
                      </div>
                      {isSelected && <Check className="w-4 h-4 text-primary ml-auto" />}
                    </div>
                    <p className="font-medium">{type.label}</p>
                    <p className="text-xs text-muted-foreground">{type.description}</p>
                  </motion.button>
                );
              })}
            </div>
          </div>
        </FadeIn>

        {/* Recurring Toggle & Payment Day */}
        {selectedType === "salary" && (
          <FadeIn delay={0.3}>
            <motion.button
              whileTap={{ scale: 0.98 }}
              onClick={() => setIsRecurring(!isRecurring)}
              className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 transition-all ${
                isRecurring
                  ? "border-essential bg-essential/5"
                  : "border-border"
              }`}
            >
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  isRecurring ? "bg-essential/20" : "bg-muted"
                }`}
              >
                <RefreshCw
                  className={`w-5 h-5 ${
                    isRecurring ? "text-essential" : "text-muted-foreground"
                  }`}
                />
              </div>
              <div className="flex-1 text-left">
                <p className="font-medium">Receita recorrente</p>
                <p className="text-sm text-muted-foreground">
                  Ser├í registrada automaticamente todo m├¬s
                </p>
              </div>
              <div
                className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                  isRecurring ? "border-essential bg-essential" : "border-muted-foreground"
                }`}
              >
                {isRecurring && <Check className="w-4 h-4 text-primary-foreground" />}
              </div>
            </motion.button>
          </FadeIn>
        )}

        {/* Payment Day Selector - shown when recurring */}
        {isRecurring && (
          <FadeIn delay={0.35}>
            <div className="space-y-3">
              <div className="flex items-center gap-2">
                <CalendarClock className="w-4 h-4 text-muted-foreground" />
                <p className="text-sm font-medium">Dia do recebimento *</p>
              </div>
              <Select value={paymentDay} onValueChange={setPaymentDay}>
                <SelectTrigger className="h-12">
                  <SelectValue placeholder="Selecione o dia do m├¬s" />
                </SelectTrigger>
                <SelectContent>
                  {paymentDays.map((day) => (
                    <SelectItem key={day} value={String(day)}>
                      Dia {day}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>

              {paymentDay && (
                <div className="flex items-start gap-2 p-3 rounded-xl bg-muted/50 border border-border">
                  <Info className="w-4 h-4 text-muted-foreground mt-0.5 shrink-0" />
                  <p className="text-xs text-muted-foreground">
                    Essa receita ser├í registrada e somada ao saldo apenas no dia {paymentDay} de cada m├¬s. At├® l├í, ela aparecer├í como receita prevista.
                  </p>
                </div>
              )}
            </div>
          </FadeIn>
        )}

        {/* Bank Account Selector */}
        <FadeIn delay={0.4}>
          <BankAccountSelector
            selectedId={selectedBankId}
            onSelect={(id) => setSelectedBankId(selectedBankId === id ? "" : id)}
            label={isRecurring ? "Conta de destino (quando receber) *" : "Conta de destino *"}
            emptyMessage="Para registrar uma receita, ├® necess├írio cadastrar uma conta banc├íria."
            onCreateAccount={() => {
              navigate("/banks/add", {
                state: {
                  returnTo: "/income/confirm",
                  returnState: {
                    amount,
                    description,
                    selectedType,
                    isRecurring,
                    paymentDay,
                  },
                },
              });
            }}
          />
        </FadeIn>
      </main>

      {/* Save Button */}
      <div className="fixed bottom-0 left-0 right-0 px-5 pb-8 pb-safe-bottom pt-4 bg-background/95 backdrop-blur-sm border-t border-border">
        <div className="flex gap-3">
          <Button
            variant="outline"
            size="lg"
            className="flex-1"
            onClick={() => navigate("/")}
          >
            Cancelar
          </Button>
          <Button
            variant="warm"
            size="lg"
            className="flex-1"
            onClick={handleSave}
            disabled={!canSave}
          >
            {createIncome.isPending ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin" />
                Salvando...
              </>
            ) : (
              isFutureIncome ? "Agendar" : "Salvar"
            )}
          </Button>
        </div>
      </div>
    </div>
  );
};

export default ConfirmIncome;

import { useState, useMemo } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { FadeIn, ScaleIn } from "@/components/ui/motion";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { ArrowLeft, Calendar as CalendarIcon, User, DollarSign, Loader2, AlertCircle, Landmark, Handshake, Repeat } from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { useCreateReceivable } from "@/hooks/useReceivables";
import { useBankAccounts } from "@/hooks/useBankAccounts";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";

const ConfirmReceivable = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const createReceivable = useCreateReceivable();
  const { data: bankAccounts = [] } = useBankAccounts();

  const amount = location.state?.amount || 0;

  const [debtorName, setDebtorName] = useState("");
  const [description, setDescription] = useState("");
  const [dueDate, setDueDate] = useState<Date | undefined>();
  const [isLoan, setIsLoan] = useState(false);
  const [isInstallment, setIsInstallment] = useState(false);
  const [totalInstallments, setTotalInstallments] = useState("2");
  const [bankAccountId, setBankAccountId] = useState("");
  const [sourceAccountId, setSourceAccountId] = useState("");
  const [validationError, setValidationError] = useState<string | null>(null);

  const formattedAmount = new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(amount);

  const isFormValid = useMemo(() => {
    const baseValid = debtorName.trim() && dueDate && bankAccountId;
    if (isLoan) return baseValid && sourceAccountId;
    return baseValid;
  }, [debtorName, dueDate, bankAccountId, isLoan, sourceAccountId]);

  const validateForm = (): boolean => {
    if (!user) {
      setValidationError("Voc├¬ precisa estar logado para salvar.");
      return false;
    }

    if (!debtorName.trim()) {
      setValidationError("Digite o nome da pessoa.");
      return false;
    }

    if (!dueDate) {
      setValidationError("Selecione a data de pagamento.");
      return false;
    }

    // For loans, destination is optional (might not know yet). For simple receivables, it is required.
    if (!isLoan && !bankAccountId) {
      setValidationError("Selecione a conta onde o dinheiro deve entrar.");
      return false;
    }

    if (isLoan && !sourceAccountId) {
      setValidationError("Selecione a conta de onde o dinheiro est├í saindo.");
      return false;
    }

    setValidationError(null);
    return true;
  };

  const handleSubmit = async () => {
    if (!validateForm()) return;

    try {
      await createReceivable.mutateAsync({
        debtor_name: debtorName.trim(),
        amount,
        description: description.trim() || null,
        due_date: format(dueDate!, "yyyy-MM-dd"),
        status: "pending",
        type: isLoan ? "loan" : "simple",
        is_installment: isInstallment,
        total_installments: isInstallment ? parseInt(totalInstallments) : 1,
        // For non-loans, destination is required. For loans, it is optional (can be decided later).
        bank_account_id: isLoan ? (bankAccountId || null) : bankAccountId,
        source_account_id: isLoan ? sourceAccountId : null,
      });

      toast.success(isLoan ? "Empr├®stimo registrado com sucesso!" : "Valor a receber registrado!");
      navigate("/");
    } catch (error: any) {
      console.error("Failed to save receivable:", error);
      const errorMessage = error?.message || "Erro desconhecido";
      toast.error(`Erro ao salvar: ${errorMessage}`);
    }
  };

  if (!amount) {
    navigate("/receivables/add");
    return null;
  }

  return (
    <div className="min-h-screen bg-background pb-32">
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-4">
          <FadeIn>
            <div className="flex items-center gap-3">
              <Button
                variant="ghost"
                size="icon"
                className="h-9 w-9"
                onClick={() => navigate("/")}
              >
                <ArrowLeft className="h-5 w-5" />
              </Button>
              <h1 className="font-serif text-2xl font-semibold">
                {isLoan ? "Conceder Empr├®stimo" : "Valor a receber"}
              </h1>
            </div>
          </FadeIn>
        </div>
      </header>

      <main className="px-5 space-y-6">
        <FadeIn>
          <div className="text-center py-4">
            <p className="text-sm text-muted-foreground mb-1">Valor Total</p>
            <p className="font-serif text-4xl font-semibold text-essential">{formattedAmount}</p>
          </div>
        </FadeIn>

        <div className="space-y-5">
          {/* Debtor Name */}
          <FadeIn delay={0.05} className="space-y-2">
            <Label htmlFor="debtorName" className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">
              Nome da pessoa
            </Label>
            <div className="relative">
              <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
              <Input
                id="debtorName"
                placeholder="Quem deve para voc├¬?"
                value={debtorName}
                onChange={(e) => setDebtorName(e.target.value)}
                className="pl-11 h-12 bg-secondary/30 border-none shadow-none focus-visible:ring-primary"
              />
            </div>
          </FadeIn>

          {/* Loan Toggle */}
          <FadeIn delay={0.1}>
            <div className="p-4 rounded-2xl bg-secondary/20 border border-border/50 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="p-2 rounded-xl bg-primary/10">
                  <Handshake className="w-5 h-5 text-primary" />
                </div>
                <div>
                  <p className="text-sm font-bold">├ë um empr├®stimo?</p>
                  <p className="text-[10px] text-muted-foreground">O dinheiro sair├í da sua conta agora.</p>
                </div>
              </div>
              <Switch checked={isLoan} onCheckedChange={setIsLoan} />
            </div>
          </FadeIn>

          {/* Accounts Section */}
          <FadeIn delay={0.15} className="space-y-4">
            {isLoan && (
              <ScaleIn className="space-y-2">
                <Label className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">Conta de Origem (Sa├¡da)</Label>
                <Select value={sourceAccountId} onValueChange={setSourceAccountId}>
                  <SelectTrigger className="h-12 bg-secondary/30 border-none focus:ring-primary">
                    <SelectValue placeholder="De onde sai o dinheiro?" />
                  </SelectTrigger>
                  <SelectContent className="bg-popover border-border/50">
                    {bankAccounts.map((acc) => (
                      <SelectItem key={acc.id} value={acc.id}>
                        <div className="flex items-center gap-2">
                          <Landmark className="w-4 h-4" />
                          <span>{acc.bank_name}</span>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </ScaleIn>
            )}

            <div className="space-y-2">
              <div className="flex justify-between items-center">
                <Label className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">
                  {isLoan ? "Conta de Destino (Opcional)" : "Conta de Destino (Futuro)"}
                </Label>
                {isLoan && bankAccountId && (
                  <Button variant="ghost" size="sm" onClick={() => setBankAccountId("")} className="h-6 px-2 text-xs">
                    Limpar
                  </Button>
                )}
              </div>
              <Select value={bankAccountId} onValueChange={setBankAccountId}>
                <SelectTrigger className="h-12 bg-secondary/30 border-none focus:ring-primary">
                  <SelectValue placeholder={isLoan ? "Onde deve entrar (se souber)" : "Onde o dinheiro vai entrar?"} />
                </SelectTrigger>
                <SelectContent className="bg-popover border-border/50">
                  {bankAccounts.map((acc) => (
                    <SelectItem key={acc.id} value={acc.id}>
                      <div className="flex items-center gap-2">
                        <Landmark className="w-4 h-4" />
                        <span>{acc.bank_name}</span>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </FadeIn>

          {/* Date Picker */}
          <FadeIn delay={0.2} className="space-y-2">
            <Label className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">
              {isInstallment ? "Data da 1┬¬ Parcela" : "Data do Recebimento"}
            </Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  className={cn(
                    "w-full h-12 justify-start text-left font-normal bg-secondary/30 border-none",
                    !dueDate && "text-muted-foreground"
                  )}
                >
                  <CalendarIcon className="mr-2 h-5 w-5" />
                  {dueDate
                    ? format(dueDate, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })
                    : "Selecione uma data"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 z-50 bg-popover" align="start">
                <Calendar
                  mode="single"
                  selected={dueDate}
                  onSelect={setDueDate}
                  initialFocus
                  locale={ptBR}
                />
              </PopoverContent>
            </Popover>
          </FadeIn>

          {/* Installment Section */}
          <FadeIn delay={0.25} className="space-y-4">
            <div className="p-4 rounded-2xl bg-secondary/20 border border-border/50 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="p-2 rounded-xl bg-accent/10">
                  <Repeat className="w-5 h-5 text-accent" />
                </div>
                <div>
                  <p className="text-sm font-bold">Parcelado?</p>
                  <p className="text-[10px] text-muted-foreground">Ser├úo criados registros mensais.</p>
                </div>
              </div>
              <Switch checked={isInstallment} onCheckedChange={setIsInstallment} />
            </div>

            {isInstallment && (
              <ScaleIn className="space-y-2">
                <Label className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">N├║mero de Parcelas</Label>
                <Input
                  type="number"
                  min="2"
                  max="120"
                  value={totalInstallments}
                  onChange={(e) => setTotalInstallments(e.target.value)}
                  className="h-12 bg-secondary/30 border-none shadow-none"
                />
              </ScaleIn>
            )}
          </FadeIn>

          {/* Description */}
          <FadeIn delay={0.3} className="space-y-2">
            <Label htmlFor="description" className="text-sm font-bold uppercase tracking-widest text-muted-foreground/80">
              Descri├º├úo (opcional)
            </Label>
            <Textarea
              id="description"
              placeholder="Ex: Almo├ºo, presente..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="bg-secondary/30 border-none resize-none focus-visible:ring-primary min-h-[100px]"
            />
          </FadeIn>

          {/* Validation & Submit */}
          <FadeIn delay={0.35} className="pt-4 pb-8">
            {validationError && (
              <div className="flex items-center gap-2 p-4 rounded-2xl bg-destructive/10 text-destructive text-sm mb-4 border border-destructive/20 scale-in-sm">
                <AlertCircle className="w-5 h-5" />
                {validationError}
              </div>
            )}

            <div className="flex gap-3">
              <Button
                variant="ghost"
                className="flex-1 h-14 rounded-2xl font-bold uppercase tracking-widest text-xs"
                onClick={() => navigate("/")}
              >
                Cancelar
              </Button>
              <Button
                variant="warm"
                className="flex-1 h-14 rounded-2xl font-bold uppercase tracking-widest text-xs shadow-lg shadow-primary/20"
                disabled={!isFormValid || createReceivable.isPending}
                onClick={handleSubmit}
              >
                {createReceivable.isPending ? (
                  <Loader2 className="w-5 h-5 animate-spin" />
                ) : (
                  "Confirmar"
                )}
              </Button>
            </div>
          </FadeIn>
        </div>
      </main>
    </div>
  );
};

export default ConfirmReceivable;

import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { FadeIn } from "@/components/ui/motion";
import { BottomNav } from "@/components/BottomNav";
import { ChevronLeft, Plus, CreditCard as CreditCardIcon, ChevronRight, Smartphone as PhoneIcon } from "lucide-react";
import { useProfile } from "@/hooks/useProfile";
import { useCreditCards } from "@/hooks/useCreditCards";
import { cn } from "@/lib/utils";
import { detectBank, detectBrand, getCardColor } from "@/lib/cardBranding";

const formatCurrency = (value: number) =>
  new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(value);

export default function CreditCards() {
  const navigate = useNavigate();
  const { data: cards = [], isLoading } = useCreditCards();
  const { data: profile } = useProfile();
  const defaultCardId = (profile as any)?.wa_default_expense_card_id;

  return (
    <div className="min-h-screen bg-background pb-24">
