export const DebugStress = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const [loading, setLoading] = useState(false);
    const [progress, setProgress] = useState(0);
    const [totalRecords] = useState(5000);
    const [status, setStatus] = useState<"idle" | "running" | "success" | "error">("idle");

    const emotions = ["pilar", "essencial", "impulso"];

    const runSimulation = async () => {
        if (!user) {
            toast.error("Usu├írio n├úo autenticado");
            return;
        }

        setLoading(true);
        setStatus("running");
        setProgress(0);

        try {
            // 1. Fetch real categories to make the dashboard look real
            const { data: userCategories } = await supabase
                .from("categories")
                .select("id, name")
                .eq("user_id", user.id);

            const batchSize = 500;
            const totalBatches = totalRecords / batchSize;

            for (let b = 0; b < totalBatches; b++) {
                const batchData = [];

                for (let i = 0; i < batchSize; i++) {
                    const isExpense = Math.random() > 0.05; // 95% expenses
                    const randomDays = Math.floor(Math.random() * 180); // Last 6 months
                    const baseDate = subMonths(new Date(), Math.floor(randomDays / 30));
                    const adjustedDate = addDays(baseDate, Math.floor(Math.random() * 28));

                    if (isExpense) {
                        const randomCat = userCategories && userCategories.length > 0
                            ? userCategories[Math.floor(Math.random() * userCategories.length)]
                            : null;

                        batchData.push({
                            user_id: user.id,
                            amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
                            description: `Gasto Simulado ${b * batchSize + i}`,
                            category_id: randomCat?.id || null,
                            emotion: emotions[Math.floor(Math.random() * emotions.length)],
                            date: format(adjustedDate, "yyyy-MM-dd"),
                            status: "confirmed",
                            source: "manual",
                            is_installment: false,
                        });
                    }
                }

                if (batchData.length > 0) {
                    const { error } = await supabase.from("expenses").insert(batchData);
                    if (error) throw error;
                }

                // Add some major incomes for each month in the range
                if (b % 2 === 0) { // Every 1000 records, add some salaries
                    const incomeData = [];
                    for (let m = 0; m < 6; m++) {
                        const date = subMonths(new Date(), m);
                        incomeData.push({
                            user_id: user.id,
                            amount: 6500,
                            description: "Sal├írio Mensal Principal",
                            date: format(date, "yyyy-MM-01"),
                            type: "salary",
                            is_recurring: true,
                        });
                    }
                    await supabase.from("incomes").insert(incomeData);
                }

                const currentProgress = Math.round(((b + 1) / totalBatches) * 100);
                setProgress(currentProgress);
            }

            setStatus("success");
            toast.success("5.000 registros inseridos com sucesso!");
        } catch (error: any) {
            console.error("Stress Test Error:", error);
            setStatus("error");
            toast.error(`Falha na simula├º├úo: ${error.message}`);
        } finally {
            setLoading(false);
        }
    };

    const clearData = async () => {
        if (!confirm("Isso apagar├í TODOS os seus gastos e receitas. Tem certeza?")) return;

        setLoading(true);
        try {
            const { error: e1 } = await supabase.from("expenses").delete().eq("user_id", user?.id);
            const { error: e2 } = await supabase.from("incomes").delete().eq("user_id", user?.id);

            if (e1 || e2) throw e1 || e2;

            toast.success("Dados limpos com sucesso!");
            setStatus("idle");
            setProgress(0);
        } catch (error: any) {
            toast.error("Erro ao limpar dados");
        } finally {
            setLoading(false);
        }
    };

    return (
        <AppLayout>
            <div className="min-h-screen bg-background p-6 flex flex-col items-center justify-center">
                <FadeIn className="max-w-md w-full space-y-8 text-center">
                    <div className="w-20 h-20 bg-primary/10 rounded-3xl flex items-center justify-center mx-auto mb-6">
                        <Database className="w-10 h-10 text-primary" />
                    </div>

                    <div className="space-y-2">
                        <h1 className="text-3xl font-serif font-bold">Simulador de Estresse</h1>
                        <p className="text-muted-foreground">
                            Esta ferramenta ir├í inserir 5.000 registros de transa├º├Áes para testar a performance e escala do Saldin.
                        </p>
                    </div>

                    <div className="bg-card/50 backdrop-blur-sm border border-border/50 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden group">
                        <div className="absolute inset-0 bg-primary/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                        {(status === "idle" || status === "error") && (
                            <div className="space-y-6 relative z-10">
                                <Button
                                    onClick={runSimulation}
                                    variant="warm"
                                    size="xl"
                                    className="w-full shadow-lg hover:shadow-xl transition-all active:scale-95"
                                    disabled={loading}
                                >
                                    {loading ? (
                                        <Loader2 className="mr-2 animate-spin h-6 w-6" />
                                    ) : (
                                        "Iniciar Simula├º├úo (5.000)"
                                    )}
                                </Button>

                                <div className="flex flex-col gap-2">
                                    <Button
                                        variant="outline"
                                        onClick={clearData}
                                        className="w-full text-destructive hover:bg-destructive/10 border-destructive/20"
                                        disabled={loading}
                                    >
                                        Limpar Todos os Dados
                                    </Button>
                                </div>
                            </div>
                        )}

                        {status === "running" && (
                            <div className="space-y-4">
                                <div className="flex justify-between text-sm mb-2">
                                    <span>Processando registros...</span>
                                    <span className="font-bold">{progress}%</span>
                                </div>
                                <div className="h-3 w-full bg-secondary rounded-full overflow-hidden">
                                    <div
                                        className="h-full bg-primary transition-all duration-300"
                                        style={{ width: `${progress}%` }}
                                    />
                                </div>
                                <p className="text-xs text-muted-foreground animate-pulse">
                                    Inserindo lotes no Supabase. N├úo feche a aba.
                                </p>
                            </div>
                        )}

                        {status === "success" && (
                            <div className="space-y-4 py-4">
                                <CheckCircle2 className="w-16 h-16 text-essential mx-auto" />
                                <h3 className="text-xl font-bold">Simula├º├úo Conclu├¡da!</h3>
                                <p className="text-sm text-muted-foreground">
                                    A base de dados agora cont├®m 5.000 transa├º├Áes simuladas.
                                </p>
                                <Button onClick={() => navigate("/")} variant="outline" className="w-full">
                                    Ver Dashboard
                                </Button>
                            </div>
                        )}

                        {status === "error" && (
                            <div className="space-y-4 py-4">
                                <AlertCircle className="w-16 h-16 text-impulse mx-auto" />
                                <h3 className="text-xl font-bold">Erro na Simula├º├úo</h3>
                                <Button onClick={() => setStatus("idle")} variant="outline" className="w-full">
                                    Tentar Novamente
                                </Button>
                            </div>
                        )}
                    </div>

                    <Button variant="ghost" onClick={() => navigate("/")}>
                        Voltar para o App
                    </Button>
                </FadeIn>
            </div>
        </AppLayout>
    );
};

export default DebugStress;

import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { BottomNav } from "@/components/BottomNav";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, User, Mail, Lock, Eye, EyeOff, Check, Loader2 } from "lucide-react";
import { toast } from "@/hooks/use-toast";
import { validatePassword } from "@/lib/passwordValidation";
import { PasswordStrengthChecklist } from "@/components/PasswordStrengthChecklist";
import { useAuth } from "@/hooks/useAuth";
import { useProfile, useUpdateProfile } from "@/hooks/useProfile";
import { supabase } from "@/lib/backendClient";
import { useBankAccounts } from "@/hooks/useBankAccounts";
import { useCreditCards } from "@/hooks/useCreditCards";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Wallet, Smartphone as PhoneIcon, TrendingUp, CreditCard } from "lucide-react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export const EditAccount = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { data: profile, isLoading: profileLoading } = useProfile();
  const updateProfile = useUpdateProfile();

  // User data - initialized from auth/profile
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");

  // WhatsApp defaults
  const [defaultIncomeAcc, setDefaultIncomeAcc] = useState<string>("none");
  const [defaultExpenseAcc, setDefaultExpenseAcc] = useState<string>("none");
  const [defaultExpenseCard, setDefaultExpenseCard] = useState<string>("none");

  // Confirmation state
  const [confirmData, setConfirmData] = useState<{
    show: boolean;
    title: string;
    description: string;
    onConfirm: () => void;
  }>({
    show: false,
    title: "",
    description: "",
    onConfirm: () => { },
  });

  const { data: bankAccounts = [] } = useBankAccounts();
  const { data: creditCards = [] } = useCreditCards();

  // Initialize form with user data when available
  useEffect(() => {
    if (profile?.full_name) {
      setName(profile.full_name);
    } else if (user?.user_metadata?.name || user?.user_metadata?.full_name) {
      setName(user.user_metadata.name || user.user_metadata.full_name || "");
    }

    if (user?.email) {
      setEmail(user.email);
    }

    if (profile) {
      if ((profile as any).wa_default_income_account_id) setDefaultIncomeAcc((profile as any).wa_default_income_account_id);
      if ((profile as any).wa_default_expense_account_id) setDefaultExpenseAcc((profile as any).wa_default_expense_account_id);
      if ((profile as any).wa_default_expense_card_id) setDefaultExpenseCard((profile as any).wa_default_expense_card_id);
    }
  }, [profile, user]);

  // Password fields
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  // Password visibility toggles
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  // Loading states
  const [savingProfile, setSavingProfile] = useState(false);
  const [savingPassword, setSavingPassword] = useState(false);

  const handleSaveProfile = async () => {
    if (!name.trim()) {
      toast({
        title: "Nome obrigat├│rio",
        description: "Por favor, insira seu nome.",
        variant: "destructive",
      });
      return;
    }

    if (!email.trim() || !email.includes("@")) {
      toast({
        title: "Email inv├ílido",
        description: "Por favor, insira um email v├ílido.",
        variant: "destructive",
      });
      return;
    }

    setSavingProfile(true);

    try {
      // Update profile name in profiles table
      await updateProfile.mutateAsync({
        full_name: name.trim(),
        wa_default_income_account_id: defaultIncomeAcc === "none" ? null : defaultIncomeAcc,
        wa_default_expense_account_id: defaultExpenseAcc === "none" ? null : defaultExpenseAcc,
        wa_default_expense_card_id: defaultExpenseCard === "none" ? null : defaultExpenseCard,
      } as any);

      // Also update user_metadata in Supabase Auth
      await supabase.auth.updateUser({
        data: { name: name.trim(), full_name: name.trim() },
      });

      // Update email if changed
      if (email.trim() !== user?.email) {
        const { error } = await supabase.auth.updateUser({ email: email.trim() });
        if (error) throw error;
      }

      toast({
        title: "Dados atualizados",
        description: "Suas informa├º├Áes foram salvas com sucesso.",
      });

      // Navigate to settings after successful save
      navigate("/settings");
    } catch (error: any) {
      console.error("Erro ao salvar perfil:", error);
      toast({
        title: "Erro ao salvar",
        description: error.message || "N├úo foi poss├¡vel atualizar os dados.",
        variant: "destructive",
      });
      setSavingProfile(false);
    }
  };

  const handleChangePassword = async () => {
    if (!currentPassword) {
      toast({
        title: "Senha atual obrigat├│ria",
        description: "Por favor, insira sua senha atual.",
        variant: "destructive",
      });
      return;
    }

    const passwordValidation = validatePassword(newPassword);
    if (!passwordValidation.isValid) {
      let message = "A nova senha n├úo atende aos requisitos de seguran├ºa.";
      if (passwordValidation.isCommonPassword) {
        message = "Esta senha ├® muito comum. Escolha uma senha mais forte.";
      }
      toast({
        title: "Senha inv├ílida",
        description: message,
        variant: "destructive",
      });
      return;
    }

    if (newPassword !== confirmPassword) {
      toast({
        title: "Senhas n├úo coincidem",
        description: "A confirma├º├úo da senha n├úo corresponde ├á nova senha.",
        variant: "destructive",
      });
      return;
    }

    setSavingPassword(true);

    try {
      // First verify current password by re-authenticating
      const { error: signInError } = await supabase.auth.signInWithPassword({
        email: user?.email || "",
        password: currentPassword,
      });

      if (signInError) {
        throw new Error("Senha atual incorreta.");
      }

      // Update to new password
      const { error: updateError } = await supabase.auth.updateUser({
        password: newPassword,
      });

      if (updateError) throw updateError;

      // Clear password fields
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");

      toast({
        title: "Senha alterada",
        description: "Sua senha foi atualizada com sucesso.",
      });
    } catch (error: any) {
      toast({
        title: "Erro ao alterar senha",
        description: error.message || "N├úo foi poss├¡vel alterar a senha.",
        variant: "destructive",
      });
    } finally {
      setSavingPassword(false);
    }
  };

  if (profileLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-24">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-3 flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/")}>
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="font-serif text-xl font-semibold">Editar conta</h1>
        </div>
      </header>

      <main className="px-5 space-y-6">
        {/* Profile Section */}
        <FadeIn>
          <div className="bg-card rounded-xl border border-border shadow-soft p-5 space-y-4">
            <h2 className="text-sm font-medium text-muted-foreground uppercase tracking-wide">
              Informa├º├Áes pessoais
            </h2>

            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name" className="flex items-center gap-2">
                  <User className="w-4 h-4 text-muted-foreground" />
                  Nome
                </Label>
                <Input
                  id="name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Seu nome"
                  maxLength={50}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="email" className="flex items-center gap-2">
                  <Mail className="w-4 h-4 text-muted-foreground" />
                  Email
                </Label>
                <Input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="seu@email.com"
                  maxLength={100}
                />
              </div>
            </div>

            <Button
              variant="warm"
              className="w-full mt-2"
              onClick={handleSaveProfile}
              disabled={savingProfile}
            >
              {savingProfile ? (
                "Salvando..."
              ) : (
                <>
                  <Check className="w-4 h-4" />
                  Salvar altera├º├Áes
                </>
              )}
            </Button>
          </div>
        </FadeIn>

        {/* WhatsApp Config Section */}
        <FadeIn delay={0.05}>
          <div className="bg-card rounded-xl border border-border shadow-soft p-5 space-y-4">
            <h2 className="text-sm font-medium text-muted-foreground uppercase tracking-wide flex items-center gap-2">
              <PhoneIcon className="w-4 h-4" />
              WhatsApp (Saldin AI)
            </h2>

            <p className="text-sm text-muted-foreground">
              Configure as contas padr├úo para quando voc├¬ registrar transa├º├Áes pelo WhatsApp.
            </p>

            <div className="space-y-4">
              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <TrendingUp className="w-4 h-4 text-essential" />
                  Conta para Receitas
                </Label>
                <Select
                  value={defaultIncomeAcc}
                  onValueChange={(val) => {
                    const existingId = (profile as any)?.wa_default_income_account_id;
                    if (val !== "none" && existingId && val !== existingId) {
                      const oldName = bankAccounts.find(a => a.id === existingId)?.bank_name;
                      const newName = bankAccounts.find(a => a.id === val)?.bank_name;
                      setConfirmData({
                        show: true,
                        title: "Substituir conta de receitas?",
                        description: `Deseja trocar a conta principal de receitas de ${oldName} para ${newName}?`,
                        onConfirm: () => setDefaultIncomeAcc(val)
                      });
                    } else {
                      setDefaultIncomeAcc(val);
                    }
                  }}
                >
                  <SelectTrigger className="bg-background">
                    <SelectValue placeholder="Selecione uma conta" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nenhuma (usar padr├úo geral)</SelectItem>
                    {bankAccounts.map((acc) => (
                      <SelectItem key={acc.id} value={acc.id}>
                        {acc.bank_name} ({acc.account_type === 'checking' ? 'Corrente' : 'Poupan├ºa'})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <CreditCard className="w-4 h-4 text-violet-500" />
                  Cart├úo para Gastos (Cr├®dito)
                </Label>
                <Select
                  value={defaultExpenseCard}
                  onValueChange={(val) => {
                    const existingId = (profile as any)?.wa_default_expense_card_id;
                    if (val !== "none" && existingId && val !== existingId) {
                      const oldName = creditCards.find(c => c.id === existingId)?.card_name;
                      const newName = creditCards.find(c => c.id === val)?.card_name;
                      setConfirmData({
                        show: true,
                        title: "Substituir cart├úo principal?",
                        description: `Deseja trocar o cart├úo principal de gastos de ${oldName} para ${newName}?`,
                        onConfirm: () => setDefaultExpenseCard(val)
                      });
                    } else {
                      setDefaultExpenseCard(val);
                    }
                  }}
                >
                  <SelectTrigger className="bg-background">
                    <SelectValue placeholder="Selecione um cart├úo" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nenhum (usar conta banc├íria)</SelectItem>
                    {creditCards.map((card) => (
                      <SelectItem key={card.id} value={card.id}>
                        {card.card_name} (final {card.last_four_digits})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <Wallet className="w-4 h-4 text-impulse" />
                  Conta para Gastos (D├®bito/Pix)
                </Label>
                <Select
                  value={defaultExpenseAcc}
                  onValueChange={(val) => {
                    const existingId = (profile as any)?.wa_default_expense_account_id;
                    if (val !== "none" && existingId && val !== existingId) {
                      const oldName = bankAccounts.find(a => a.id === existingId)?.bank_name;
                      const newName = bankAccounts.find(a => a.id === val)?.bank_name;
                      setConfirmData({
                        show: true,
                        title: "Substituir conta de gastos?",
                        description: `Deseja trocar a conta principal de gastos (d├®bito) de ${oldName} para ${newName}?`,
                        onConfirm: () => setDefaultExpenseAcc(val)
                      });
                    } else {
                      setDefaultExpenseAcc(val);
                    }
                  }}
                >
                  <SelectTrigger className="bg-background">
                    <SelectValue placeholder="Selecione uma conta" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nenhuma (usar primeira conta)</SelectItem>
                    {bankAccounts.map((acc) => (
                      <SelectItem key={acc.id} value={acc.id}>
                        {acc.bank_name} ({acc.account_type === 'checking' ? 'Corrente' : 'Poupan├ºa'})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <Button
              variant="warm"
              className="w-full mt-2"
              onClick={handleSaveProfile}
              disabled={savingProfile}
            >
              {savingProfile ? "Salvando..." : "Salvar Configura├º├Áes WhatsApp"}
            </Button>
          </div>
        </FadeIn>

        <AlertDialog
          open={confirmData.show}
          onOpenChange={(open) => setConfirmData(prev => ({ ...prev, show: open }))}
        >
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>{confirmData.title}</AlertDialogTitle>
              <AlertDialogDescription>{confirmData.description}</AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>N├úo, manter atual</AlertDialogCancel>
              <AlertDialogAction onClick={() => {
                confirmData.onConfirm();
                setConfirmData(prev => ({ ...prev, show: false }));
              }}>
                Sim, substituir
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Security Section */}
        <FadeIn delay={0.1}>
          <div className="bg-card rounded-xl border border-border shadow-soft p-5 space-y-4">
            <h2 className="text-sm font-medium text-muted-foreground uppercase tracking-wide flex items-center gap-2">
              <Lock className="w-4 h-4" />
              Seguran├ºa
            </h2>

            <p className="text-sm text-muted-foreground">
              Para alterar sua senha, preencha os campos abaixo.
            </p>

            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="currentPassword">Senha atual</Label>
                <div className="relative">
                  <Input
                    id="currentPassword"
                    type={showCurrentPassword ? "text" : "password"}
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                    className="pr-10"
                  />
                  <button
                    type="button"
                    onClick={() => setShowCurrentPassword(!showCurrentPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                  >
                    {showCurrentPassword ? (
                      <EyeOff className="w-4 h-4" />
                    ) : (
                      <Eye className="w-4 h-4" />
                    )}
                  </button>
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="newPassword">Nova senha</Label>
                <div className="relative">
                  <Input
                    id="newPassword"
                    type={showNewPassword ? "text" : "password"}
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    placeholder="Crie uma senha forte"
                    className="pr-10"
                  />
                  <button
                    type="button"
                    onClick={() => setShowNewPassword(!showNewPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                  >
                    {showNewPassword ? (
                      <EyeOff className="w-4 h-4" />
                    ) : (
                      <Eye className="w-4 h-4" />
                    )}
                  </button>
                </div>
                <PasswordStrengthChecklist password={newPassword} />
              </div>

              <div className="space-y-2">
                <Label htmlFor="confirmPassword">Confirmar nova senha</Label>
                <div className="relative">
                  <Input
                    id="confirmPassword"
                    type={showConfirmPassword ? "text" : "password"}
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="Repita a nova senha"
                    className="pr-10"
                  />
                  <button
                    type="button"
                    onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                  >
                    {showConfirmPassword ? (
                      <EyeOff className="w-4 h-4" />
                    ) : (
                      <Eye className="w-4 h-4" />
                    )}
                  </button>
                </div>
              </div>
            </div>

            <Button
              variant="outline"
              className="w-full mt-2"
              onClick={handleChangePassword}
              disabled={savingPassword || (!currentPassword && !newPassword && !confirmPassword) || (newPassword && !validatePassword(newPassword).isValid)}
            >
              {savingPassword ? (
                "Alterando senha..."
              ) : (
                <>
                  <Lock className="w-4 h-4" />
                  Alterar senha
                </>
              )}
            </Button>
          </div>
        </FadeIn>
      </main>

      <BottomNav />
    </div>
  );
};

export default EditAccount;

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { CurrencyInput } from "@/components/ui/currency-input";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Check, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { useBankAccountById, useUpdateBankAccount } from "@/hooks/useBankAccounts";
import { BANK_LIST } from "@/lib/cardBranding";
import { accountTypeOptions, type BankAccountType } from "@/types/bankAccount";
import { parseCurrency } from "@/lib/currency";
import { BankLogo } from "@/components/BankLogo";
import { useProfile, useUpdateProfile } from "@/hooks/useProfile";
import { Switch } from "@/components/ui/switch";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useBankAccounts } from "@/hooks/useBankAccounts";

export const EditBankAccount = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { data: account, isLoading } = useBankAccountById(id);
    const updateAccount = useUpdateBankAccount();
    const { data: profile } = useProfile();
    const updateProfile = useUpdateProfile();

    const [bankKey, setBankKey] = useState<string>("");
    const [customBankName, setCustomBankName] = useState("");
    const [accountType, setAccountType] = useState<BankAccountType>("checking");
    const [currentBalance, setCurrentBalance] = useState("");
    const [isMainAccount, setIsMainAccount] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);

    const { data: accounts = [] } = useBankAccounts();

    // Find existing main account for confirmation message
    const existingIncomeAccId = (profile as any)?.wa_default_income_account_id;
    const existingIncomeAcc = accounts.find(a => a.id === existingIncomeAccId);
    const isEditingCurrentMain = existingIncomeAccId === id;

    useEffect(() => {
        if (account) {
            setBankKey(account.bank_key || "outros");
            setCustomBankName(account.bank_name);
            setAccountType(account.account_type);
            setCurrentBalance(account.current_balance.toString());

            // Check if this is the main account in profile
            if (profile) {
                const isMain = (profile as any).wa_default_income_account_id === account.id ||
                    (profile as any).wa_default_expense_account_id === account.id;
                setIsMainAccount(isMain);
            }
        }
    }, [account, profile]);

    const selectedBank = BANK_LIST.find((b) => b.key === bankKey);
    const bankName = bankKey === "outros" ? customBankName : selectedBank?.name || customBankName;

    const canSave = bankName.trim().length > 0;

    const handleSave = async () => {
        if (!canSave || !id) return;

        const balance = parseCurrency(currentBalance);

        await updateAccount.mutateAsync({
            id,
            bank_name: bankName.trim(),
            bank_key: bankKey === "outros" ? null : bankKey,
            account_type: accountType,
            current_balance: balance,
            color: selectedBank?.color || account?.color || null,
        });

        if (isMainAccount) {
            // Define como padr├úo no perfil
            await updateProfile.mutateAsync({
                wa_default_income_account_id: id,
                wa_default_expense_account_id: id
            } as any);
        } else {
            // Se era a principal e desmarcou, removemos (opcional, mas seguro)
            if ((profile as any).wa_default_income_account_id === id) {
                await updateProfile.mutateAsync({
                    wa_default_income_account_id: null,
                    wa_default_expense_account_id: null
                } as any);
            }
        }

        navigate(`/banks/${id}`);
    };

    if (isLoading) {
        return (
            <div className="min-h-screen bg-background flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex flex-col">
            <header className="px-5 pt-safe-top">
                <div className="pt-4 pb-2 flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => navigate(`/banks/${id}`)}>
                        <ArrowLeft className="w-5 h-5" />
                    </Button>
                    <h1 className="font-serif text-xl font-semibold">Editar Conta</h1>
                </div>
            </header>

            <main className="flex-1 px-5 py-6 overflow-y-auto pb-32">
                {/* Bank selector */}
                <FadeIn className="mb-6">
                    <label className="text-sm text-muted-foreground mb-3 block">Escolha o banco</label>
                    <div className="flex gap-4 overflow-x-auto pb-4 snap-x snap-mandatory no-scrollbar">
                        {BANK_LIST.filter((b) => b.key !== "outros").map((bank) => (
                            <motion.button
                                key={bank.key}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => {
                                    setBankKey(bank.key);
                                    setCustomBankName("");
                                }}
                                className="flex flex-col items-center gap-2 min-w-[72px] snap-center"
                            >
                                <div className={cn(
                                    "w-14 h-14 rounded-full flex items-center justify-center transition-all border-2 shadow-sm",
                                    bankKey === bank.key
                                        ? "border-primary ring-2 ring-primary/20 ring-offset-2 scale-110"
                                        : "border-border bg-card hover:border-primary/50"
                                )}
                                    style={{ backgroundColor: bankKey === bank.key ? bank.color : "#ffffff" }}
                                >
                                    {bankKey === bank.key ? (
                                        <Check className="w-6 h-6 text-white" />
                                    ) : (
                                        <BankLogo bankName={bank.name} color={bank.color} size="lg" />
                                    )}
                                </div>
                                <span className={cn(
                                    "text-xs font-bold text-center truncate w-full transition-colors",
                                    bankKey === bank.key ? "text-primary" : "text-muted-foreground"
                                )}>
                                    {bank.name}
                                </span>
                            </motion.button>
                        ))}
                    </div>
                </FadeIn>

                {/* Account type */}
                <FadeIn delay={0.05} className="mb-6">
                    <label className="text-sm text-muted-foreground mb-3 block">Tipo de conta</label>
                    <div className="grid grid-cols-3 gap-2">
                        {accountTypeOptions.map((opt) => (
                            <motion.button
                                key={opt.value}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => setAccountType(opt.value)}
                                className={cn(
                                    "p-3 rounded-xl border-2 text-center transition-all",
                                    accountType === opt.value
                                        ? "border-primary bg-primary/10 text-primary font-medium"
                                        : "border-border bg-card hover:bg-secondary"
                                )}
                            >
                                <span className="text-sm">{opt.label}</span>
                            </motion.button>
                        ))}
                    </div>
                </FadeIn>

                {/* Balance */}
                <FadeIn delay={0.1} className="mb-6">
                    <label className="text-sm text-muted-foreground mb-2 block">
                        Saldo Atual
                    </label>
                    <CurrencyInput value={currentBalance} onChange={setCurrentBalance} />
                </FadeIn>

                {/* Main account toggle */}
                <FadeIn delay={0.15}>
                    <div className="flex items-center justify-between p-4 rounded-xl bg-card border border-border shadow-soft">
                        <div>
                            <p className="text-sm font-medium">Definir como conta principal</p>
                            <p className="text-xs text-muted-foreground">Usar para transa├º├Áes autom├íticas via WhatsApp</p>
                        </div>
                        <Switch
                            checked={isMainAccount}
                            onCheckedChange={(checked) => {
                                // Only show confirm if trying to enable on a non-main account while another exists
                                if (checked && existingIncomeAccId && !isEditingCurrentMain) {
                                    setShowConfirm(true);
                                } else {
                                    setIsMainAccount(checked);
                                }
                            }}
                        />
                    </div>
                </FadeIn>

                <AlertDialog open={showConfirm} onOpenChange={setShowConfirm}>
                    <AlertDialogContent>
                        <AlertDialogHeader>
                            <AlertDialogTitle>Substituir conta principal?</AlertDialogTitle>
                            <AlertDialogDescription>
                                A conta <strong>{existingIncomeAcc?.bank_name}</strong> j├í est├í definida como principal.
                                Deseja que <strong>{bankName}</strong> passe a ser a padr├úo para o WhatsApp?
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel onClick={() => setIsMainAccount(false)}>Cancelar</AlertDialogCancel>
                            <AlertDialogAction onClick={() => {
                                setIsMainAccount(true);
                                setShowConfirm(false);
                            }}>
                                Sim, substituir
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>
            </main>

            <div className="fixed bottom-0 left-0 right-0 p-5 bg-background/95 backdrop-blur-sm border-t border-border">
                <Button
                    variant="warm"
                    size="lg"
                    className="w-full gap-2"
                    onClick={handleSave}
                    disabled={!canSave || updateAccount.isPending}
                >
                    {updateAccount.isPending ? (
                        <Loader2 className="w-5 h-5 animate-spin" />
                    ) : (
                        <Check className="w-5 h-5" />
                    )}
                    Salvar altera├º├Áes
                </Button>
            </div>
        </div>
    );
};

export default EditBankAccount;

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, CreditCard as CreditCardIcon, Check, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { useCreditCardById, useUpdateCreditCard } from "@/hooks/useCreditCards";
import { formatCurrencyInput, parseCurrency } from "@/lib/currency";
import { BANK_LIST, BRAND_LIST, detectBank } from "@/lib/cardBranding";
import { BankLogo } from "@/components/BankLogo";
import { useProfile, useUpdateProfile } from "@/hooks/useProfile";
import { Switch } from "@/components/ui/switch";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useCreditCards } from "@/hooks/useCreditCards";

export default function EditCreditCard() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { data: card, isLoading } = useCreditCardById(id);
    const updateCard = useUpdateCreditCard();
    const { data: profile } = useProfile();
    const updateProfile = useUpdateProfile();

    const [cardName, setCardName] = useState("");
    const [cardBrand, setCardBrand] = useState("");
    const [lastFour, setLastFour] = useState("");
    const [limit, setLimit] = useState("");
    const [closingDay, setClosingDay] = useState("");
    const [dueDay, setDueDay] = useState("");
    const [selectedBank, setSelectedBank] = useState<string | null>(null);
    const [isMainCard, setIsMainCard] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);

    const { data: cards = [] } = useCreditCards();

    // Find existing main card for confirmation
    const existingCardId = (profile as any)?.wa_default_expense_card_id;
    const existingCard = cards.find(c => c.id === existingCardId);
    const isEditingCurrentMain = existingCardId === id;

    useEffect(() => {
        if (card) {
            setCardName(card.card_name);
            setCardBrand(card.card_brand || "");
            setLastFour(card.last_four_digits || "");
            setLimit(card.credit_limit.toString());
            setClosingDay(card.closing_day.toString());
            setDueDay(card.due_day.toString());

            const bank = BANK_LIST.find(b => b.name === card.card_name || b.color === card.color);
            if (bank) setSelectedBank(bank.key);

            if (profile) {
                setIsMainCard((profile as any).wa_default_expense_card_id === card.id);
            }
        }
    }, [card, profile]);

    const bankTheme = selectedBank
        ? BANK_LIST.find(b => b.key === selectedBank)
        : detectBank(cardName);

    const cardColor = bankTheme?.color || card?.color || "#8B5CF6";
    const canSubmit = cardName.trim() && closingDay && dueDay;

    const handleSubmit = async () => {
        if (!canSubmit || !id) return;

        await updateCard.mutateAsync({
            id,
            card_name: cardName.trim(),
            card_brand: cardBrand.trim() || null,
            last_four_digits: lastFour.trim() || null,
            credit_limit: parseCurrency(limit),
            closing_day: parseInt(closingDay),
            due_day: parseInt(dueDay),
            color: cardColor,
        });

        if (isMainCard) {
            await updateProfile.mutateAsync({
                wa_default_expense_card_id: id
            } as any);
        } else {
            if ((profile as any).wa_default_expense_card_id === id) {
                await updateProfile.mutateAsync({
                    wa_default_expense_card_id: null
                } as any);
            }
        }

        navigate(`/cards/${id}`);
    };

    if (isLoading) {
        return (
            <div className="min-h-screen bg-background flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex flex-col">
            <header className="px-5 pt-safe-top">
                <div className="pt-4 pb-2 flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => navigate(`/cards/${id}`)}>
                        <ArrowLeft className="w-5 h-5" />
                    </Button>
                    <h1 className="font-serif text-xl font-semibold">Editar Cart├úo</h1>
                </div>
            </header>

            <main className="flex-1 px-5 py-6 space-y-5 overflow-y-auto pb-32">
                <FadeIn>
                    {/* Card Preview */}
                    <div
                        className="rounded-2xl p-5 text-white mb-6 shadow-lg relative overflow-hidden"
                        style={{ background: `linear-gradient(135deg, ${cardColor}, ${cardColor}cc)` }}
                    >
                        <div className="absolute top-4 right-4 opacity-20">
                            <CreditCardIcon className="w-16 h-16" />
                        </div>
                        <div className="relative z-10">
                            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center shadow-inner overflow-hidden border border-white/10 backdrop-blur-sm">
                                <BankLogo
                                    bankName={bankTheme?.name || "Cart├úo"}
                                    className="w-full h-full border-0 bg-transparent"
                                    iconClassName="text-white"
                                />
                            </div>
                            <p className="text-sm opacity-80 font-semibold tracking-tight uppercase">
                                {cardBrand || bankTheme?.name || "Cart├úo"}
                            </p>
                            <h3 className="text-xl font-bold mt-1">{cardName || "Nome do cart├úo"}</h3>
                            {lastFour && (
                                <p className="text-sm opacity-70 font-mono mt-3">ÔÇóÔÇóÔÇóÔÇó ÔÇóÔÇóÔÇóÔÇó ÔÇóÔÇóÔÇóÔÇó {lastFour}</p>
                            )}
                        </div>
                    </div>

                    {/* Form fields - Simplified for brevity but keeping essentials */}
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-sm text-muted-foreground">Nome do cart├úo *</label>
                            <Input
                                placeholder="Ex: Nubank"
                                value={cardName}
                                onChange={e => setCardName(e.target.value)}
                                maxLength={30}
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm text-muted-foreground">Limite total</label>
                            <Input
                                placeholder="5.000,00"
                                value={limit}
                                onChange={e => {
                                    const digits = e.target.value.replace(/[^\d]/g, "");
                                    setLimit(digits ? formatCurrencyInput(digits) : "");
                                }}
                                inputMode="numeric"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div className="space-y-2">
                                <label className="text-sm text-muted-foreground">Dia Fechamento *</label>
                                <Input
                                    value={closingDay}
                                    onChange={e => setClosingDay(e.target.value.replace(/\D/g, "").slice(0, 2))}
                                    inputMode="numeric"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm text-muted-foreground">Dia Vencimento *</label>
                                <Input
                                    value={dueDay}
                                    onChange={e => setDueDay(e.target.value.replace(/\D/g, "").slice(0, 2))}
                                    inputMode="numeric"
                                />
                            </div>
                        </div>

                        {/* Main card toggle */}
                        <div className="flex items-center justify-between p-4 rounded-xl bg-card border border-border shadow-soft mt-4">
                            <div>
                                <p className="text-sm font-medium">Definir como cart├úo principal</p>
                                <p className="text-xs text-muted-foreground">Usar para gastos via WhatsApp</p>
                            </div>
                            <Switch
                                checked={isMainCard}
                                onCheckedChange={(checked) => {
                                    if (checked && existingCardId && !isEditingCurrentMain) {
                                        setShowConfirm(true);
                                    } else {
                                        setIsMainCard(checked);
                                    }
                                }}
                            />
                        </div>
                    </div>
                </FadeIn>

                <AlertDialog open={showConfirm} onOpenChange={setShowConfirm}>
                    <AlertDialogContent>
                        <AlertDialogHeader>
                            <AlertDialogTitle>Substituir cart├úo principal?</AlertDialogTitle>
                            <AlertDialogDescription>
                                O cart├úo <strong>{existingCard?.card_name}</strong> j├í est├í definido como principal.
                                Deseja que <strong>{cardName}</strong> passe a ser o padr├úo para o WhatsApp?
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel onClick={() => setIsMainCard(false)}>Cancelar</AlertDialogCancel>
                            <AlertDialogAction onClick={() => {
                                setIsMainCard(true);
                                setShowConfirm(false);
                            }}>
                                Sim, substituir
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>
            </main>

            <div className="fixed bottom-0 left-0 right-0 p-5 bg-background/95 backdrop-blur-sm border-t border-border">
                <Button
                    variant="warm"
                    size="lg"
                    className="w-full gap-2"
                    onClick={handleSubmit}
                    disabled={!canSubmit || updateCard.isPending}
                >
                    {updateCard.isPending ? <Loader2 className="w-5 h-5 animate-spin" /> : <Check className="w-5 h-5" />}
                    Salvar altera├º├Áes
                </Button>
            </div>
        </div>
    );
}

import { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Edit2, Building2, Calendar, Smartphone, Trash2, Loader2 } from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useExpenseById, useDeleteExpense } from "@/hooks/useExpenses";
import { useCreditCardInstallmentById } from "@/hooks/useCreditCards";
import { DeleteExpenseDialog } from "@/components/expense/DeleteExpenseDialog";

const sourceLabels: Record<string, string> = {
  manual: "Registro manual",
  whatsapp: "Mensagem WhatsApp",
  integration: "Integra├º├úo",
};

export const ExpenseDetail = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const isCreditCard = id?.startsWith("cc-");

  // Hooks
  const { data: expense, isLoading: expenseLoading } = useExpenseById(isCreditCard ? undefined : id);
  const { data: installment, isLoading: ccLoading } = useCreditCardInstallmentById(isCreditCard ? id : undefined);

  const deleteExpense = useDeleteExpense();
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const isLoading = expenseLoading || ccLoading;

  // Normalize data for display
  const displayData = isCreditCard && installment ? {
    amount: installment.amount,
    description: installment.purchase.description,
    date: installment.purchase.purchase_date,
    created_at: installment.created_at,
    status: installment.status === 'paid' ? 'paid' : 'pending',
    source: "cartao",
    emotion: null, // Credit cards might not have this yet
    is_installment: true,
    installment_number: installment.installment_number,
    total_installments: installment.purchase.total_installments,
    card_name: installment.purchase.card.card_name,
  } : expense;

  const isFromIntegration = displayData?.source !== "manual";

  const formattedAmount = displayData
    ? new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(Number(displayData.amount))
    : "R$ 0,00";

  const handleDelete = async () => {
    if (!id) return;
    try {
      // TODO: Implement delete for credit card installment/purchase if needed
      // For now, we only support deleting regular expenses
      if (isCreditCard) {
        // Maybe show a toast that it's not supported yet or implement it
        console.log("Delete credit card expense not implemented yet");
        return;
      }

      await deleteExpense.mutateAsync({ id, softDelete: isFromIntegration });
      setShowDeleteDialog(false);
      navigate("/");
    } catch (error) {
      console.error("Error deleting expense:", error);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!displayData) {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center p-5">
        <span className="text-4xl mb-4">­ƒöì</span>
        <p className="text-muted-foreground mb-4">Gasto n├úo encontrado</p>
        <Button variant="ghost" onClick={() => navigate(-1)}>Voltar</Button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-2 flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate(-1)}>
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="font-serif text-xl font-semibold flex-1">Detalhe do Gasto</h1>
          {!isCreditCard && (
            <Button variant="ghost" size="icon" onClick={() => navigate(`/expenses/${id}/edit`)}>
              <Edit2 className="w-5 h-5" />
            </Button>
          )}
          {!isCreditCard && (
            <Button variant="ghost" size="icon" onClick={() => setShowDeleteDialog(true)} className="text-destructive hover:text-destructive">
              <Trash2 className="w-5 h-5" />
            </Button>
          )}
        </div>
      </header>

      <main className="flex-1 px-5 py-6">
        <FadeIn className="text-center mb-8">
          <p className="font-serif text-4xl font-semibold">{formattedAmount}</p>
