    });
  }, [ccInstallments]);

  // Merge all expenses
  const allItems = useMemo(() => {
    return [...expenses.map(transformExpense), ...cardExpenses]
      .sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
