            </div>
          </div>
          <Button variant="warm" size="icon" onClick={() => navigate("/expenses/add")}>
            <Plus className="w-5 h-5" />
          </Button>
        </div>
      </header>

      <main className="px-5 space-y-5">
        {/* Summary Card */}
