export const History = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const location = useLocation();
  const initialTypeFilter = (searchParams.get("type") as ItemTypeFilter) || "all";

  const { launch } = useSubscriptionAutoLauncher();

  // Accept selectedMonth from navigation state or default to current month
  const navState = location.state as { selectedMonth?: string } | null;
  const [selectedMonth, setSelectedMonth] = useState(() => {
    if (navState?.selectedMonth) return new Date(navState.selectedMonth);
    return new Date();
  });

  // Auto launch subscriptions on mount
  useEffect(() => {
    launch();
  }, []);

  const [periodFilter, setPeriodFilter] = useState<PeriodFilter>("month");
  const [sourceFilter, setSourceFilter] = useState<SourceFilter>("all");
  const [emotionFilter, setEmotionFilter] = useState<EmotionFilter>("all");
  const [typeFilter, setTypeFilter] = useState<ItemTypeFilter>(initialTypeFilter);

  const monthStart = startOfMonth(selectedMonth);
  const monthEnd = endOfMonth(selectedMonth);
  const currentMonth = selectedMonth.getMonth();
  const currentYear = selectedMonth.getFullYear();
  const monthLabel = format(selectedMonth, "MMMM yyyy", { locale: ptBR });
  const isCurrentMonth = format(selectedMonth, "yyyy-MM") === format(new Date(), "yyyy-MM");

  // Fetch real data from Supabase - Optimized with server-side filtering
  const { data: expenses = [], isLoading: expensesLoading } = useExpenses("all", currentMonth, currentYear);
  const { data: incomes = [], isLoading: incomesLoading } = useIncomes(currentMonth, currentYear);
  const { data: debts = [], isLoading: debtsLoading } = useDebts("active");
  const { data: receivables = [], isLoading: receivablesLoading } = useReceivables("all");
  const { data: ccInstallments = [], isLoading: ccLoading } = useCardInstallmentsByMonth(selectedMonth);
  const { data: subscriptions = [], isLoading: subsLoading } = useSubscriptions();

  const isLoading = expensesLoading || incomesLoading || debtsLoading || ccLoading || receivablesLoading || subsLoading;

  // Transform data to HistoryItem format ÔÇö filter by selectedMonth
  const historyItems = useMemo(() => {
    const items: HistoryItem[] = [];

    // Add expenses ÔÇö server already filtered mostly, but getExpensesForMonth handles recurring logic
    const filteredExpenses = getExpensesForMonth(expenses, selectedMonth);
    filteredExpenses.forEach((expense: ExpenseRow) => {
      // Skip auto-generated loan expenses (they're internal accounting, user sees the receivable instead)
      if (expense.description?.startsWith("Empr├®stimo concedido:")) return;

      const expDate = expense.date ? parseLocalDate(expense.date) : new Date(expense.created_at);
      const installmentLabel = expense.is_installment && expense.total_installments && expense.total_installments > 1
        ? ` (${expense.installment_number}/${expense.total_installments}x)`
        : "";

      const isSub = expense.description?.startsWith("Assinatura: ");

      items.push({
        id: expense.id,
        type: isSub ? "subscription" : "expense",
        amount: Number(expense.amount),
        description: `${expense.description}${installmentLabel}`,
        category: expense.emotion as EmotionCategory | undefined,
        source: expense.source as HistoryItem["source"],
        pending: expense.status === "pending",
        createdAt: expDate,
        accountName: (expense as any).bank_accounts?.name || (expense as any).bank_accounts?.bank_name,
      });
    });

    // Add incomes ÔÇö filter by month (including recurring)
    incomes.forEach((income: IncomeRow) => {
      const incomeDate = income.date ? parseLocalDate(income.date) : new Date(income.created_at);
      const isRecurring = income.is_recurring;
      if (isRecurring === true) {
        if (isBefore(monthStart, startOfMonth(incomeDate))) return;
      } else {
        if (!isWithinInterval(incomeDate, { start: monthStart, end: monthEnd })) return;
      }
      items.push({
        id: income.id,
        type: "income",
        amount: Number(income.amount),
        description: income.description,
        incomeType: income.type,
        source: "manual" as const,
        pending: false,
        createdAt: isRecurring
          ? new Date(selectedMonth.getFullYear(), selectedMonth.getMonth(), incomeDate.getDate())
          : incomeDate,
        accountName: (income as any).bank_account?.name || (income as any).bank_account?.bank_name,
      });
    });

    // Add receivables (Loans)
    receivables.forEach((receivable) => {
      const dueDate = receivable.due_date ? parseLocalDate(receivable.due_date) : new Date(receivable.created_at);
      // Filter by due date corresponding to the selected month (or creation date if no due date)
      if (!isWithinInterval(dueDate, { start: monthStart, end: monthEnd })) return;

      items.push({
        id: receivable.id,
        type: "receivable",
        amount: Number(receivable.amount),
        description: `${receivable.debtor_name}${receivable.description ? ` ┬À ${receivable.description}` : ""}`,
        source: "manual" as const,
        pending: receivable.status === "pending",
        createdAt: new Date(receivable.created_at), // Original creation date for sorting? Or due date? Keep creation for now.
        accountName: (receivable as any).bank_account?.name || (receivable as any).bank_account?.bank_name, // Typically destination account
      });
    });

    // Add active debts
    debts.forEach((debt: DebtRow) => {
      const debtDate = new Date(debt.created_at);
      if (!isWithinInterval(debtDate, { start: monthStart, end: monthEnd }) && !isBefore(debtDate, monthStart)) return;
      items.push({
        id: debt.id,
        type: "debt",
        amount: Number(debt.installment_amount || debt.total_amount),
        description: `${debt.creditor_name} - ${debt.current_installment || 0}/${debt.total_installments || 1}`,
        source: "manual" as const,
        pending: false,
        createdAt: debtDate,
      });
    });

    // Add credit card installments (already filtered by selectedMonth via hook)
    ccInstallments.forEach((inst: any) => {
      const purchase = inst.purchase;
      const card = purchase?.card;
      const refMonth = inst.reference_month
        ? format(parseLocalDate(inst.reference_month), "MMM/yy", { locale: ptBR })
        : undefined;

      const isSub = purchase?.description?.startsWith("Assinatura: ");

      items.push({
        id: inst.id,
        type: isSub ? "subscription" : "credit_card",
        amount: Number(inst.amount),
        description: purchase?.description || "Compra no cart├úo",
        cardName: card?.card_name,
        invoiceMonth: refMonth,
        source: "manual" as const,
        pending: inst.status === "open",
        createdAt: purchase?.purchase_date ? parseLocalDate(purchase.purchase_date) : new Date(inst.created_at),
      });
    });

    // Add projected subscriptions
    subscriptions.forEach(sub => {
      if (sub.status !== 'active') return;

      // Only show if subscription was already created by this month
      const subCreatedAt = new Date(sub.created_at);
      if (isAfter(startOfMonth(subCreatedAt), monthEnd)) return;

      const hasExecuted = items.some(item =>
        (item.type === "subscription" || item.type === "expense" || item.type === "credit_card") &&
        item.description.toLowerCase().includes(sub.name.toLowerCase())
      );

      if (!hasExecuted) {
        items.push({
          id: `proj-${sub.id}`,
          type: "subscription",
          amount: Number(sub.amount),
          description: `Assinatura: ${sub.name}`,
          source: "manual",
          pending: true,
          createdAt: new Date(selectedMonth.getFullYear(), selectedMonth.getMonth(), sub.billing_date || 1),
          accountName: "Previsto",
        });
      }
    });

    return items;
  }, [expenses, incomes, debts, receivables, ccInstallments, subscriptions, monthStart, monthEnd, selectedMonth, isCurrentMonth]);

  const handleItemClick = (item: HistoryItem) => {
    if (item.type === "income") {
      navigate(`/income/${item.id}`);
    } else if (item.type === "debt") {
      navigate(`/debts/${item.id}`);
    } else if (item.type === "receivable") {
      navigate(`/receivables/${item.id}`);
    } else if (item.type === "credit_card") {
      navigate(`/expenses/cc-${item.id}`);
    } else if (item.pending || !item.category) {
      navigate(`/confirm/${item.id}`);
    } else {
      navigate(`/expenses/${item.id}`, { state: { item } });
    }
  };

  const resetFilters = () => {
    setPeriodFilter("month");
    setSourceFilter("all");
    setEmotionFilter("all");
    setTypeFilter("all");
  };

  // Apply filters
  const filteredItems = historyItems.filter((item) => {
    // Type filter
    if (typeFilter !== "all") {
      if (typeFilter === "expense" && item.type !== "expense" && item.type !== "credit_card" && item.type !== "subscription") return false;
      if (typeFilter === "income" && item.type !== "income") return false;
      if (typeFilter === "debt" && item.type !== "debt") return false;
      if (typeFilter === "receivable" && item.type !== "receivable") return false;
    }
    // Source filter
    if (sourceFilter !== "all") {
      const sourceMap: Record<string, string> = {
        manual: "manual",
        bank: "integration",
        whatsapp: "whatsapp",
        photo: "manual",
        audio: "manual",
      };
      if (item.source !== sourceMap[sourceFilter]) return false;
    }
    // Emotion filter (only for expenses)
    if (emotionFilter !== "all" && item.type === "expense") {
      const emotionMap: Record<string, string> = {
        essential: "essencial",
        obligation: "pilar",
        pleasure: "essencial",
        impulse: "impulso",
      };
      const mappedEmotion = emotionMap[emotionFilter] || emotionFilter;
      if (item.category !== mappedEmotion) return false;
    }
    // Period filter
    if (periodFilter === "week") {
      const weekAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
      if (item.createdAt.getTime() < weekAgo) return false;
    }
    return true;
  });

  // Sort by date (newest first)
  const sortedItems = [...filteredItems].sort(
    (a, b) => b.createdAt.getTime() - a.createdAt.getTime()
  );

  // Group by period
  const groupedItems = groupByPeriod(sortedItems, selectedMonth);

  // Calculate totals

  const totalExpenses = filteredItems
    .filter((i) => i.type === "expense")
    .reduce((acc, e) => acc + e.amount, 0);
  const totalIncome = filteredItems
    .filter((i) => i.type === "income")
    .reduce((acc, e) => acc + e.amount, 0);
  const totalDebt = filteredItems
    .filter((i) => i.type === "debt")
    .reduce((acc, e) => acc + e.amount, 0);
  const totalCreditCard = filteredItems
    .filter((i) => i.type === "credit_card")
    .reduce((acc, e) => acc + e.amount, 0);
  const totalReceivables = filteredItems
    .filter((i) => i.type === "receivable")
    .reduce((acc, e) => acc + e.amount, 0);
  const activeSubsAmount = subscriptions
    .filter(s => s.status === 'active')
    .reduce((sum, s) => sum + Number(s.amount), 0);

  const totalSubscriptions = (isCurrentMonth || isAfter(monthStart, startOfMonth(new Date())))
    ? activeSubsAmount
    : filteredItems
      .filter((i) => i.type === "subscription")
      .reduce((acc, e) => acc + e.amount, 0);

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("pt-BR", {
      style: "currency",
      currency: "BRL",
    }).format(value);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center pb-24">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
        <BottomNav />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-24">
      {/* Header */}
      <header className="px-5 pt-safe-top sticky top-0 bg-background/95 backdrop-blur-sm z-10">
        <div className="pt-4 pb-2 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Button variant="ghost" size="icon" onClick={() => navigate("/")} className="-ml-2">
              <ChevronLeft className="w-5 h-5" />
            </Button>
            <h1 className="font-serif text-xl font-semibold">Hist├│rico</h1>
          </div>
          <FilterSheet
            periodFilter={periodFilter}
            sourceFilter={sourceFilter}
            emotionFilter={emotionFilter}
            typeFilter={typeFilter}
            onPeriodChange={setPeriodFilter}
            onSourceChange={setSourceFilter}
            onEmotionChange={setEmotionFilter}
            onTypeChange={setTypeFilter}
            onReset={resetFilters}
          />
        </div>
        {/* Month selector */}
        <div className="flex items-center justify-between py-2">
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setSelectedMonth(prev => subMonths(prev, 1))}>
            <ChevronLeft className="w-5 h-5" />
          </Button>
          <div className="flex items-center gap-2">
            <Calendar className="w-4 h-4 text-muted-foreground" />
            <span className="font-medium capitalize text-sm">{monthLabel}</span>
            {isCurrentMonth && (
              <span className="text-[10px] px-1.5 py-0.5 rounded bg-primary/10 text-primary font-medium">Atual</span>
            )}
          </div>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setSelectedMonth(prev => addMonths(prev, 1))}>
            <ChevronRight className="w-5 h-5" />
          </Button>
        </div>
      </header>

      <main className="px-5">
        {/* Compact Summary */}
        <FadeIn className="mb-4">
          <div className="grid grid-cols-2 gap-2">
            <div className="p-3 rounded-xl bg-card border border-border shadow-soft">
              <p className="text-xs text-muted-foreground whitespace-nowrap">Total de Gastos</p>
              <p className="font-semibold text-sm">{formatCurrency(totalExpenses + totalCreditCard + totalSubscriptions)}</p>
            </div>
            <div className="p-3 rounded-xl bg-essential/5 border border-essential/20 shadow-soft">
              <p className="text-xs text-muted-foreground whitespace-nowrap">Receitas</p>
              <p className="font-semibold text-sm text-essential">{formatCurrency(totalIncome)}</p>
            </div>
            <div className="p-3 rounded-xl bg-impulse/5 border border-impulse/20 shadow-soft">
              <p className="text-xs text-muted-foreground whitespace-nowrap">D├¡vidas</p>
              <p className="font-semibold text-sm text-impulse">{formatCurrency(totalDebt)}</p>
            </div>
            {totalReceivables > 0 && (
              <div className="p-3 rounded-xl bg-essential/5 border border-essential/20 shadow-soft flex flex-col justify-center">
                <p className="text-[10px] text-muted-foreground whitespace-nowrap uppercase tracking-wider mb-0.5">A receber</p>
                <p className="font-semibold text-sm text-essential truncate">{formatCurrency(totalReceivables)}</p>
              </div>
            )}
            <div className="p-3 rounded-xl bg-obligation/5 border border-obligation/20 shadow-soft">
              <p className="text-xs text-muted-foreground whitespace-nowrap">Cart├úo</p>
              <p className="font-semibold text-sm text-obligation">{formatCurrency(totalCreditCard)}</p>
            </div>
            <div className="p-3 rounded-xl bg-primary/5 border border-primary/20 shadow-soft">
              <p className="text-xs text-muted-foreground whitespace-nowrap">Assinaturas</p>
              <p className="font-semibold text-sm text-primary">{formatCurrency(totalSubscriptions)}</p>
            </div>
          </div>
        </FadeIn>

        {/* Grouped List */}
        {groupedItems.length > 0 ? (
          groupedItems.map((group, groupIndex) => (
            <FadeIn key={group.label} delay={0.05 * groupIndex} className="mb-4">
              <h3 className="text-xs font-medium text-muted-foreground uppercase tracking-wide mb-2">
                {group.label}
              </h3>
              <div className="space-y-2">
                {group.items.map((item, itemIndex) => (
                  <motion.div
                    key={item.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: itemIndex * 0.03 }}
                  >
                    <HistoryItemCard
                      item={item}
                      onClick={() => handleItemClick(item)}
                    />
                  </motion.div>
                ))}
              </div>
            </FadeIn>
          ))
        ) : (
          <FadeIn className="text-center py-12">
            <p className="text-muted-foreground">
              Nenhum registro encontrado.
            </p>
          </FadeIn>
        )}
      </main>

      <BottomNav />
    </div>
  );
};

export default History;

import { useState, useMemo, useEffect } from "react";
import { parseLocalDate } from "@/lib/dateUtils";
import { useNavigate } from "react-router-dom";
import { useSubscriptionAutoLauncher } from "@/hooks/useSubscriptions";
import { Button } from "@/components/ui/button";
import { FadeIn, PageTransition } from "@/components/ui/motion";
import {
  TrendingDown,
  TrendingUp,
  ChevronLeft,
  ChevronRight,
  Loader2,
  Calendar,
  Wallet,
} from "lucide-react";
import { useProfile } from "@/hooks/useProfile";
import { useExpenses } from "@/hooks/useExpenses";
import { useDebts } from "@/hooks/useDebts";
import { useReceivables } from "@/hooks/useReceivables";
import { useIncomes } from "@/hooks/useIncomes";
import { useGoals, useGoalStats } from "@/hooks/useGoals";
import { useSubscriptions } from "@/hooks/useSubscriptions";
import { useCreditCards, useCardInstallmentsByMonth } from "@/hooks/useCreditCards";
import { calculateBalances } from "@/lib/balanceCalculations";
import { getExpensesForMonth } from "@/lib/recurringExpenses";
import { format, startOfMonth, endOfMonth, subMonths, addMonths, isWithinInterval, isBefore, isAfter } from "date-fns";
import { ptBR } from "date-fns/locale";

// Layout & Components
import { AppLayout } from "@/components/layout/AppLayout";
import { BalanceHero } from "@/components/home/BalanceHero";
import { MonthlyResult } from "@/components/home/MonthlyResult";
import { AlertsSection } from "@/components/home/AlertsSection";
import { CreditCardsCarousel } from "@/components/home/CreditCardsCarousel";
import { TransactionsSection } from "@/components/home/TransactionsSection";
import { GoalsSummary } from "@/components/home/GoalsSummary";
import { BankAccountsSummary } from "@/components/home/BankAccountsSummary";
import { CryptoSummary } from "@/components/home/CryptoSummary";

// Hooks
import { useUserPreferences } from "@/hooks/useUserPreferences";
import { useBankAccounts } from "@/hooks/useBankAccounts";
import { useCryptoTotalValue, useCryptoInvestedInMonth } from "@/hooks/useCryptoWallets";

export default function Home() {
  const navigate = useNavigate();
  const { launch } = useSubscriptionAutoLauncher();
  const [selectedMonth, setSelectedMonth] = useState(new Date());

  // Auto launch subscriptions on mount
  useEffect(() => {
    launch();
  }, []);

  const { preferences } = useUserPreferences();

  // Fetch data
  const currentMonthArg = selectedMonth.getMonth();
  const currentYearArg = selectedMonth.getFullYear();

  const { data: profile, isLoading: profileLoading } = useProfile();
  const { data: expenses = [], isLoading: expenseLoading } = useExpenses("all", currentMonthArg, currentYearArg);
  const { data: debts = [], isLoading: debtLoading } = useDebts("active");
  const { data: receivables = [], isLoading: receivableLoading } = useReceivables("pending");
  const { data: incomes = [], isLoading: incomeLoading } = useIncomes(currentMonthArg, currentYearArg);
  const { data: goalStats, isLoading: goalLoading } = useGoalStats();
  const { data: goals = [] } = useGoals("all");
  const { data: creditCards = [] } = useCreditCards();
  const { data: ccInstallments = [] } = useCardInstallmentsByMonth(selectedMonth);
  const { data: bankAccounts = [] } = useBankAccounts();
  const { totalValue: cryptoTotal } = useCryptoTotalValue();
  const { data: cryptoInvested = 0 } = useCryptoInvestedInMonth(currentMonthArg, currentYearArg);
  const { data: subscriptions = [] } = useSubscriptions();

  const activeSubs = useMemo(() => subscriptions.filter(s => s.status === 'active'), [subscriptions]);

  const isLoading = profileLoading || expenseLoading || debtLoading || receivableLoading || incomeLoading || goalLoading;

  const monthStart = startOfMonth(selectedMonth);
  const monthEnd = endOfMonth(selectedMonth);

  const filteredExpenses = useMemo(() => {
    return getExpensesForMonth(expenses, selectedMonth);
  }, [expenses, selectedMonth]);

  const filteredIncomes = useMemo(() => {
    return incomes.filter(income => {
      const incomeDate = income.date ? parseLocalDate(income.date) : new Date(income.created_at);
      if (income.is_recurring === true) {
        return !isBefore(monthStart, startOfMonth(incomeDate));
      }
      return isWithinInterval(incomeDate, { start: monthStart, end: monthEnd });
    });
  }, [incomes, monthStart, monthEnd]);

  const filteredReceivables = useMemo(() => {
    return receivables.filter(r => {
      // Just showing pending ones as "active" receivables
      return r.status === "pending";
    });
  }, [receivables]);

  const filteredDebts = useMemo(() => {
    return debts.filter(debt => {
      const debtStart = new Date(debt.created_at);
      if (isAfter(debtStart, monthEnd)) return false;
      if (debt.is_installment && debt.total_installments) {
        const monthsFromStart = Math.floor(
          (monthStart.getTime() - debtStart.getTime()) / (30 * 24 * 60 * 60 * 1000)
        );
        return monthsFromStart < debt.total_installments;
      }
      return true;
    });
  }, [debts, monthStart, monthEnd]);

  const totalSpent = useMemo(() => filteredExpenses.reduce((sum, e) => sum + Number(e.amount), 0), [filteredExpenses]);
  const totalIncome = useMemo(() => filteredIncomes.reduce((sum, i) => sum + Number(i.amount), 0), [filteredIncomes]);
  const totalCCInstallments = useMemo(() => ccInstallments.reduce((sum, inst) => sum + Number(inst.amount), 0), [ccInstallments]);
  const bankTotal = useMemo(() => bankAccounts.reduce((sum, acc) => sum + Number(acc.current_balance), 0), [bankAccounts]);

  const balanceBreakdown = useMemo(() => calculateBalances(
    filteredIncomes,
    filteredExpenses,
    filteredDebts,
    selectedMonth,
    subscriptions,
    goalStats?.totalSaved || 0,
    totalCCInstallments,
    bankTotal
  ), [filteredIncomes, filteredExpenses, filteredDebts, selectedMonth, subscriptions, goalStats?.totalSaved, totalCCInstallments, bankTotal]);

  const monthLabel = format(selectedMonth, "MMMM yyyy", { locale: ptBR });
  const isCurrentMonth = format(selectedMonth, "yyyy-MM") === format(new Date(), "yyyy-MM");

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const hasData = totalIncome > 0 || totalSpent > 0 || totalCCInstallments > 0 || bankAccounts.length > 0;

  return (
    <AppLayout>
      <PageTransition className="pb-24">
        {/* Month Selector Bar - Compact */}
        <div className="px-4 py-2 flex flex-col md:flex-row md:items-center justify-between relative lg:sticky lg:top-0 bg-background/95 backdrop-blur-sm z-10 border-b border-border/50 lg:border-none gap-2 shadow-sm">
          {/* Greeting / Title - Desktop Only */}
          <div className="hidden lg:block">
            <h1 className="font-serif text-2xl font-semibold">Vis├úo Geral</h1>
            <p className="text-sm text-muted-foreground">Resumo financeiro do m├¬s.</p>
          </div>

          {/* Date Picker - Centered & Compact */}
          <div className="flex items-center justify-center gap-1 bg-secondary/50 p-1 rounded-xl border border-border/50 w-full md:w-fit mx-auto lg:mx-0 max-w-[280px]">
            <Button variant="ghost" size="icon" className="h-7 w-7 rounded-lg" onClick={() => setSelectedMonth(prev => subMonths(prev, 1))}>
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <button
              onClick={() => setSelectedMonth(new Date())}
              className="flex items-center gap-2 px-3 py-1 rounded-lg hover:bg-background transition-all active:scale-95 flex-1 justify-center"
            >
              <Calendar className="w-3.5 h-3.5 text-primary" />
              <span className="font-bold capitalize text-sm tracking-tight" data-testid="month-label">{monthLabel}</span>
            </button>
            <Button variant="ghost" size="icon" className="h-7 w-7 rounded-lg" onClick={() => setSelectedMonth(prev => addMonths(prev, 1))}>
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>

        <div className="px-5 space-y-8 pt-4">
          {hasData ? (
            <>
              {/* 1. Hero Balance */}
              <FadeIn>
                <BalanceHero
                  balance={balanceBreakdown}
                  cryptoTotal={preferences.cryptoEnabled ? cryptoTotal : 0}
                  cryptoEnabled={preferences.cryptoEnabled}
                />
              </FadeIn>

              {/* 2. Monthly Summary (Income vs Expense) - High Priority */}
              <FadeIn delay={0.05}>
                <MonthlyResult
                  totalIncome={totalIncome}
                  totalSpent={totalSpent + totalCCInstallments}
                  investedAmount={cryptoInvested}
                  subscriptionsAmount={activeSubs.reduce((sum, s) => sum + Number(s.amount), 0)}
                />
              </FadeIn>

              {/* 3. Critical Alerts */}
              <FadeIn delay={0.1}>
                <AlertsSection
                  debts={filteredDebts}
                  goals={goals}
                  creditCards={creditCards}
                  installments={ccInstallments}
                  subscriptions={activeSubs}
                  selectedMonth={selectedMonth}
                />
              </FadeIn>

              {/* 4. Credit Cards Carousel (New Highlight) */}
              {creditCards.length > 0 && (
                <FadeIn delay={0.15} className="bg-gradient-to-br from-secondary/30 to-background p-4 -mx-4 sm:mx-0 sm:rounded-3xl border-y sm:border border-border/50">
                  <div className="flex items-center justify-between px-1 mb-3">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-full bg-obligation/10 flex items-center justify-center">
                        <Wallet className="w-4 h-4 text-obligation" />
                      </div>
                      <h3 className="text-sm font-semibold text-foreground uppercase tracking-wider">Meus Cart├Áes</h3>
                    </div>
                    <button onClick={() => navigate("/cards")} className="text-xs text-primary font-medium hover:underline">Gerenciar</button>
                  </div>
                  <CreditCardsCarousel
                    cards={creditCards}
                    installments={ccInstallments}
                    selectedMonth={selectedMonth}
                  />
                </FadeIn>
              )}

              {/* 5. Bank Accounts & Crypto */}
              <FadeIn delay={0.2} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <BankAccountsSummary />
                {preferences.cryptoEnabled && <CryptoSummary />}
              </FadeIn>

              {/* 6. Goals */}
              <FadeIn delay={0.25}>
                <GoalsSummary
                  goals={goals}
                  totalSaved={goalStats?.totalSaved || 0}
                  totalTarget={goalStats?.totalTarget || 0}
                />
              </FadeIn>

              {/* 7. Recent Transactions */}
              <FadeIn delay={0.3}>
                <TransactionsSection
                  expenses={filteredExpenses}
                  incomes={filteredIncomes}
                  debts={filteredDebts}
                  receivables={filteredReceivables}
                  creditCardInstallments={ccInstallments}
                  subscriptions={subscriptions}
                  selectedMonth={selectedMonth}
                />
              </FadeIn>
            </>
          ) : (
            <FadeIn delay={0.1} className="flex flex-col items-center justify-center py-12 px-4 text-center">
              {/* Onboarding Empty State */}
              <div className="w-24 h-24 rounded-full bg-primary/10 flex items-center justify-center mb-6 shadow-soft animate-pulse">
                <Wallet className="w-10 h-10 text-primary" />
              </div>
              <h3 className="font-serif text-2xl font-bold mb-3 text-foreground">Sua liberdade come├ºa aqui</h3>
              <p className="text-sm text-muted-foreground max-w-[280px] mb-8 leading-relaxed mx-auto">
                Para o Saldin funcionar, precisamos saber onde seu dinheiro est├í.
              </p>

              <div className="flex flex-col gap-3 w-full max-w-sm">
                <Button
                  size="lg"
                  className="w-full h-14 text-base shadow-medium rounded-xl gap-2"
                  onClick={() => navigate("/banks/add")}
                >
                  <Wallet className="w-5 h-5" />
                  Configurar conta banc├íria
                </Button>

                <div className="relative py-2">
                  <div className="absolute inset-0 flex items-center">
                    <span className="w-full border-t border-border" />
                  </div>
                  <div className="relative flex justify-center text-xs uppercase">
                    <span className="bg-background px-2 text-muted-foreground">Ou comece lan├ºando</span>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <Button variant="outline" className="h-12 rounded-xl border-dashed" onClick={() => navigate("/income/add")}>
                    <TrendingUp className="w-4 h-4 mr-2 text-essential" />
                    Receita
                  </Button>
                  <Button variant="outline" className="h-12 rounded-xl border-dashed" onClick={() => navigate("/expenses/add")}>
                    <TrendingDown className="w-4 h-4 mr-2 text-impulse" />
                    Gasto
                  </Button>
                </div>
              </div>
            </FadeIn>
          )}
        </div>
      </PageTransition>
    </AppLayout >
  );
}

import { useState, useCallback, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Upload, FileText, Check, Loader2, AlertCircle, X, Tag, CreditCard, Package, RefreshCw } from "lucide-react";
import { cn } from "@/lib/utils";
import { useCreditCards, useCreateCreditCardPurchase } from "@/hooks/useCreditCards";
import { useAllCategories } from "@/hooks/useCategories";
import { formatCurrency } from "@/lib/balanceCalculations";
import { toast } from "sonner";
import { motion, AnimatePresence } from "framer-motion";
import { parseStatementFile, type ParsedTransaction, type ParseResult } from "@/lib/statementParser";

type Step = "upload" | "parsing" | "review" | "importing" | "done";

export default function ImportStatement() {
  const navigate = useNavigate();
  const location = useLocation();
  const fromOnboarding = (location.state as any)?.fromOnboarding === true;
  const preselectedCardId = (location.state as any)?.preselectedCardId as string | undefined;
  const { data: cards = [] } = useCreditCards();
  const createPurchase = useCreateCreditCardPurchase();
  const { allCategories } = useAllCategories();

  const [step, setStep] = useState<Step>("upload");
  const [parseResult, setParseResult] = useState<ParseResult | null>(null);
  const [transactions, setTransactions] = useState<ParsedTransaction[]>([]);
  const [selectedCardId, setSelectedCardId] = useState<string>(preselectedCardId || "");
  const [categorizingIndex, setCategorizingIndex] = useState<number | null>(null);
  const [importProgress, setImportProgress] = useState(0);
  const [importedCount, setImportedCount] = useState(0);

  // Auto-select the preselected card or the only available card
  useEffect(() => {
    if (selectedCardId) return;
    if (preselectedCardId) {
      setSelectedCardId(preselectedCardId);
    } else if (cards.length === 1) {
      setSelectedCardId(cards[0].id);
    }
  }, [cards, preselectedCardId, selectedCardId]);

  const handleFileChange = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const ext = file.name.split(".").pop()?.toLowerCase();
    if (ext !== "csv" && ext !== "pdf") {
      toast.error("Formato n├úo suportado. Use arquivos CSV ou PDF.");
      return;
    }

    setStep("parsing");

    try {
      const result = await parseStatementFile(file);

      if (result.transactions.length === 0) {
        toast.error(result.warnings[0] || "Nenhuma transa├º├úo encontrada no arquivo.");
        setStep("upload");
        return;
      }

      setParseResult(result);
      setTransactions(result.transactions);
      setStep("review");
      toast.success(`${result.transactions.length} lan├ºamentos encontrados!`);

      if (result.warnings.length > 0) {
        result.warnings.forEach(w => toast.warning(w, { duration: 5000 }));
      }
    } catch (err) {
      console.error("Parse error:", err);
      toast.error("Erro ao processar o arquivo. Tente novamente.");
      setStep("upload");
    }
  }, []);

  const handleStartImport = async () => {
    if (!selectedCardId) {
      toast.error("Selecione um cart├úo.");
      return;
    }

    const toImport = transactions.filter(t => t.selected && t.type === "purchase");
    if (toImport.length === 0) {
      toast.error("Nenhum lan├ºamento selecionado para importa├º├úo.");
      return;
    }

    setStep("importing");
    let imported = 0;

    for (const tx of toImport) {
      try {
        // If it's an installment and we have info, use totalInstallments
        const installments = tx.isInstallment && tx.totalInstallments
          ? tx.totalInstallments
          : 1;

        // For installment purchases, calculate total amount
        const totalAmount = tx.isInstallment && tx.totalInstallments
          ? tx.amount * tx.totalInstallments
          : tx.amount;

        await createPurchase.mutateAsync({
          card_id: selectedCardId,
          description: tx.description,
          total_amount: totalAmount,
          total_installments: installments,
          purchase_date: tx.date,
          category_id: tx.categoryId,
        });
        imported++;
        setImportProgress(Math.round((imported / toImport.length) * 100));
      } catch (err) {
        console.error("Error importing:", tx.description, err);
      }
    }

    setImportedCount(imported);
    setStep("done");
    toast.success(`${imported} de ${toImport.length} lan├ºamentos importados!`);
  };

  const toggleLine = (idx: number) => {
    setTransactions(prev => prev.map((t, i) => i === idx ? { ...t, selected: !t.selected } : t));
  };

  const removeLine = (idx: number) => {
    setTransactions(prev => prev.filter((_, i) => i !== idx));
  };

  const setCategory = (idx: number, catId: string) => {
    setTransactions(prev => prev.map((t, i) => i === idx ? { ...t, categoryId: catId } : t));
    setCategorizingIndex(null);
  };

  const selectedTxs = transactions.filter(t => t.selected && t.type === "purchase");
  const totalSelected = selectedTxs.reduce((s, t) => s + t.amount, 0);
  const selectedCount = selectedTxs.length;
  const uncategorizedCount = selectedTxs.filter(t => !t.categoryId).length;
  const installmentCount = selectedTxs.filter(t => t.isInstallment).length;

  const stepDescription = {
    upload: "Envie o PDF ou CSV da fatura",
    parsing: "Processando arquivo...",
    review: `${transactions.length} lan├ºamentos encontrados`,
    importing: "Importando...",
    done: "Importa├º├úo conclu├¡da!",
  };

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-2 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => {
              if (step === "upload" || step === "done") navigate("/");
              else setStep("upload");
            }}>
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <div>
              <h1 className="font-serif text-xl font-semibold">Importar Fatura</h1>
              <p className="text-xs text-muted-foreground">{stepDescription[step]}</p>
            </div>
          </div>
          <Button variant="ghost" size="sm" className="text-muted-foreground" onClick={() => navigate("/", { replace: true })}>
            Cancelar
          </Button>
        </div>
      </header>

      <main className="flex-1 px-5 py-6 overflow-y-auto pb-32">
        {/* Step: Upload */}
        {step === "upload" && (
          <FadeIn className="space-y-6">
            {cards.length === 0 ? (
              <div className="text-center py-12 space-y-4">
                <div className="w-20 h-20 rounded-full bg-destructive/10 mx-auto flex items-center justify-center">
                  <CreditCard className="w-10 h-10 text-destructive" />
                </div>
                <h2 className="font-serif text-lg font-semibold">Nenhum cart├úo cadastrado</h2>
                <p className="text-sm text-muted-foreground max-w-xs mx-auto">
                  Para importar uma fatura, primeiro cadastre o cart├úo de cr├®dito correspondente.
                </p>
                <Button variant="warm" onClick={() => navigate("/cards/add")}>
                  <CreditCard className="w-4 h-4 mr-2" />
                  Cadastrar cart├úo
                </Button>
              </div>
            ) : (
              <>
                <div className="text-center py-8">
                  <div className="w-20 h-20 rounded-full bg-primary/10 mx-auto mb-4 flex items-center justify-center">
                    <Upload className="w-10 h-10 text-primary" />
                  </div>
                  <h2 className="font-serif text-lg font-semibold mb-2">Envie a fatura do cart├úo</h2>
                  <p className="text-sm text-muted-foreground max-w-xs mx-auto">
                    Aceita PDF ou CSV de qualquer banco. Os lan├ºamentos ser├úo lidos, validados e categorizados automaticamente.
                  </p>
                </div>

                <label className="block cursor-pointer">
                  <div className="border-2 border-dashed border-border rounded-2xl p-8 text-center hover:border-primary/50 transition-colors">
                    <FileText className="w-8 h-8 text-muted-foreground mx-auto mb-3" />
                    <p className="font-medium text-sm">Clique para selecionar arquivo</p>
                    <p className="text-xs text-muted-foreground mt-1">PDF ou CSV</p>
                  </div>
                  <input
                    type="file"
                    accept=".csv,.pdf"
                    className="hidden"
                    onChange={handleFileChange}
                  />
                </label>

                <div className="bg-muted/50 rounded-xl p-4 space-y-2">
                  <p className="text-xs font-medium text-muted-foreground">Bancos suportados:</p>
                  <p className="text-xs text-muted-foreground">
                    Nubank, Ita├║, Bradesco, Santander, Inter, Banco do Brasil, Caixa, C6 Bank e outros.
                  </p>
                  <p className="text-xs font-medium text-muted-foreground mt-3">Como obter o arquivo:</p>
                  <ul className="text-xs text-muted-foreground space-y-1">
                    <li>ÔÇó No app do banco, acesse a fatura do cart├úo</li>
                    <li>ÔÇó Procure "Exportar", "Baixar" ou "Compartilhar"</li>
                    <li>ÔÇó Selecione PDF ou CSV e envie aqui</li>
                  </ul>
                </div>
              </>
            )}
          </FadeIn>
        )}

        {/* Step: Parsing */}
        {step === "parsing" && (
          <FadeIn className="text-center py-16 space-y-4">
            <Loader2 className="w-12 h-12 animate-spin text-primary mx-auto" />
            <h2 className="font-serif text-lg font-semibold">Processando fatura...</h2>
            <p className="text-sm text-muted-foreground">Identificando transa├º├Áes, removendo ru├¡do e detectando parcelas.</p>
          </FadeIn>
        )}

        {/* Step: Review */}
        {step === "review" && (
          <FadeIn className="space-y-4">
            {/* Card selector */}
            <div className="space-y-2">
              <label className="text-sm font-medium flex items-center gap-2">
                <CreditCard className="w-4 h-4" />
                Cart├úo de destino:
              </label>
              {cards.length === 0 ? (
                <div className="p-3 rounded-xl bg-destructive/10 border border-destructive/20">
                  <p className="text-sm text-destructive">Nenhum cart├úo cadastrado.</p>
                  <Button variant="outline" size="sm" className="mt-2" onClick={() => navigate("/cards/add")}>
                    Cadastrar cart├úo
                  </Button>
                </div>
              ) : (
                <div className="flex gap-2 flex-wrap">
                  {cards.map(card => (
                    <button
                      key={card.id}
                      onClick={() => setSelectedCardId(card.id)}
                      className={cn(
                        "px-3 py-2 rounded-xl text-sm font-medium border transition-all",
                        selectedCardId === card.id
                          ? "border-foreground bg-foreground text-background"
                          : "border-border bg-card hover:border-foreground/30"
                      )}
                    >
                      <span className="inline-block w-3 h-3 rounded-full mr-2" style={{ backgroundColor: card.color }} />
                      {card.card_name}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Summary cards */}
            <div className="grid grid-cols-3 gap-2">
              <div className="p-3 rounded-xl bg-card border border-border text-center">
                <p className="text-xs text-muted-foreground">Selecionados</p>
                <p className="font-bold text-base">{selectedCount}</p>
              </div>
              <div className="p-3 rounded-xl bg-card border border-border text-center">
                <p className="text-xs text-muted-foreground">Parcelados</p>
                <p className="font-bold text-base">{installmentCount}</p>
              </div>
              <div className="p-3 rounded-xl bg-card border border-border text-center">
                <p className="text-xs text-muted-foreground">Total</p>
                <p className="font-bold text-sm">{formatCurrency(totalSelected)}</p>
              </div>
            </div>

            {/* Warnings */}
            {uncategorizedCount > 0 && (
              <div className="p-3 rounded-xl bg-accent/10 border border-accent/30 flex items-center gap-2">
                <Tag className="w-4 h-4 text-accent shrink-0" />
                <p className="text-xs text-accent">
                  {uncategorizedCount} lan├ºamento(s) sem categoria. Toque para categorizar.
                </p>
              </div>
            )}

            {/* Transaction list */}
            <div className="space-y-2">
              {transactions.map((tx, idx) => {
                const cat = tx.categoryId ? allCategories.find(c => c.id === tx.categoryId) : null;
                return (
                  <div key={idx}>
                    <motion.div
                      initial={{ opacity: 0, y: 8 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: Math.min(idx * 0.015, 0.5) }}
                      className={cn(
                        "p-3 rounded-xl border flex items-center gap-3",
                        tx.type === "payment" && "bg-green-500/5 border-green-500/20",
                        tx.type === "purchase" && tx.selected && "bg-card border-border",
                        tx.type === "purchase" && !tx.selected && "bg-muted/30 border-border/50 opacity-60",
                        tx.type === "other" && "bg-muted/20 border-border/30 opacity-50",
                      )}
                    >
                      {tx.type === "purchase" && (
                        <button onClick={() => toggleLine(idx)} className="shrink-0">
                          <div className={cn(
                            "w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors",
                            tx.selected ? "border-primary bg-primary" : "border-muted-foreground"
                          )}>
                            {tx.selected && <Check className="w-3.5 h-3.5 text-primary-foreground" />}
                          </div>
                        </button>
                      )}
                      {tx.type !== "purchase" && (
                        <div className="w-6 h-6 shrink-0 flex items-center justify-center text-muted-foreground">
                          {tx.type === "payment" ? <CreditCard className="w-4 h-4" /> : <RefreshCw className="w-4 h-4" />}
                        </div>
                      )}

                      <div
                        className="flex-1 min-w-0 cursor-pointer"
                        onClick={() => tx.type === "purchase" && setCategorizingIndex(categorizingIndex === idx ? null : idx)}
                      >
                        <p className="font-medium text-sm truncate">{tx.description}</p>
                        <div className="flex items-center gap-1.5 text-xs text-muted-foreground flex-wrap">
                          <span>{tx.date.split("-").reverse().join("/")}</span>
                          {tx.isInstallment && tx.currentInstallment && tx.totalInstallments && (
                            <>
                              <span>┬À</span>
                              <span className="text-primary font-medium">
                                {tx.currentInstallment}/{tx.totalInstallments}x
                              </span>
                            </>
                          )}
                          {cat && (
                            <>
                              <span>┬À</span>
                              <span style={{ color: cat.color }}>{cat.name}</span>
                            </>
                          )}
                          {!cat && tx.selected && tx.type === "purchase" && (
                            <>
                              <span>┬À</span>
                              <span className="text-accent">Sem categoria</span>
                            </>
                          )}
                          {tx.type === "payment" && (
                            <>
                              <span>┬À</span>
                              <span className="text-green-500">Pagamento</span>
                            </>
                          )}
                        </div>
                      </div>

                      <div className="flex items-center gap-2 shrink-0">
                        <p className={cn(
                          "font-semibold text-sm tabular-nums",
                          tx.type === "payment" && "text-green-500"
                        )}>
                          {tx.type === "payment" ? "- " : ""}{formatCurrency(tx.amount)}
                        </p>
                        {tx.type === "purchase" && (
                          <button
                            onClick={(e) => { e.stopPropagation(); removeLine(idx); }}
                            className="p-1 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"
                          >
                            <X className="w-3.5 h-3.5" />
                          </button>
                        )}
                      </div>
                    </motion.div>

                    {/* Inline category picker */}
                    <AnimatePresence>
                      {categorizingIndex === idx && tx.type === "purchase" && (
                        <motion.div
                          initial={{ height: 0, opacity: 0 }}
                          animate={{ height: "auto", opacity: 1 }}
                          exit={{ height: 0, opacity: 0 }}
                          className="overflow-hidden"
                        >
                          <div className="p-3 bg-muted/30 rounded-b-xl border-x border-b border-border flex flex-wrap gap-1.5">
                            {allCategories.map(c => (
                              <button
                                key={c.id}
                                onClick={() => setCategory(idx, c.id)}
                                className={cn(
                                  "px-2 py-1 rounded-full text-[10px] font-medium border transition-all",
                                  tx.categoryId === c.id
                                    ? "border-foreground bg-foreground text-background"
                                    : "border-border bg-card hover:border-foreground/30"
                                )}
                              >
                                {c.name}
                              </button>
                            ))}
                          </div>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                );
              })}
            </div>
          </FadeIn>
        )}

        {/* Step: Importing */}
        {step === "importing" && (
          <FadeIn className="text-center py-12 space-y-4">
            <Loader2 className="w-12 h-12 animate-spin text-primary mx-auto" />
            <h2 className="font-serif text-lg font-semibold">Importando lan├ºamentos...</h2>
            <p className="text-sm text-muted-foreground">
              Criando compras e distribuindo parcelas nos meses correspondentes.
            </p>
            <div className="max-w-xs mx-auto">
              <div className="h-2 bg-muted rounded-full overflow-hidden">
                <motion.div
                  className="h-full bg-primary rounded-full"
                  animate={{ width: `${importProgress}%` }}
                  transition={{ duration: 0.3 }}
                />
              </div>
              <p className="text-sm text-muted-foreground mt-2">{importProgress}%</p>
            </div>
          </FadeIn>
        )}

        {/* Step: Done */}
        {step === "done" && (
          <FadeIn className="text-center py-12 space-y-6">
            <div className="w-20 h-20 rounded-full bg-green-500/10 mx-auto flex items-center justify-center">
              <Check className="w-10 h-10 text-green-500" />
            </div>
            <div>
              <h2 className="font-serif text-lg font-semibold">Importa├º├úo conclu├¡da!</h2>
              <p className="text-sm text-muted-foreground mt-1">
                {importedCount} lan├ºamento(s) importados com sucesso.
              </p>
              {installmentCount > 0 && (
                <p className="text-xs text-muted-foreground mt-1">
                  Parcelas distribu├¡das automaticamente nos meses correspondentes.
                </p>
              )}
            </div>
            <div className="flex flex-col gap-3 items-center w-full max-w-xs mx-auto">
              <Button variant="warm" className="w-full" onClick={() => navigate("/", { replace: true })}>
                Ir para o In├¡cio
              </Button>
              <div className="flex gap-3 w-full">
                <Button variant="outline" className="flex-1" onClick={() => navigate("/cards")}>
                  Ver cart├Áes
                </Button>
                <Button variant="outline" className="flex-1" onClick={() => { setStep("upload"); setTransactions([]); setParseResult(null); }}>
                  Importar outra
                </Button>
              </div>
            </div>
          </FadeIn>
        )}
      </main>

      {/* Footer - Review step */}
      {step === "review" && (
        <div className="fixed bottom-0 left-0 right-0 bg-background border-t border-border px-5 pb-safe-bottom">
          <div className="py-4 flex gap-3">
            <Button variant="outline" size="lg" className="flex-1 h-14" onClick={() => { setStep("upload"); setTransactions([]); }}>
              Voltar
            </Button>
            <Button
              variant="warm"
              size="lg"
              className="flex-1 h-14 gap-2"
              onClick={handleStartImport}
              disabled={!selectedCardId || selectedCount === 0}
            >
              <Check className="w-5 h-5" />
              Importar {selectedCount}
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from "react";
import { parseLocalDate } from "@/lib/dateUtils";
import { useNavigate, useParams } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { FadeIn } from "@/components/ui/motion";
import { ArrowLeft, Edit2, Trash2, RefreshCw, Zap, Calendar, Pencil, Loader2 } from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { useIncomeById, useDeleteIncome } from "@/hooks/useIncomes";
import { DeleteConfirmDialog } from "@/components/shared/DeleteConfirmDialog";

// Map database income_type to display categories
const isFixedType = (type: string) => ["salary"].includes(type);

const typeLabels: Record<string, string> = {
  salary: "Sal├írio",
  freelance: "Freelance",
  investment: "Investimento",
  gift: "Presente",
  initial_balance: "Saldo inicial",
  other: "Outros",
};

export const IncomeDetail = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const { data: income, isLoading } = useIncomeById(id);
  const deleteIncome = useDeleteIncome();

  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("pt-BR", {
      style: "currency",
      currency: "BRL",
    }).format(value);

  const handleDelete = async () => {
    if (!id) return;

    try {
      await deleteIncome.mutateAsync(id);
      setShowDeleteDialog(false);
      navigate("/");
    } catch (error) {
      console.error("Error deleting income:", error);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!income) {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center p-5">
        <span className="text-4xl mb-4">­ƒöì</span>
        <p className="text-muted-foreground mb-4">Receita n├úo encontrada</p>
        <Button variant="ghost" onClick={() => navigate(-1)}>
          Voltar
        </Button>
      </div>
    );
  }

  const isFixed = isFixedType(income.type);

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-2 flex items-center gap-4">
