            </div>
          </div>
        </FadeIn>

        {/* Details */}
        <FadeIn delay={0.15}>
          <div className="space-y-3">
            {/* Date */}
            <div className="flex items-center gap-3 p-3 rounded-xl bg-card border border-border">
              <div className="w-9 h-9 rounded-full bg-muted flex items-center justify-center">
