    // UI
    const [showKeypad, setShowKeypad] = useState(true);
    const keypadTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const catScrollRef = useRef<HTMLDivElement>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showSuccess, setShowSuccess] = useState(false);

    // Auto-hide keypad 1.5s after last keystroke
    const handleAmountChange = useCallback((val: string) => {
        setAmount(val);
        setShowKeypad(true);
        if (keypadTimerRef.current) clearTimeout(keypadTimerRef.current);
        keypadTimerRef.current = setTimeout(() => setShowKeypad(false), 1500);
    }, []);

    // ÔöÇÔöÇ Derived values ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const numericAmount = parseCurrency(amount);
    const selectedCategory = categoryId ? allCategories.find(c => c.id === categoryId) : undefined;

    // Balance Calculation
    const totalCCInstallments = ccInstallments.reduce((sum, inst) => sum + Number(inst.amount), 0);
    const bankTotal = bankAccounts.reduce((sum, acc) => sum + Number(acc.current_balance), 0);

    const currentBalance = useMemo(() => calculateBalances(
        incomes,
        expensesRepo,
        debts,
        now,
        subscriptions,
        goalStats?.totalSaved || 0,
        totalCCInstallments,
        bankTotal
    ), [incomes, expensesRepo, debts, subscriptions, goalStats?.totalSaved, totalCCInstallments, bankTotal]);

    const newSaldoLivre = currentBalance.saldoLivre - numericAmount;
    const impactPercentage = currentBalance.saldoLivre > 0
        ? Math.min(100, Math.round((numericAmount / currentBalance.saldoLivre) * 100))
        : 0;

    // All categories carousel: quick picks first, then the rest
    const sourceList = allCategories.length > 0 ? allCategories : defaultCategories;
    const quickSet = new Set(QUICK_CAT_IDS);
    const quickFirst = QUICK_CAT_IDS
        .map(slug => sourceList.find(c => c.id === slug))
        .filter(Boolean) as typeof allCategories;
    const remaining = sourceList.filter(c => !quickSet.has(c.id));
    const orderedCategories = [...quickFirst, ...remaining];

    const isCreditCard = paymentMethod === "credit" && !!selectedCardId;
    const canSubmit = numericAmount > 0 && !!paymentMethod &&
        (paymentMethod === "credit" ? !!selectedCardId : true);

    // ÔöÇÔöÇ Reimbursement shortcuts ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const setReimbFraction = (frac: number) => {
        if (!numericAmount) return;
        const val = Math.round(numericAmount * frac * 100);
        setReimbAmount(formatCurrencyInput(String(val)));
    };

    // ÔöÇÔöÇ UUID resolver ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    async function resolveCategoryId(id: string | undefined): Promise<string | null> {
        if (!id || !user) return null;
        if (isValidUuid(id) && id.length >= 30) return id;

        const cat = allCategories.find(c => c.id === id);
        if (!cat) return null;

        const { data: existing } = await supabase
            .from("categories").select("id")
            .ilike("name", cat.name).eq("user_id", user.id).maybeSingle();
        if (existing) return existing.id;

        const { data: created } = await supabase.from("categories").insert({
            user_id: user.id, name: cat.name, icon: "Tag", color: cat.color,
            type: "expense", group_name: cat.group, nature: cat.nature as any,
            is_default: true, allow_expense: cat.allowExpense ?? true,
            allow_card: cat.allowCard ?? true, allow_subscription: cat.allowSubscription ?? true,
        }).select().single();

        return created?.id ?? null;
    }

    // ÔöÇÔöÇ Save ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleSave = async () => {
        if (!canSubmit || !user || isSubmitting) return;
        setIsSubmitting(true);
        try {
            const finalCategoryId = await resolveCategoryId(categoryId);

            if (isCreditCard) {
                await createCreditCardPurchase.mutateAsync({
                    card_id: selectedCardId!,
                    description: description || selectedCategory?.name || "Compra no cart├úo",
                    total_amount: numericAmount,
                    total_installments: installments,
                    category_id: finalCategoryId,
                    purchase_date: date,
                });
            } else {
                let bankId = selectedBankId;
                if (paymentMethod === "cash") bankId = await ensureCashAccount();

                const purchaseDate = new Date(date + "T12:00:00");
                const totalInstalls = installments > 1 ? installments : 1;

                if (totalInstalls > 1) {
                    const groupId = crypto.randomUUID();
                    await createBulkExpenses.mutateAsync(
                        Array.from({ length: totalInstalls }, (_, i) => ({
                            amount: numericAmount,
                            description: description || selectedCategory?.name || "Gasto",
                            status: "confirmed" as const,
                            source: "manual" as const,
                            is_installment: false,
                            total_installments: totalInstalls,
                            installment_number: i + 1,
                            installment_group_id: groupId,
                            bank_account_id: bankId ?? undefined,
                            date: format(addMonths(purchaseDate, i), "yyyy-MM-dd"),
                            category_id: finalCategoryId,
                        })) as any
                    );
                } else {
                    await createExpense.mutateAsync({
                        amount: numericAmount,
                        description: description || selectedCategory?.name || "Gasto",
                        status: "confirmed",
                        source: "manual",
                        is_installment: false,
                        installment_number: 1,
                        bank_account_id: bankId ?? undefined,
                        date,
                        category_id: finalCategoryId,
                    } as any);
                }

                if (bankId) {
                    await updateBankBalance.mutateAsync({ accountId: bankId, delta: -numericAmount });
                }
            }

            if (isForOtherPerson && reimbName.trim()) {
                const reimbValue = parseCurrency(reimbAmount) || numericAmount;
                await createReceivable.mutateAsync({
                    debtor_name: reimbName.trim(),
                    amount: reimbValue,
                    description: `Reembolso ÔÇô ${description || selectedCategory?.name || "Gasto"}`,
                    due_date: reimbDate,
                    status: "pending",
                });
            }

            setShowSuccess(true);
            setTimeout(() => navigate("/", { state: { success: true } }), 1800);
        } catch (err: any) {
            console.error(err);
            toast.error(err?.message || "Erro ao salvar. Tente novamente.");
        } finally {
            setIsSubmitting(false);
        }
    };

    // ÔöÇÔöÇ Success ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    if (showSuccess) {
        return (
            <div className="min-h-screen bg-background flex flex-col items-center justify-center gap-6 px-6">
                <motion.div
                    initial={{ scale: 0 }} animate={{ scale: 1 }}
                    transition={{ type: "spring", damping: 14 }}
                    className="w-24 h-24 rounded-full bg-green-500/15 flex items-center justify-center"
                >
                    <Check className="w-12 h-12 text-green-500" strokeWidth={2.5} />
                </motion.div>
                <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className="text-center">
                    <p className="text-2xl font-bold">Gasto registrado!</p>
                    <p className="text-muted-foreground mt-1">{formatCurrency(numericAmount)} debitado</p>
                    {isForOtherPerson && reimbName && (
                        <p className="text-sm text-primary font-medium mt-2">
                            ­ƒÆ¼ Valor a receber criado para {reimbName}
                        </p>
                    )}
                </motion.div>
            </div>
        );
    }

    // ÔöÇÔöÇ Keypad height: ~284px. Bottom button: ~72px. Total fixed: ~356px. ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const keypadOpen = showKeypad;
    const bottomOffset = keypadOpen ? "pb-[370px]" : "pb-24";

    // ÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    return (
        <div className="min-h-screen bg-background flex flex-col">

            {/* Header */}
            <div className="flex items-center gap-3 px-4 pt-4 pb-2 border-b border-border bg-background/80 backdrop-blur-xl sticky top-0 z-40">
                <button onClick={() => navigate(-1)} className="w-9 h-9 rounded-full bg-muted/50 flex items-center justify-center hover:bg-muted transition-colors">
                    <ArrowLeft className="w-4 h-4" />
                </button>
                <h1 className="font-bold text-base flex-1">Novo Gasto</h1>
                <div className="flex items-center gap-1 px-2 py-1 rounded-full bg-primary/5 border border-primary/10">
                    <Sparkles className="w-3 h-3 text-primary animate-pulse" />
                    <span className="text-[10px] font-bold text-primary uppercase">Quick Mode</span>
                </div>
            </div>

            {/* Scrollable form */}
            <div className={cn("flex-1 overflow-y-auto pt-4 space-y-6", bottomOffset)}>

                {/* ÔöÇÔöÇ Balance Impact Preview ÔöÇÔöÇ */}
                <FadeIn className="px-4">
                    <div className="relative group overflow-hidden rounded-2xl bg-gradient-to-br from-card to-background border border-border p-4 shadow-sm">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl" />

                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-1.5 text-muted-foreground">
                                <Info className="w-3.5 h-3.5" />
                                <span className="text-[10px] font-bold uppercase tracking-wider">Impacto no Saldo Livre</span>
                            </div>
                            <div className={cn(
                                "px-2 py-0.5 rounded-full text-[10px] font-bold",
                                impactPercentage > 30 ? "bg-red-100 text-red-600" : "bg-emerald-100 text-emerald-600"
                            )}>
                                {impactPercentage}% do dispon├¡vel
                            </div>
                        </div>

                        <div className="flex items-end justify-between">
                            <div className="space-y-0.5">
                                <p className="text-xs text-muted-foreground">Saldo Atual</p>
                                <p className="font-bold text-foreground">{formatCurrency(currentBalance.saldoLivre)}</p>
                            </div>

                            <div className="h-8 w-px bg-border/50 mx-2" />

                            <div className="text-right space-y-0.5">
                                <p className="text-xs text-muted-foreground">Ap├│s este gasto</p>
                                <Counter
                                    value={newSaldoLivre}
                                    className={cn(
                                        "font-bold text-lg",
                                        newSaldoLivre < 0 ? "text-red-500" : "text-emerald-500"
                                    )}
                                />
                            </div>
                        </div>

                        {/* Visual Progress Bar of Impact */}
                        <div className="mt-3 h-1 w-full bg-muted rounded-full overflow-hidden">
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${impactPercentage}%` }}
                                className={cn(
                                    "h-full rounded-full",
                                    impactPercentage > 30 ? "bg-red-500" : "bg-primary"
                                )}
                            />
                        </div>
                    </div>
                </FadeIn>

                {/* ÔöÇÔöÇ Amount ÔöÇÔöÇ */}
                <div className="px-4">
                    <button
                        onClick={() => setShowKeypad(v => !v)}
                        className="w-full text-center py-4 rounded-2xl bg-card border border-border shadow-soft active:scale-[0.98] transition-transform"
                    >
                        <p className="text-[10px] uppercase tracking-widest text-muted-foreground mb-1">Valor do Gasto</p>
                        <motion.p
                            key={amount}
                            initial={{ scale: 0.95, opacity: 0.8 }}
                            animate={{ scale: 1, opacity: 1 }}
                            className={cn(
                                "text-5xl font-bold tabular-nums tracking-tight",
                                numericAmount > 0 ? "text-foreground" : "text-muted-foreground/20"
                            )}>
                            {amount ? formatCurrency(numericAmount) : "R$ 0,00"}
                        </motion.p>
                        <p className="text-[10px] text-primary mt-2 font-bold uppercase tracking-wide">
                            {showKeypad ? "Ocultar Teclado" : "Editar Valor"}
                        </p>
                    </button>
                </div>

                {/* ÔöÇÔöÇ Categories carousel: full-bleed horizontal scroll ÔöÇÔöÇ */}
                <section>
                    <div className="px-4">
                        <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground mb-2">
                            Categoria {selectedCategory && <span className="normal-case font-normal text-primary">┬À {selectedCategory.name}</span>}
                        </p>
                    </div>

                    <div
                        ref={catScrollRef}
                        className="flex gap-2 pb-2"
                        style={{
                            overflowX: "auto",
                            overflowY: "hidden",
                            scrollbarWidth: "none",
                            WebkitOverflowScrolling: "touch" as any,
                            touchAction: "pan-x",
                            paddingLeft: "1rem",
                            paddingRight: "1rem",
                        }}
                    >
                        {(catsLoading && orderedCategories.length === 0
                            ? Array.from({ length: 8 })
                            : orderedCategories
                        ).map((cat, i) => {
                            if (!cat) {
                                return <div key={i} className="flex-shrink-0 w-[70px] h-[72px] rounded-2xl bg-muted animate-pulse" />;
                            }
                            const Icon = (cat as typeof allCategories[0]).icon;
                            const c = cat as typeof allCategories[0];
                            const isSelected = categoryId === c.id;
                            const isQuick = quickSet.has(c.id);
                            return (
                                <motion.button
                                    key={c.id}
                                    whileTap={{ scale: 0.91 }}
                                    onClick={() => setCategoryId(isSelected ? undefined : c.id)}
                                    style={{ flexShrink: 0, minWidth: 70 }}
                                    className={cn(
                                        "flex flex-col items-center gap-1.5 px-3 py-2.5 rounded-2xl border transition-all relative",
                                        isSelected
                                            ? "border-primary bg-primary/10 text-primary shadow-sm"
                                            : "border-border bg-card text-muted-foreground"
                                    )}
                                >
                                    {isQuick && !isSelected && (
                                        <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 rounded-full bg-primary/60" />
                                    )}
                                    <Icon className="w-5 h-5" />
                                    <span className="text-[9px] font-bold text-center leading-tight w-14 line-clamp-2">{c.name}</span>
                                </motion.button>
                            );
                        })}
                    </div>
                </section>

                {/* ÔöÇÔöÇ Payment method ÔöÇÔöÇ */}
                <section className="px-4">
                    <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground mb-2">Forma de Pagamento</p>
                    <div className="grid grid-cols-4 gap-2">
                        {PAYMENT_OPTIONS.map(({ value, label, Icon }) => {
                            const isSelected = paymentMethod === value;
                            return (
                                <motion.button
                                    key={value}
                                    whileTap={{ scale: 0.92 }}
                                    onClick={() => {
                                        setPaymentMethod(value);
                                        setSelectedCardId(undefined);
                                        if (value !== "credit") setInstallments(1);
                                    }}
                                    className={cn(
                                        "flex flex-col items-center gap-1.5 py-3 rounded-2xl border transition-all",
                                        isSelected
                                            ? "border-primary bg-primary/10 text-primary"
                                            : "border-border bg-card text-muted-foreground"
                                    )}
                                >
                                    <Icon className="w-5 h-5" />
                                    <span className="text-[10px] font-bold">{label}</span>
                                </motion.button>
                            );
                        })}
                    </div>
                </section>

                {/* ÔöÇÔöÇ Account / Card ÔöÇÔöÇ */}
                <AnimatePresence>
                    {paymentMethod && paymentMethod !== "cash" && (
                        <motion.section
                            initial={{ opacity: 0, height: 0 }}
                            animate={{ opacity: 1, height: "auto" }}
                            exit={{ opacity: 0, height: 0 }}
                            className="px-4"
                        >
                            <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground mb-2">
                                {paymentMethod === "credit" ? "Cart├úo" : "Conta"}
                            </p>
                            <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar">
                                {paymentMethod === "credit"
                                    ? creditCards.map(card => (
                                        <motion.button key={card.id} whileTap={{ scale: 0.95 }}
                                            onClick={() => setSelectedCardId(card.id)}
                                            className={cn(
                                                "flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl border transition-all",
                                                selectedCardId === card.id ? "border-primary bg-primary/10" : "border-border bg-card"
                                            )}>
                                            <BankLogo bankName={card.card_name || card.bank} className="w-6 h-6" size="sm" />
                                            <span className="text-xs font-medium max-w-[90px] truncate">{card.card_name || card.bank}</span>
                                        </motion.button>
                                    ))
                                    : bankAccounts.map(acc => (
                                        <motion.button key={acc.id} whileTap={{ scale: 0.95 }}
                                            onClick={() => setSelectedBankId(acc.id)}
                                            className={cn(
                                                "flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl border transition-all",
                                                selectedBankId === acc.id ? "border-primary bg-primary/10" : "border-border bg-card"
                                            )}>
                                            <BankLogo bankName={acc.bank_name} className="w-6 h-6" size="sm" />
                                            <div className="text-left">
                                                <p className="text-[11px] font-semibold max-w-[80px] truncate">{acc.bank_name}</p>
                                                <p className="text-[9px] text-muted-foreground">{formatCurrency(Number(acc.current_balance))}</p>
                                            </div>
                                        </motion.button>
                                    ))
                                }
                            </div>
                        </motion.section>
                    )}
                </AnimatePresence>

                {/* ÔöÇÔöÇ Credit: Installments ÔöÇÔöÇ */}
                <AnimatePresence>
                    {paymentMethod === "credit" && (
                        <motion.section
                            initial={{ opacity: 0, height: 0 }}
                            animate={{ opacity: 1, height: "auto" }}
                            exit={{ opacity: 0, height: 0 }}
                            className="bg-card rounded-2xl border border-border p-3 mx-4"
                        >
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <CreditCard className="w-4 h-4 text-muted-foreground" />
                                    <span className="text-sm font-semibold">Parcelas</span>
                                </div>
                                <div className="flex items-center gap-3">
                                    <button onClick={() => setInstallments(v => Math.max(1, v - 1))}
                                        className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                                        <Minus className="w-3 h-3" />
                                    </button>
                                    <span className="text-base font-bold w-8 text-center">{installments}x</span>
                                    <button onClick={() => setInstallments(v => Math.min(48, v + 1))}
                                        className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                                        <Plus className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                            {installments > 1 && numericAmount > 0 && (
                                <p className="text-xs text-muted-foreground mt-2 text-right">
                                    {installments}├ù de {formatCurrency(numericAmount / installments)}/m├¬s
                                </p>
                            )}
                        </motion.section>
                    )}
                </AnimatePresence>

                {/* ÔöÇÔöÇ Recorrente (non-credit only) ÔöÇÔöÇ */}
                <AnimatePresence>
                    {paymentMethod && paymentMethod !== "credit" && (
                        <motion.section
                            initial={{ opacity: 0, height: 0 }}
                            animate={{ opacity: 1, height: "auto" }}
                            exit={{ opacity: 0, height: 0 }}
                            className="px-4"
                        >
                            <button
                                onClick={() => setIsRecurring(v => !v)}
                                className={cn(
                                    "w-full flex items-center justify-between px-4 py-3 rounded-2xl border transition-all",
                                    isRecurring ? "border-primary bg-primary/10 text-primary" : "border-border bg-card text-muted-foreground"
                                )}
                            >
                                <div className="flex items-center gap-2">
                                    <RepeatIcon className="w-4 h-4" />
                                    <span className="text-sm font-semibold">Gasto recorrente</span>
                                </div>
                                <span className="text-xs font-bold">{isRecurring ? "Sim Ô£ô" : "N├úo"}</span>
                            </button>

                            <AnimatePresence>
                                {isRecurring && (
                                    <motion.div
                                        initial={{ height: 0, opacity: 0 }}
                                        animate={{ height: "auto", opacity: 1 }}
                                        exit={{ height: 0, opacity: 0 }}
                                        className="overflow-hidden mt-2"
                                    >
                                        <div className="bg-card rounded-2xl border border-border p-3 space-y-2">
                                            <p className="text-xs text-muted-foreground">Quantas vezes se repete?</p>
                                            <div className="flex items-center gap-3">
                                                <button onClick={() => setInstallments(v => Math.max(2, v - 1))}
                                                    className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                                                    <Minus className="w-3 h-3" />
                                                </button>
                                                <span className="text-base font-bold w-16 text-center">{installments} meses</span>
                                                <button onClick={() => setInstallments(v => Math.min(36, v + 1))}
                                                    className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                                                    <Plus className="w-3 h-3" />
                                                </button>
                                            </div>
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </motion.section>
                    )}
                </AnimatePresence>

                {/* ÔöÇÔöÇ Date & Description ÔöÇÔöÇ */}
                <section className="flex gap-2 px-4">
                    <div className="flex-1 flex items-center gap-2 p-3 bg-card rounded-xl border border-border">
                        <Calendar className="w-4 h-4 text-muted-foreground flex-shrink-0" />
                        <input
                            type="date" value={date} onChange={e => setDate(e.target.value)}
                            className="flex-1 bg-transparent text-sm font-medium outline-none min-w-0"
                        />
                    </div>
                </section>

                <section className="px-4">
                    <input
                        type="text" value={description} onChange={e => setDescription(e.target.value)}
                        placeholder="Descri├º├úo (opcional)"
                        className="w-full p-3 bg-card rounded-xl border border-border text-sm outline-none placeholder:text-muted-foreground/40"
                    />
                </section>

                {/* ÔöÇÔöÇ Gasto meu / Para outra pessoa ÔöÇÔöÇ */}
                <section className="rounded-2xl border border-border overflow-hidden bg-card mx-4">
                    {/* Toggle header */}
                    <div className="flex">
                        <button
                            onClick={() => setIsForOtherPerson(false)}
                            className={cn(
                                "flex-1 py-3.5 text-sm font-bold transition-all",
                                !isForOtherPerson ? "bg-primary text-primary-foreground" : "text-muted-foreground"
                            )}
                        >
                            Ô£ô Gasto meu
                        </button>
                        <button
                            onClick={() => setIsForOtherPerson(true)}
                            className={cn(
                                "flex-1 py-3.5 text-sm font-bold transition-all",
                                isForOtherPerson ? "bg-primary text-primary-foreground" : "text-muted-foreground"
                            )}
                        >
                            ­ƒæñ Para outra pessoa
                        </button>
                    </div>

                    {/* Third-party fields */}
                    <AnimatePresence>
                        {isForOtherPerson && (
                            <motion.div
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: "auto", opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                className="overflow-hidden border-t border-border"
                            >
                                <div className="p-4 space-y-3">
                                    {/* Name */}
                                    <div className="flex items-center gap-2 p-2 bg-muted rounded-xl">
                                        <User className="w-4 h-4 text-muted-foreground flex-shrink-0" />
                                        <input
                                            type="text" value={reimbName} onChange={e => setReimbName(e.target.value)}
                                            placeholder="Nome da pessoa"
                                            className="flex-1 bg-transparent text-sm outline-none placeholder:text-muted-foreground/50"
                                        />
                                    </div>

                                    {/* Partial amount */}
                                    <div>
                                        <p className="text-[10px] text-muted-foreground mb-1 ml-1">Valor a receber de volta</p>
                                        <input
                                            type="text" value={reimbAmount} onChange={e => setReimbAmount(e.target.value)}
                                            placeholder={`Total: ${amount || "R$ 0,00"}`}
                                            className="w-full p-2.5 bg-muted rounded-xl text-sm outline-none placeholder:text-muted-foreground/40"
                                        />
                                        {numericAmount > 0 && (
                                            <div className="flex gap-2 mt-2">
                                                {[{ label: "50%", frac: 0.5 }, { label: "33%", frac: 1 / 3 }, { label: "25%", frac: 0.25 }].map(({ label, frac }) => (
                                                    <button
                                                        key={label}
                                                        onClick={() => setReimbFraction(frac)}
                                                        className="text-[10px] px-2.5 py-1 rounded-full bg-primary/10 text-primary font-bold"
                                                    >
                                                        {label} ÔÇô {formatCurrency(numericAmount * frac)}
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    {/* Due date */}
                                    <div className="flex items-center gap-2 p-2 bg-muted rounded-xl">
                                        <Calendar className="w-4 h-4 text-muted-foreground flex-shrink-0" />
                                        <input
                                            type="date" value={reimbDate} onChange={e => setReimbDate(e.target.value)}
                                            className="flex-1 bg-transparent text-xs outline-none"
                                        />
                                        <span className="text-[9px] text-muted-foreground whitespace-nowrap">previs├úo devolu├º├úo</span>
                                    </div>
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </section>

                {/* Bottom spacer */}
                <div className="h-4 px-4" />
            </div>

            {/* ÔöÇÔöÇ Fixed bottom: keypad + button ÔöÇÔöÇ */}
            <div className="fixed bottom-0 left-0 right-0 z-50 bg-background/95 backdrop-blur-sm border-t border-border">
                <AnimatePresence>
                    {showKeypad && (
                        <motion.div
                            initial={{ height: 0, opacity: 0 }}
                            animate={{ height: "auto", opacity: 1 }}
                            exit={{ height: 0, opacity: 0 }}
                            transition={{ type: "spring", damping: 26, stiffness: 320 }}
                            className="overflow-hidden"
                        >
                            <div className="px-3 pt-3">
                                <NumericKeypad value={amount} onChange={handleAmountChange} />
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                <div className="px-4 py-3">
                    <motion.button
                        whileTap={{ scale: 0.97 }}
                        onClick={handleSave}
                        disabled={!canSubmit || isSubmitting}
                        className={cn(
                            "w-full h-14 rounded-2xl text-base font-bold transition-all flex items-center justify-center gap-2 shadow-lg",
                            canSubmit && !isSubmitting
                                ? "bg-primary text-primary-foreground shadow-primary/25"
                                : "bg-muted text-muted-foreground cursor-not-allowed"
                        )}
                    >
                        {isSubmitting ? (
                            <Loader2 className="w-5 h-5 animate-spin" />
                        ) : (
                            <><Check className="w-5 h-5" /> Registrar Gasto</>
                        )}
                    </motion.button>
                </div>
            </div>
        </div>
    );
};

export default QuickExpense;

import { useState, useMemo } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { FadeIn } from "@/components/ui/motion";
import {
  ArrowLeft,
  User,
  Calendar,
  Clock,
  CheckCircle2,
  AlertTriangle,
  Trash2,
  Edit2,
  MessageCircle,
  Loader2,
  Landmark,
  Handshake
} from "lucide-react";
import { toast } from "sonner";
import { format, differenceInDays } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { useReceivableById, useUpdateReceivable, useDeleteReceivable } from "@/hooks/useReceivables";
import { DeleteConfirmDialog, DeleteScope } from "@/components/shared/DeleteConfirmDialog";

type ReceivableStatus = "pending" | "received" | "cancelled";

const statusConfig: Record<ReceivableStatus, { label: string; color: string; bgColor: string; icon: typeof Clock }> = {
  pending: {
    label: "Em aberto",
    color: "text-accent",
    bgColor: "bg-accent/10",
    icon: Clock
  },
  received: {
    label: "Recebido",
    color: "text-essential",
    bgColor: "bg-essential/10",
    icon: CheckCircle2
  },
  cancelled: {
    label: "Cancelado",
    color: "text-muted-foreground",
    bgColor: "bg-muted",
    icon: Clock
  },
};

const getDueDateInfo = (dueDate: Date | null) => {
  if (!dueDate) return { isOverdue: false, isDueSoon: false, daysText: "Sem data" };

  const today = new Date();
  const daysUntilDue = differenceInDays(dueDate, today);

  if (daysUntilDue < 0) {
    return { isOverdue: true, isDueSoon: false, daysText: `${Math.abs(daysUntilDue)} dias atrasado` };
  } else if (daysUntilDue === 0) {
    return { isOverdue: false, isDueSoon: true, daysText: "Vence hoje" };
  } else if (daysUntilDue <= 3) {
    return { isOverdue: false, isDueSoon: true, daysText: `Vence em ${daysUntilDue} dia${daysUntilDue > 1 ? "s" : ""}` };
  }
  return { isOverdue: false, isDueSoon: false, daysText: `Vence em ${daysUntilDue} dias` };
};

const ReceivableDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { data: receivable, isLoading } = useReceivableById(id);
  const updateReceivable = useUpdateReceivable();
  const deleteReceivable = useDeleteReceivable();

  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const dueDateInfo = useMemo(() => {
    if (!receivable?.due_date) return { isOverdue: false, isDueSoon: false, daysText: "Sem data" };
    return getDueDateInfo(new Date(receivable.due_date));
  }, [receivable]);

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("pt-BR", {
      style: "currency",
      currency: "BRL",
    }).format(value);

  const handleMarkAsReceived = async () => {
    if (!id || !receivable) return;

    try {
      await updateReceivable.mutateAsync({
        id,
        status: "received",
        received_at: new Date().toISOString(),
      });
      toast.success("Valor marcado como recebido!");
      navigate("/");
    } catch (error) {
      console.error("Error marking as received:", error);
    }
  };

  const handleDelete = async (scope: DeleteScope = "current") => {
    if (!id) return;

    try {
      await deleteReceivable.mutateAsync({
        id,
        scope,
        groupId: (receivable as any).installment_group_id,
        dueDate: receivable.due_date
      });
      setShowDeleteDialog(false);
      navigate("/");
    } catch (error) {
      console.error("Error deleting receivable:", error);
    }
  };

  const handleSendReminder = () => {
    if (!receivable) return;

    const formattedAmount = formatCurrency(Number(receivable.amount));
    const formattedDate = receivable.due_date
      ? format(new Date(receivable.due_date), "dd/MM/yyyy")
      : "a combinar";

    const message = dueDateInfo.isOverdue
      ? `Ol├í ${receivable.debtor_name}! Tudo bem? Passando para lembrar sobre o valor de ${formattedAmount}${receivable.description ? ` referente a "${receivable.description}"` : ""}. O pagamento estava previsto para ${formattedDate}. Consegue me retornar sobre isso?`
      : `Ol├í ${receivable.debtor_name}! Tudo bem? Passando para lembrar sobre o valor de ${formattedAmount}${receivable.description ? ` referente a "${receivable.description}"` : ""}, combinado para ${formattedDate}. S├│ para confirmar que est├í tudo certo!`;

    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/?text=${encodedMessage}`;

    window.open(whatsappUrl, "_blank");

    toast.success("WhatsApp aberto! Selecione o contato.");
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!receivable) {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center p-5">
        <span className="text-4xl mb-4">­ƒöì</span>
        <p className="text-muted-foreground mb-4">Valor a receber n├úo encontrado</p>
        <Button variant="ghost" onClick={() => navigate(-1)}>
          Voltar
        </Button>
      </div>
    );
  }

  const config = statusConfig[receivable.status as ReceivableStatus] || statusConfig.pending;
  const StatusIcon = config.icon;
  const isOverdue = dueDateInfo.isOverdue;
  const allReceived = receivable.status === "received";

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="px-5 pt-safe-top">
        <div className="pt-4 pb-4">
          <FadeIn>
            <div className="flex items-center gap-3">
              <Button
                variant="ghost"
                size="icon"
                className="h-9 w-9"
                onClick={() => navigate(-1)}
              >
                <ArrowLeft className="h-5 w-5" />
              </Button>
              <h1 className="font-serif text-2xl font-semibold flex-1">
                Detalhes
              </h1>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => navigate(`/receivables/${id}/edit`)}
              >
                <Edit2 className="w-5 h-5" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setShowDeleteDialog(true)}
                className="text-destructive hover:text-destructive"
              >
                <Trash2 className="w-5 h-5" />
              </Button>
            </div>
          </FadeIn>
        </div>
      </header>

      <main className="px-5 pb-8 space-y-6">
        {/* Main Card */}
        <FadeIn delay={0.05}>
          <Card className="p-6">
            <div className="flex items-center gap-4 mb-6">
              <div className={cn(
                "w-16 h-16 rounded-2xl flex items-center justify-center shadow-soft",
                (receivable as any).type === "loan" ? "bg-primary/10" : "bg-muted"
              )}>
                {(receivable as any).type === "loan" ? (
                  <Handshake className="w-8 h-8 text-primary" />
                ) : (
                  <User className="w-8 h-8 text-muted-foreground" />
                )}
              </div>
              <div className="flex-1">
                <p className="font-serif text-2xl font-semibold flex items-center gap-2">
                  {receivable.debtor_name}
                  {(receivable as any).is_installment && (
                    <span className="text-sm font-sans font-bold text-muted-foreground bg-secondary px-2 py-0.5 rounded-lg">
                      {(receivable as any).installment_number}/{(receivable as any).total_installments}
                    </span>
                  )}
                </p>
                <div className="flex flex-wrap gap-2 mt-2">
                  <div className={cn(
                    "inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider",
                    allReceived ? statusConfig.received.bgColor : isOverdue ? "bg-impulse/10" : config.bgColor
                  )}>
                    {allReceived ? (
                      <CheckCircle2 className="w-3 h-3 text-essential" />
                    ) : (
                      <StatusIcon className={cn("w-3 h-3", isOverdue ? "text-impulse" : config.color)} />
                    )}
                    <span className={allReceived ? "text-essential" : isOverdue ? "text-impulse" : config.color}>
                      {allReceived ? "Quitado" : isOverdue ? "Atrasado" : config.label}
                    </span>
                  </div>

                  {(receivable as any).type === "loan" && (
                    <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-primary/10 text-primary text-[10px] font-bold uppercase tracking-wider">
                      <Handshake className="w-3 h-3" />
                      <span>Empr├®stimo</span>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Amount */}
            <div className="text-center py-6 border-y border-border/50">
              <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-muted-foreground mb-2">Valor Total</p>
              <p className="font-serif text-4xl font-semibold text-essential">
                {formatCurrency(Number(receivable.amount))}
              </p>
            </div>

            {/* Details Grid */}
            <div className="pt-6 space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {/* Due Date */}
                <div className="flex items-center gap-3 p-3 rounded-2xl bg-secondary/20">
                  <div className={cn(
                    "w-10 h-10 rounded-xl flex items-center justify-center",
                    isOverdue && !allReceived ? "bg-impulse/10 text-impulse" : "bg-card text-muted-foreground"
                  )}>
                    <Calendar className="w-5 h-5" />
                  </div>
                  <div className="flex-1">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Vencimento</p>
                    <p className={cn("text-sm font-semibold", isOverdue && !allReceived && "text-impulse")}>
                      {receivable.due_date
                        ? format(new Date(receivable.due_date), "dd/MM/yyyy")
                        : "A combinar"}
                    </p>
                  </div>
                </div>

                {/* Account (Destination) */}
                <div className="flex items-center gap-3 p-3 rounded-2xl bg-secondary/20">
                  <div className="w-10 h-10 rounded-xl bg-card text-muted-foreground flex items-center justify-center">
                    <Landmark className="w-5 h-5 text-essential" />
                  </div>
                  <div className="flex-1">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Receber na conta</p>
                    <p className="text-sm font-semibold">
                      {(receivable as any).bank_account
                        ? ((receivable as any).bank_account.name || (receivable as any).bank_account.bank_name)
                        : (receivable as any).bank_account_id ? "Conta Vinculada" : "N├úo definida"}
                    </p>
                  </div>
                </div>

                {/* Source Account (If loan) */}
                {(receivable as any).type === "loan" && (
                  <div className="flex items-center gap-3 p-3 rounded-2xl bg-secondary/20">
                    <div className="w-10 h-10 rounded-xl bg-card text-muted-foreground flex items-center justify-center">
                      <Landmark className="w-5 h-5 text-impulse" />
                    </div>
                    <div className="flex-1">
                      <p className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Saiu da conta</p>
                      <p className="text-sm font-semibold">
                        {(receivable as any).source_account
                          ? ((receivable as any).source_account.name || (receivable as any).source_account.bank_name)
                          : (receivable as any).source_account_id ? "Conta de Origem" : "N├úo definida"}
                      </p>
                    </div>
                  </div>
                )}
              </div>

              {/* Description */}
              {receivable.description && (
                <div className="p-4 rounded-2xl bg-secondary/10 border border-border/50">
                  <p className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground mb-1">Notas</p>
                  <p className="text-sm text-foreground/80 leading-relaxed">{receivable.description}</p>
                </div>
              )}
            </div>
          </Card>
        </FadeIn>

        {/* Action Buttons */}
        {!allReceived && (
          <FadeIn delay={0.1}>
            <div className="space-y-3">
              <Button
                variant="default"
                size="lg"
                className="w-full h-14 text-base gap-2"
                onClick={handleMarkAsReceived}
                disabled={updateReceivable.isPending}
              >
                <CheckCircle2 className="w-5 h-5" />
                Marcar como recebido
              </Button>

              <Button
                variant="outline"
                size="lg"
                className="w-full h-14 text-base gap-2"
                onClick={handleSendReminder}
              >
                <MessageCircle className="w-5 h-5 text-[#25D366]" />
                Enviar cobran├ºa via WhatsApp
              </Button>
            </div>
          </FadeIn>
        )}
      </main>

      {/* Delete Dialog */}
      <DeleteConfirmDialog
        open={showDeleteDialog}
        onOpenChange={setShowDeleteDialog}
        onConfirm={handleDelete}
        isInstallment={!!(receivable as any).installment_group_id}
        title={(receivable as any).installment_group_id ? "Excluir parcelas?" : "Excluir valor a receber?"}
        description="Esta a├º├úo n├úo pode ser desfeita."
        isLoading={deleteReceivable.isPending}
        entityName="valor a receber"
      />
    </div>
  );
};

export default ReceivableDetail;

import { useState, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    PieChart,
    Pie,
    Cell,
    Legend
} from "recharts";
import {
    ArrowLeft,
    Calendar,
    ChevronLeft,
    ChevronRight,
    TrendingUp,
    TrendingDown,
    PieChart as PieIcon,
    BarChart3,
    LayoutGrid,
    Filter
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { BottomNav } from "@/components/BottomNav";
import { FadeIn } from "@/components/ui/motion";
import { format, startOfMonth, endOfMonth, subMonths, addMonths, isWithinInterval } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useExpenses } from "@/hooks/useExpenses";
import { useCardInstallmentsByMonth } from "@/hooks/useCreditCards";
import { defaultCategories, categoryGroups, type CategoryGroup } from "@/lib/categories";
import { cn } from "@/lib/utils";
import { useAllCategories } from "@/hooks/useCategories";

const COLORS = [
    "#3B82F6", "#10B981", "#EF4444", "#8B5CF6", "#F59E0B",
    "#EC4899", "#14B8A6", "#6366F1", "#94A3B8"
];

export default function Reports() {
    const navigate = useNavigate();
    const [selectedMonth, setSelectedMonth] = useState(new Date());
    const [viewMode, setViewMode] = useState<"category" | "group">("group");

    const monthStart = startOfMonth(selectedMonth);
    const monthEnd = endOfMonth(selectedMonth);
    const prevMonthStart = startOfMonth(subMonths(selectedMonth, 1));
    const prevMonthEnd = endOfMonth(subMonths(selectedMonth, 1));

    // Current month data
    const { data: expenses = [] } = useExpenses();
    const { data: installments = [] } = useCardInstallmentsByMonth(format(selectedMonth, "yyyy-MM"));

    // Prev month data (to compare)
    const { data: prevInstallments = [] } = useCardInstallmentsByMonth(format(subMonths(selectedMonth, 1), "yyyy-MM"));

    const { allCategories } = useAllCategories();

    // Aggregate current month
    const reportData = useMemo(() => {
        // 1. Manual expenses for current month
        const monthExpenses = expenses.filter(e =>
            e.status !== "deleted" &&
