// ÔöÇÔöÇÔöÇ Regex Patterns para os principais bancos brasileiros ÔöÇÔöÇÔöÇ
const BANK_PATTERNS: { bank: string; regex: RegExp; swap?: boolean }[] = [
    // Padr├Áes de COMPRA/D├ëBITO (cart├úo)
    { bank: "Nubank", regex: /(?:compra|d├®bito|debit).*?R\$\s*([\d.,]+).*?(?:em|no|na|at)\s+(.+?)(?:\.|$)/i },
    { bank: "Inter", regex: /(?:compra|d├®bito).*?R\$\s*([\d.,]+)\s*[-ÔÇô]\s*(.+?)(?:\.|$)/i },
    { bank: "Ita├║", regex: /(?:compra|d├®bito)\s+(?:cart├úo\s+)?R\$\s*([\d.,]+)\s+(.+?)(?:\.|$)/i },
    { bank: "Bradesco", regex: /d├®bito\s+R\$\s*([\d.,]+)\s+(.+?)(?:\.|$)/i },
    { bank: "C6", regex: /C6\s*Bank.*?R\$\s*([\d.,]+)\s+(?:em\s+)?(.+?)(?:\.|$)/i },
    { bank: "Mercado Pago", regex: /(?:voc├¬ pagou|pagamento).*?R\$\s*([\d.,]+)\s+(?:para\s+)?(.+?)(?:\.|$)/i },
    { bank: "Caixa", regex: /(?:caixa|cef).*?compra\s+R\$\s*([\d.,]+)\s+(.+?)(?:\.|$)/i },
    { bank: "Santander", regex: /santander.*?R\$\s*([\d.,]+)\s+(.+?)(?:\.|$)/i },

    // Padr├Áes de PIX (enviado: valor vem primeiro)
    { bank: "Pix", regex: /pix\s+(?:enviado|realizado|feito|efetuado).*?R\$\s*([\d.,]+).*?(?:para|a)\s+(.+?)(?:\.|,\s*$|$)/i },
    // Pix recebido: nome vem primeiro, valor depois ÔåÆ swap=true
    { bank: "Pix", regex: /pix\s+(?:recebido|receber).*?(?:de|do\(a\)|do|da)\s+(.+?),?\s*(?:no\s+)?valor\s+(?:de\s+)?R\$\s*([\d.,]+)/i, swap: true },
    // Transfer├¬ncias
    { bank: "Pix", regex: /(?:transfer├¬ncia|transferencia)\s+(?:enviada|realizada|recebida).*?R\$\s*([\d.,]+).*?(?:para|de|do|da)\s+(.+?)(?:\.|,\s*$|$)/i },

    // Padr├úo gen├®rico (deve ser o ├║ltimo)
    { bank: "Banco", regex: /R\$\s*([\d.,]+).*?(?:em|no|na|para|de)\s+(.+?)(?:\.|,\s*$|$)/i },
];

// ÔöÇÔöÇÔöÇ Legacy: Chave secreta para POST antigo ÔöÇÔöÇÔöÇ
const INJECT_SECRET = Deno.env.get("INJECT_SECRET") || "saldin_inject_2026";

// ÔöÇÔöÇÔöÇ WhatsApp Send Helpers ÔöÇÔöÇÔöÇ
async function sendWhatsApp(to: string, text: string): Promise<{ ok: boolean; errorCode?: number }> {
    if (!META_ACCESS_TOKEN || !META_PHONE_NUMBER_ID) return { ok: false };
    try {
        const url = `https://graph.facebook.com/v22.0/${META_PHONE_NUMBER_ID}/messages`;
        const res = await fetch(url, {
            method: "POST",
            headers: { Authorization: `Bearer ${META_ACCESS_TOKEN}`, "Content-Type": "application/json" },
            body: JSON.stringify({
                messaging_product: "whatsapp",
                to,
                type: "text",
                text: { body: text },
            }),
        });
        const data = await res.json();
        if (data.error) {
            console.error("sendWhatsApp error:", data.error.code, data.error.message);
            return { ok: false, errorCode: data.error.code };
        }
        return { ok: true };
    } catch (e) {
        console.error("sendWhatsApp error:", e);
        return { ok: false };
    }
}

async function sendWhatsAppTemplate(
    to: string,
    templateName: string,
    params: string[]
): Promise<boolean> {
    if (!META_ACCESS_TOKEN || !META_PHONE_NUMBER_ID) return false;
    try {
        const url = `https://graph.facebook.com/v22.0/${META_PHONE_NUMBER_ID}/messages`;
        const res = await fetch(url, {
            method: "POST",
            headers: { Authorization: `Bearer ${META_ACCESS_TOKEN}`, "Content-Type": "application/json" },
            body: JSON.stringify({
                messaging_product: "whatsapp",
                to,
                type: "template",
                template: {
                    name: templateName,
                    language: { code: "pt_BR" },
                    components: [{
                        type: "body",
                        parameters: params.map(p => ({ type: "text", text: p })),
                    }],
                },
            }),
        });
        const data = await res.json();
        if (data.error) {
            console.error(`Template '${templateName}' failed:`, data.error.code, data.error.message);
            return false;
        }
        console.info(`Ô£à Template '${templateName}' sent to ${to}`);
        return true;
    } catch (e) {
        console.error("sendWhatsAppTemplate error:", e);
        return false;
    }
}

async function sendInteractive(to: string, text: string, buttons: { id: string; title: string }[]) {
