// ÔöÇÔöÇÔöÇ Parser de Texto de Notifica├º├úo ÔöÇÔöÇÔöÇ
function parseNotificationText(text: string): { valor: number; estabelecimento: string; banco: string } | null {
    const cleanText = text.trim();

    for (const { bank, regex, swap } of BANK_PATTERNS) {
        const match = cleanText.match(regex);
        if (match) {
            // swap=true: group(1)=nome, group(2)=valor (ex: Pix recebido)
            const rawValue = (swap ? match[2] : match[1]).replace(/\./g, "").replace(",", ".");
            const valor = parseFloat(rawValue);
            if (isNaN(valor) || valor <= 0) continue;

            const rawEstab = swap ? match[1] : match[2];
            const estabelecimento = rawEstab
                ?.trim()
                .replace(/\*+/g, "")
                .replace(/\s+/g, " ")
                .substring(0, 80) || "Compra";

            return { valor, estabelecimento, banco: bank };
        }
    }

    return null;
}

// ÔöÇÔöÇÔöÇ Normaliza n├║mero de telefone para E.164 ÔöÇÔöÇÔöÇ
function normalizePhone(phone: string): string {
    const digits = phone.replace(/\D/g, "");
    if (digits.startsWith("55")) return digits;
    if (digits.length === 10 || digits.length === 11) return `55${digits}`;
    return digits;
}

// ÔöÇÔöÇÔöÇ Busca usu├írio por capture_token (novo fluxo GET simplificado) ÔöÇÔöÇÔöÇ
async function findUserByToken(token: string) {
    const { data, error } = await supabase
        .from("whatsapp_users")
        .select("user_id, phone_number, is_verified, capture_token")
        .eq("capture_token", token)
        .eq("is_verified", true)
        .maybeSingle();

    if (error) {
        console.error("Token lookup error:", error);
        return null;
    }
    return data;
}

// ÔöÇÔöÇÔöÇ Busca usu├írio por telefone (fluxo POST legado) ÔöÇÔöÇÔöÇ
async function findUserByPhone(phone: string) {
    const normalizedPhone = normalizePhone(phone);
    const phoneVariations = [normalizedPhone];
    if (normalizedPhone.startsWith("55") && normalizedPhone.length === 13) {
        const ddd = normalizedPhone.substring(2, 4);
        const num = normalizedPhone.substring(4);
        phoneVariations.push(`55${ddd}${num.substring(1)}`);
    } else if (normalizedPhone.startsWith("55") && normalizedPhone.length === 12) {
        const ddd = normalizedPhone.substring(2, 4);
        const num = normalizedPhone.substring(4);
        phoneVariations.push(`55${ddd}9${num}`);
    }

    const { data, error } = await supabase
        .from("whatsapp_users")
        .select("user_id, phone_number, is_verified")
        .in("phone_number", phoneVariations)
        .eq("is_verified", true)
        .limit(1)
        .maybeSingle();

    if (error) {
        console.error("Phone lookup error:", error);
        return null;
    }
    return data;
}

// ÔöÇÔöÇÔöÇ Processa a transa├º├úo e envia no WhatsApp ÔöÇÔöÇÔöÇ
async function processAndNotify(userId: string, phoneToReply: string, text: string, source: string) {
    const parsed = parseNotificationText(text);

    if (!parsed) {
        console.log("Ôä╣´©Å Notification not parseable as transaction. Ignoring silently.");
        return { status: "ignored", reason: "not_a_transaction" };
    }

    console.log(`­ƒÆ© Parsed: R$ ${parsed.valor} em "${parsed.estabelecimento}" (${parsed.banco})`);

    // IA para categoria
    const aiText = `Gastei R$ ${parsed.valor} em ${parsed.estabelecimento}`;
    let intent: any = null;
    try {
        intent = await analyzeText(aiText);
    } catch (e) {
        console.warn("AI analysis failed, using defaults:", e);
    }

    // Conta/cart├úo de destino
    const metodo = intent?.items?.[0]?.metodo_pagamento || "pix";
    const { id: targetAccountId, isCreditCard } = await getPreferredAccount(userId, metodo);

    // Registra transa├º├úo
    const tCode = generateTransactionCode();
    const categoryId = intent?.items?.[0]?.categoria_sugerida
        ? await getCategoryId(userId, intent.items[0].categoria_sugerida)
        : null;

    const result = await processTransaction({
        userId,
        type: "expense",
        amount: parsed.valor,
        description: parsed.estabelecimento,
        categoryId: categoryId || undefined,
        bankAccountId: targetAccountId || undefined,
        transactionCode: tCode,
        isCreditCard,
    });

    // Log de auditoria
    await supabase.from("whatsapp_logs").insert({
        phone_number: phoneToReply,
        whatsapp_user_id: null,
        message_content: JSON.stringify({ text, source, parsed }),
        message_type: "auto_notification",
        processed: true,
        processing_result: { valor: parsed.valor, estabelecimento: parsed.estabelecimento, tCode },
    });

    // Monta resposta premium
    const alerts = await getImportantAlerts(userId);
    const premiumMsg = formatPremiumMessage(
        {
            id: result.id,
            description: parsed.estabelecimento,
            amount: parsed.valor,
            date: new Date().toISOString(),
            category: intent?.items?.[0]?.categoria_sugerida || "Compras",
            account_name: result.dest_name,
            type: "expense",
            transaction_code: tCode,
            account_balance: result.account_balance,
        },
        { new_balance: result.new_balance },
        alerts
    );

    const finalMsg = `­ƒöö *Auto-Captura Ativa*\n_Detectei uma compra via ${parsed.banco}_\n\n${premiumMsg}`;

    // Tenta enviar mensagem interativa (com bot├Áes)
    const msgResult = await sendWhatsApp(phoneToReply, finalMsg);

    if (!msgResult.ok && msgResult.errorCode === 131047) {
        // Janela de 24h expirada ÔåÆ tenta template
        console.info("ÔÅ░ 24h window expired, trying template fallback...");
        const categoria = intent?.items?.[0]?.categoria_sugerida || "Compras";
        await sendWhatsAppTemplate(phoneToReply, "auto_capture_confirmation", [
            String(parsed.valor).replace(".", ","),
            parsed.estabelecimento,
            categoria,
            tCode,
        ]);
    } else if (msgResult.ok) {
        // Mensagem de texto funcionou, agora envia os bot├Áes
        await sendInteractive(phoneToReply, `A├º├Áes para ${tCode}:`, [
            { id: `excluir_${tCode}`, title: "­ƒùæ´©Å Excluir" },
            { id: `editar_${tCode}`, title: "­ƒôØ Editar" },
        ]);
    }

    console.log(`Ô£à Auto-registered: R$ ${parsed.valor} | ${parsed.estabelecimento} | Code: ${tCode}`);

    return {
        status: "success",
        transaction_code: tCode,
        valor: parsed.valor,
        estabelecimento: parsed.estabelecimento,
        banco: parsed.banco,
    };
}

// ÔöÇÔöÇÔöÇ MAIN HANDLER ÔöÇÔöÇÔöÇ
Deno.serve(async (req: Request) => {
    // CORS
    if (req.method === "OPTIONS") {
        return new Response("ok", {
            headers: {
                "Access-Control-Allow-Origin": "*",
                "Access-Control-Allow-Headers": "Content-Type, Authorization",
            },
        });
    }

    const url = new URL(req.url);

    try {
        // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
        // ­ƒåò FLUXO GET ÔÇö Simplificado para MacroDroid
        // URL: /inject-notification?t=TOKEN&n=TEXTO_DA_NOTIFICACAO
        // O MacroDroid s├│ precisa de "Abrir URL" com essa URL.
        // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
        if (req.method === "GET") {
            const token = url.searchParams.get("t");
            const notificationText = url.searchParams.get("n");

            if (!token || !notificationText) {
                return new Response(JSON.stringify({ error: "Par├ómetros t e n s├úo obrigat├│rios" }), {
                    status: 400,
                    headers: { "Content-Type": "application/json" },
                });
            }

            console.log(`­ƒô▓ [GET] Token: ${token.substring(0, 8)}... | Text: ${notificationText.substring(0, 60)}`);

            // Busca usu├írio pelo token
            const userLink = await findUserByToken(token);
            if (!userLink) {
                console.warn("ÔØî Invalid or unverified token:", token.substring(0, 8));
                return new Response(JSON.stringify({ error: "Token inv├ílido" }), {
                    status: 401,
                    headers: { "Content-Type": "application/json" },
                });
            }

            const result = await processAndNotify(
                userLink.user_id,
                userLink.phone_number,
                notificationText,
                "macrodroid_get"
            );

            return new Response(JSON.stringify(result), {
                status: 200,
                headers: { "Content-Type": "application/json" },
            });
        }

        // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
        // ­ƒô« FLUXO POST ÔÇö Legado (mantido por compatibilidade)
        // Body: { secret, phone, text, source }
        // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
        if (req.method === "POST") {
            const body = await req.json();
            console.log("­ƒô▓ [POST] Received:", JSON.stringify(body));

            // Autentica├º├úo por secret ou token
            const secret = body.secret || req.headers.get("x-saldin-secret");
            const token = body.token;

            let userId: string;
            let phoneToReply: string;

            if (token) {
                // Novo: auth por token
                const userLink = await findUserByToken(token);
                if (!userLink) {
                    return new Response(JSON.stringify({ error: "Token inv├ílido" }), { status: 401 });
                }
                userId = userLink.user_id;
                phoneToReply = userLink.phone_number;
            } else if (secret === INJECT_SECRET) {
                // Legacy: auth por secret + phone
                const { phone, text } = body;
                if (!phone || !text) {
                    return new Response(JSON.stringify({ error: "phone e text s├úo obrigat├│rios" }), { status: 400 });
                }
                const userLink = await findUserByPhone(phone);
                if (!userLink) {
                    return new Response(JSON.stringify({ error: "Usu├írio n├úo encontrado" }), { status: 404 });
                }
                userId = userLink.user_id;
                phoneToReply = userLink.phone_number;
            } else {
                return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
            }

            const text = body.text;
            if (!text) {
                return new Response(JSON.stringify({ error: "text ├® obrigat├│rio" }), { status: 400 });
            }

            const result = await processAndNotify(userId, phoneToReply, text, body.source || "api_post");

            return new Response(JSON.stringify(result), {
                status: 200,
                headers: { "Content-Type": "application/json" },
            });
        }

        return new Response("Method Not Allowed", { status: 405 });

    } catch (e) {
        console.error("ÔØî inject-notification fatal error:", e);
        return new Response(JSON.stringify({ error: String(e) }), { status: 500 });
    }
});

// ÔöÇÔöÇÔöÇ Helper: busca category_id por nome ÔöÇÔöÇÔöÇ
async function getCategoryId(userId: string, name: string): Promise<string | null> {
    const { data } = await supabase
        .from("categories")
        .select("id")
        .eq("user_id", userId)
        .ilike("name", `%${name}%`)
        .eq("type", "expense")
        .limit(1)
        .maybeSingle();

    if (data) return data.id;

    const { data: fallback } = await supabase
        .from("categories")
        .select("id")
        .eq("user_id", userId)
        .ilike("name", "%outros%")
        .eq("type", "expense")
        .limit(1)
        .maybeSingle();

    return fallback?.id || null;
}

// Audio Processing Service (Transcription) using OpenAI Whisper
import { OpenAI } from "npm:openai";

const openai = new OpenAI({
    apiKey: Deno.env.get("OPENAI_API_KEY")!,
});

/**
 * Transcribes audio using OpenAI's Whisper model.
 * 
 * @param buffer The audio file buffer
 * @param mimeType The MIME type of the audio file (default: audio/ogg)
 * @returns The transcribed text
 */
export async function transcribeAudio(
    buffer: ArrayBuffer,
    mimeType: string = "audio/ogg"
): Promise<string> {
    try {
        if (!buffer || buffer.byteLength === 0) {
            throw new Error("Empty audio buffer provided.");
        }

        console.log(`­ƒÄñ Transcribing audio: ${(buffer.byteLength / 1024).toFixed(2)} KB, Mime: ${mimeType}`);

        // Create a file-like object for OpenAI SDK
        const blob = new Blob([buffer], { type: mimeType });
        const file = new File([blob], "audio.ogg", { type: mimeType });

        const response = await openai.audio.transcriptions.create({
            file: file,
            model: "whisper-1",
            language: "pt",
            response_format: "text",
        });

        const text = typeof response === "string" ? response : (response as any).text;
        console.log("Ô£à Transcription complete:", text);

        return text;
    } catch (error) {
        console.error("ÔØî Transcription failed:", error);
        throw error;
    }
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
const supabaseAdmin = createClient(SUPABASE_URL, SERVICE_ROLE_KEY);

interface TransactionData {
    userId: string;
    type: "expense" | "income";
    amount: number;
    description: string;
    categoryId?: string;
    bankAccountId?: string;
    date?: string; // YYYY-MM-DD
    transactionCode: string;
    isCreditCard?: boolean;
    metodo?: string; // Add method for logging/debugging
}

export async function processTransaction(data: TransactionData) {
    const { userId, type, amount, description, categoryId, bankAccountId, date, transactionCode, isCreditCard } = data;
    const finalDate = date ? new Date(date).toISOString() : new Date().toISOString();

    try {
        let result;
        let error;

        if (isCreditCard && type === 'expense') {
            if (!bankAccountId) {
                throw new Error("N├úo encontrei um cart├úo cadastrado para vincular este gasto.");
            }

            // Register as Credit Card Purchase
            const payload: any = {
                user_id: userId,
                card_id: bankAccountId, // bankAccountId acts as cardId here
                total_amount: amount,
                description,
                purchase_date: finalDate,
                total_installments: 1, // Default to 1 for WhatsApp unless otherwise specified
                transaction_code: transactionCode, // Ensure we store the code here too
                created_at: finalDate
            };
            if (categoryId) payload.category_id = categoryId;

            const { data: purchase, error: err } = await supabaseAdmin
                .from('credit_card_purchases')
                .insert(payload)
                .select('*, card:credit_cards(card_name)')
                .single();

            result = purchase;
            error = err;

            // Generate first installment
            if (purchase && !error) {
                // Ensure reference_month is the 1st of the month
                const d = new Date(finalDate);
                const refMonth = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-01`;

                await supabaseAdmin
                    .from('credit_card_installments')
                    .insert({
                        user_id: userId,
                        purchase_id: purchase.id,
                        amount: amount,
                        installment_number: 1,
                        reference_month: refMonth,
                        status: 'open'
                    });
            }

            return {
                ...result,
                new_balance: await getBalance(userId),
                dest_name: result?.card?.card_name || "Cart├úo",
                is_credit_card: true
            };
        }

        if (type === 'expense') {
            const payload: any = {
                user_id: userId,
                amount,
                description,
                date: finalDate,
                source: 'whatsapp',
                status: 'confirmed',
                confirmed_at: finalDate,
                transaction_code: transactionCode,
                created_at: finalDate
            };
            if (categoryId) payload.category_id = categoryId;
            if (bankAccountId) payload.bank_account_id = bankAccountId;

            const { data: exp, error: err } = await supabaseAdmin
                .from('expenses')
                .insert(payload)
                .select('*, bank_account:bank_accounts(bank_name)')
                .single();
            result = exp;
            error = err;
        } else {
            let incomeType = 'other';
            const descLower = description.toLowerCase();
            if (descLower.includes('sal├írio') || descLower.includes('salario')) incomeType = 'salary';
            else if (descLower.includes('freelance') || descLower.includes('freela')) incomeType = 'freelance';
            else if (descLower.includes('investimento')) incomeType = 'investment';
            else if (descLower.includes('presente')) incomeType = 'gift';

            const payload: any = {
                user_id: userId,
                amount,
                description,
                date: finalDate,
                type: incomeType,
                is_recurring: false,
                transaction_code: transactionCode,
                created_at: finalDate,
                status: 'active'
            };
            if (categoryId) payload.category_id = categoryId;
            if (bankAccountId) payload.bank_account_id = bankAccountId;

            const { data: inc, error: err } = await supabaseAdmin
                .from('incomes')
                .insert(payload)
                .select('*, bank_account:bank_accounts(bank_name)')
                .single();
            result = inc;
            error = err;
        }

        if (error) {
            console.error("ÔØî DB Insert Error:", JSON.stringify(error));
            throw error;
        }

        // Update Bank Account Balance if linked
        let accountBalance: number | undefined;
        if (bankAccountId && !isCreditCard) {
            const { data: acc } = await supabaseAdmin
                .from('bank_accounts')
                .select('current_balance')
                .eq('id', bankAccountId)
                .single();

            if (acc) {
                const currentBal = Number(acc.current_balance) || 0;
                const newAccBal = type === 'income' ? (currentBal + amount) : (currentBal - amount);

                await supabaseAdmin
                    .from('bank_accounts')
                    .update({ current_balance: newAccBal })
                    .eq('id', bankAccountId);

                accountBalance = newAccBal;
            }
        }

        const newBalance = await getBalance(userId);

        return {
            ...result,
            new_balance: newBalance,
            account_balance: accountBalance,
            dest_name: result?.bank_account?.bank_name || result?.card?.card_name || (isCreditCard ? "Cart├úo" : "Conta"),
            is_credit_card: isCreditCard
        };

    } catch (err) {
        console.error("Financial Transaction Failed:", err);
        throw new Error("Erro ao registrar transa├º├úo no banco.");
    }
}


export async function getBalance(userId: string): Promise<number> {
    const now = new Date();
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
    const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59).toISOString();
    const refMonthStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`;

    // 1. Bank Total
    const { data: banks } = await supabaseAdmin.from('bank_accounts').select('current_balance').eq('user_id', userId).eq('active', true);
    const bankTotal = banks?.reduce((acc: number, b: any) => acc + Number(b.current_balance), 0) || 0;

    // 2. Unlinked Transactions (Confirmed but not in a bank account yet)
    // Incomes
    const { data: unlinkedIncomes } = await supabaseAdmin.from('incomes')
        .select('amount')
        .eq('user_id', userId)
        .is('bank_account_id', null)
        .or('status.eq.received,status.eq.confirmed')
        .gte('date', monthStart)
        .lte('date', monthEnd);
    const confirmedUnlinkedIncome = unlinkedIncomes?.reduce((acc: number, i: any) => acc + Number(i.amount), 0) || 0;

    // Expenses
    const { data: unlinkedExpenses } = await supabaseAdmin.from('expenses')
        .select('amount')
        .eq('user_id', userId)
        .is('bank_account_id', null)
        .eq('status', 'confirmed')
        .gte('date', monthStart)
        .lte('date', monthEnd);
    const confirmedUnlinkedExpenses = unlinkedExpenses?.reduce((acc: number, e: any) => acc + Number(e.amount), 0) || 0;

    const saldoBruto = bankTotal + confirmedUnlinkedIncome - confirmedUnlinkedExpenses;

    // 3. Commitments (Saldo Comprometido)
    // Pending essential/pilar expenses
    const { data: pendingExpenses } = await supabaseAdmin.from('expenses')
        .select('amount')
        .eq('user_id', userId)
        .eq('status', 'pending')
        .or('emotion.eq.essencial,emotion.eq.pilar')
        .gte('date', monthStart)
        .lte('date', monthEnd);
    const pendingTotal = pendingExpenses?.reduce((acc: number, e: any) => acc + Number(e.amount), 0) || 0;

    // Active debts
    const { data: debts } = await supabaseAdmin.from('debts')
        .select('total_amount, installment_amount, is_installment')
        .eq('user_id', userId)
        .eq('status', 'active');
    const debtTotal = debts?.reduce((acc: number, d: any) => acc + Number(d.is_installment ? (d.installment_amount || 0) : d.total_amount), 0) || 0;

    // CC Installments for the month
    const { data: ccInstallments } = await supabaseAdmin.from('credit_card_installments')
        .select('amount')
        .eq('user_id', userId)
        .eq('reference_month', refMonthStr)
        .eq('status', 'open');
    const ccTotal = ccInstallments?.reduce((acc: number, inst: any) => acc + Number(inst.amount), 0) || 0;

    const saldoComprometido = pendingTotal + debtTotal + ccTotal;

    // 4. Goals Saved (Saldo Guardado)
    const { data: goals } = await supabaseAdmin.from('goals')
        .select('current_amount')
        .eq('user_id', userId)
        .neq('is_personal', false)
        .eq('status', 'in_progress');
    const saldoGuardado = goals?.reduce((acc: number, g: any) => acc + Number(g.current_amount), 0) || 0;

    // 5. Saldo Livre = Saldo Bruto - Comprometido - Guardado
    return saldoBruto - saldoComprometido - saldoGuardado;
}

export async function getLastTransactions(userId: string, limit = 5) {
    // Busca expenses e incomes recentes
    const { data: exp, error: errExp } = await supabaseAdmin
        .from('expenses')
        .select('amount, description, date, category_id')
        .eq('user_id', userId)
        .order('date', { ascending: false })
        .limit(limit);

    const { data: inc, error: errInc } = await supabaseAdmin
        .from('incomes')
        .select('amount, description, date, type') // Removed category_id, added type
        .eq('user_id', userId)
        .order('date', { ascending: false })
        .limit(limit);

    if (errExp || errInc) {
        const msg = errExp?.message || errInc?.message || "Unknown DB Error";
        console.error("Get Transactions Failed:", msg);
        throw new Error(`DB Error: ${msg}`);
    }

    // Merge expenses and incomes
    const all = [
        ...(exp || []).map((e: any) => ({ ...e, type: 'expense' })),
        ...(inc || []).map((i: any) => ({ ...i, type: 'income' }))
    ];

    // Sort by date descending
    all.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return all.slice(0, limit);
}

export async function getPreferredAccount(userId: string, method?: string): Promise<{ id: string | null; isCreditCard: boolean }> {
    const { data: profile } = await supabaseAdmin
        .from('profiles')
        .select('wa_default_income_account_id, wa_default_expense_account_id, wa_default_expense_card_id')
        .eq('user_id', userId)
        .single();

    const cleanMethod = method?.toLowerCase().trim();
    const isPaymentMethodDebitLike = cleanMethod && ['pix', 'debito', 'd├®bito', 'dinheiro', 'esp├®cie', 'especie', 'boleto'].some(m => cleanMethod.includes(m));

    // 1. Try to find matching Bank Account first if it's a debit-like method
    if (isPaymentMethodDebitLike) {
        // Try to match the specific name if provided (e.g., "Inter" in "pix no inter")
        // We need to extract the bank name part. GPT usually puts everything in method if it's names.
        // Let's try to match the method name against bank accounts first.
        const { data: matchedAcc } = await supabaseAdmin
            .from('bank_accounts')
            .select('id')
            .eq('user_id', userId)
            .eq('active', true)
            .ilike('bank_name', `%${cleanMethod.replace('pix', '').replace('debito', '').replace('d├®bito', '').trim()}%`)
            .maybeSingle();

        if (matchedAcc) return { id: matchedAcc.id, isCreditCard: false };
    }

    // 2. Try to find a matching Credit Card by name (e.g., "Inter", "Nubank")
    if (cleanMethod && !['credito', 'cart├úo', 'cartao', 'pix', 'debito', 'd├®bito'].includes(cleanMethod)) {
        const { data: matchedCard } = await supabaseAdmin
            .from('credit_cards')
            .select('id')
            .eq('user_id', userId)
            .eq('active', true)
            .ilike('card_name', `%${cleanMethod}%`)
            .maybeSingle();

        if (matchedCard) return { id: matchedCard.id, isCreditCard: true };
    }

    // 3. Try to find a matching Bank Account by name (e.g., "Ita├║", "Cofre")
    if (cleanMethod && !isPaymentMethodDebitLike) {
        const { data: matchedAcc } = await supabaseAdmin
            .from('bank_accounts')
            .select('id')
            .eq('user_id', userId)
            .eq('active', true)
            .ilike('bank_name', `%${cleanMethod}%`)
            .maybeSingle();

        if (matchedAcc) return { id: matchedAcc.id, isCreditCard: false };
    }

    // 3. Fallback to default Credit Card logic
    if (cleanMethod && ['credito', 'cart├úo', 'cartao', 'visa', 'master', 'elo', 'amex'].some(m => cleanMethod.includes(m))) {
        if (profile?.wa_default_expense_card_id) {
            return { id: profile.wa_default_expense_card_id, isCreditCard: true };
        }

        const { data: card } = await supabaseAdmin
            .from('credit_cards')
            .select('id')
            .eq('user_id', userId)
            .eq('active', true)
            .limit(1)
            .maybeSingle();

        return { id: card?.id || null, isCreditCard: !!card };
    }

    // 4. Default: Check for default accounts (Pix, Debit, etc.)
    if (profile?.wa_default_expense_account_id) return { id: profile.wa_default_expense_account_id, isCreditCard: false };
    if (profile?.wa_default_income_account_id) return { id: profile.wa_default_income_account_id, isCreditCard: false };

    // Fallback: Any active bank account
    const { data: acc } = await supabaseAdmin
        .from('bank_accounts')
        .select('id')
        .eq('user_id', userId)
        .eq('active', true)
        .order('account_type', { ascending: true })
        .limit(1)
        .maybeSingle();

    return { id: acc?.id || null, isCreditCard: false };
}

