            for (const card of cards) {
                // A. Vencimento da Fatura
                if (card.due_day === today || card.due_day === tomorrowDay) {
                    const { data: statement } = await supabaseAdmin
                        .from('credit_card_statements')
                        .select('total_amount, status')
                        .eq('card_id', card.id)
                        .eq('reference_month', currentMonthStr)
                        .maybeSingle();

                    if (statement && statement.status !== 'paid' && Number(statement.total_amount) > 0) {
                        const when = card.due_day === today ? "Hoje" : "Amanh├ú";
                        alerts.push(`­ƒÆ│ *Fatura ${when}:* ${card.card_name} (R$ ${formatCurrencyAlert(statement.total_amount)})`);
                    }
                }

                // B. Alerta de Limite Dispon├¡vel
                if (card.credit_limit && Number(card.credit_limit) > 0) {
                    // Busca limite ocupado do cart├úo via parcelas abertas
                    const { data: purchases } = await supabaseAdmin
                        .from('credit_card_purchases')
                        .select('id')
                        .eq('card_id', card.id);

                    if (purchases && purchases.length > 0) {
                        const purchaseIds = purchases.map(p => p.id);
                        const { data: openInst } = await supabaseAdmin
                            .from('credit_card_installments')
                            .select('amount')
                            .in('purchase_id', purchaseIds)
                            .eq('status', 'open');

                        const usedLimit = openInst?.reduce((sum, inst) => sum + Number(inst.amount), 0) || 0;
                        const available = Number(card.credit_limit) - usedLimit;
                        const pctAvailable = (available / Number(card.credit_limit)) * 100;

                        if (pctAvailable < 15 && available > 0) {
                            alerts.push(`­ƒøí´©Å *Limite Baixo:* ${card.card_name} tem apenas ${pctAvailable.toFixed(0)}% dispon├¡vel (R$ ${formatCurrencyAlert(available)}).`);
                        } else if (available <= 0) {
                            alerts.push(`­ƒÜ½ *Cart├úo Sem Limite:* ${card.card_name} atingiu o limite m├íximo.`);
                        }
                    }
                }
            }
        }

        // 4. Assinaturas (Hoje e Amanh├ú)
        const { data: subs } = await supabaseAdmin
            .from('subscriptions')
            .select('name, amount, billing_date')
            .eq('user_id', userId)
            .eq('status', 'active');

        if (subs) {
            subs.forEach((s: any) => {
                if (s.billing_date === today) {
                    alerts.push(`­ƒôà *Assinatura Hoje:* ${s.name} (R$ ${formatCurrencyAlert(s.amount)})`);
                } else if (s.billing_date === tomorrowDay) {
                    alerts.push(`­ƒòÆ *Assinatura Amanh├ú:* ${s.name} (R$ ${formatCurrencyAlert(s.amount)})`);
                }
            });
        }

        // 5. D├¡vidas vencendo hoje
        const { data: debts } = await supabaseAdmin
            .from('debts')
            .select('creditor_name, installment_amount, total_amount, is_installment, due_date')
            .eq('user_id', userId)
            .eq('status', 'active');

        if (debts) {
            debts.forEach((d: any) => {
                if (d.due_date) {
                    const due = new Date(d.due_date);
                    if (due.getUTCDate() === today && due.getUTCMonth() === now.getMonth()) {
                        alerts.push(`­ƒÆ© *D├¡vida Hoje:* ${d.creditor_name} (R$ ${formatCurrencyAlert(d.is_installment ? d.installment_amount : d.total_amount)})`);
                    }
                }
            });
        }

    } catch (err) {
        console.error("Error generating alerts:", err);
    }

    return alerts;
}

function formatCurrencyAlert(val: number | string) {
    const num = typeof val === 'string' ? parseFloat(val) : val;
    return new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(num || 0);
}

