function normalizeTo(phone: string): string {
    // Handling Brazil 9th digit for Meta Test Accounts
    // If it's 55 + DDD (2) + 8 digits, add the '9'
    if (phone.startsWith("55") && phone.length === 12) {
        console.log(`­ƒöº Normalizing Brazil number: ${phone} -> ${phone.substring(0, 4)}9${phone.substring(4)}`);
        return phone.substring(0, 4) + "9" + phone.substring(4);
    }
    return phone;
}

async function sendWhatsApp(to: string, text: string): Promise<void> {
    if (!META_ACCESS_TOKEN || !META_PHONE_NUMBER_ID) {
        console.error("ÔØî Missing META credentials");
        return;
    }

    const normalizedToValue = normalizeTo(to);
    console.log(`­ƒôñ [v22.0] Sending Text to ${normalizedToValue}...`);
    try {
        const url = `https://graph.facebook.com/v22.0/${META_PHONE_NUMBER_ID}/messages`;
        const resp = await fetch(url, {
            method: "POST",
            headers: { "Authorization": `Bearer ${META_ACCESS_TOKEN}`, "Content-Type": "application/json" },
            body: JSON.stringify({
                messaging_product: "whatsapp",
                to: normalizedToValue,
                type: "text",
                text: { body: text }
            })
        });
        const data = await resp.json();
        console.log(`Ô£à Response for ${normalizedToValue}:`, JSON.stringify(data));
        if (data.error) console.error("ÔØî Meta API Error:", data.error);
    } catch (e) { console.error(`ÔØî Failed:`, e); }
}

