        if (logId && intent) {
            await supabaseAdmin.from("whatsapp_logs").update({ processing_result: intent, processed: intent.status === "ok" }).eq("id", logId);
        }

        if (!intent || intent.tipo === 'duvida') {
            if (textToAnalyze) {
                await sendWhatsApp(phoneToSend, "­ƒñö N├úo consegui identificar a opera├º├úo. Se for um registro, use o formato: 'Valor Descri├º├úo' (ex: '50 cafezinho').");
            }
            return new Response("Ok", { status: 200 });
        }

        // 6. Execute Intent
        if (intent.status === "incompleto") {
            await sendWhatsApp(phoneToSend, "­ƒñö Pode me dar mais detalhes? Preciso do *valor*, da *descri├º├úo* e de *como voc├¬ pagou* (ex: pix, d├®bito, cr├®dito ou dinheiro).");
            return new Response("Incomplete", { status: 200 });
        }

        if (intent.tipo === 'consulta_saldo') {
            const balance = await getBalance(userId);
            const alerts = await getImportantAlerts(userId);
            const formatted = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(balance);

            let msg = `­ƒÆ░ Seu saldo atual ├®: *${formatted}*`;
            if (alerts.length > 0) {
                msg += `\n\nÔÜá´©Å *AVISOS IMPORTANTES*\n${alerts.map(a => `ÔÇó ${a}`).join('\n')}`;
            }
            await sendWhatsApp(phoneToSend, msg);
            return new Response("OK", { status: 200 });
        }

        if (intent.tipo === 'consulta_extrato') {
            await sendExtrato(userId, phoneToSend);
            return new Response("OK", { status: 200 });
        }

        // 7. MULTIPLE TRANSACTIONS PROCESSING
        if (intent.tipo === 'transacao' || (intent.items && intent.items.length > 0)) {
            const isSingle = intent.items.length === 1;
            let summaryMsg = isSingle ? "" : "Ô£à *RESUMO DAS OPERA├ç├òES*\nÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü\n\n";
            let totalProcessed = 0;
            let lastTCode = "";

            for (const item of intent.items) {
                try {
                    const categoryId = await getCategoryId(userId, item.categoria_sugerida, item.tipo === "receita" ? "income" : "expense");
                    const { id: targetAccountId, isCreditCard } = await getPreferredAccount(userId, item.metodo_pagamento);
                    const tCode = generateTransactionCode();
                    lastTCode = tCode;

                    const result = await processTransaction({
                        userId,
                        type: item.tipo === "receita" ? "income" : "expense",
                        amount: item.valor,
                        description: item.descricao,
                        categoryId: categoryId || undefined,
                        bankAccountId: targetAccountId || undefined,
                        transactionCode: tCode,
                        isCreditCard: isCreditCard
                    });

                    const valStr = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(item.valor);
                    const icon = item.tipo === 'receita' ? '­ƒÆ░' : '­ƒÆ©';

                    if (isSingle) {
                        const alerts = await getImportantAlerts(userId);
                        summaryMsg = formatPremiumMessage({
                            id: result.id,
                            description: item.descricao,
                            amount: item.valor,
                            date: new Date().toISOString(),
                            category: item.categoria_sugerida,
                            account_name: result.dest_name,
                            type: item.tipo === "receita" ? "income" : "expense",
                            transaction_code: tCode,
                            account_balance: result.account_balance
                        }, { new_balance: result.new_balance }, alerts);
                    } else {
                        summaryMsg += `${icon} *${item.descricao}*\n   Valor: *${valStr}*\n   ID: \`${tCode}\`\n\n`;
                    }
                    totalProcessed++;
                } catch (err) {
                    console.error(`ÔØî Item Failed: ${item.descricao}`, err);
                }
            }

            if (totalProcessed > 0) {
                if (isSingle) {
                    await sendWhatsAppInteractive(phoneToSend, summaryMsg, [
                        { id: `excluir_${lastTCode}`, title: "­ƒùæ´©Å Excluir" },
                        { id: `editar_${lastTCode}`, title: "­ƒôØ Editar" }
                    ]);
                } else {
                    const balance = await getBalance(userId);
                    const alerts = await getImportantAlerts(userId);
                    const balStr = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(balance);
                    summaryMsg += "ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü\n";
                    summaryMsg += `­ƒôè *SALDO TOTAL:* ${balStr}\n`;

                    if (alerts.length > 0) {
                        summaryMsg += `\nÔÜá´©Å *AVISOS IMPORTANTES*\n${alerts.map(a => `ÔÇó ${a}`).join('\n')}\n`;
                    }

                    summaryMsg += `\n_Para excluir, use: excluir ID_`;
                    await sendWhatsApp(phoneToSend, summaryMsg);
                }
            } else {
                // If it failed because of a specific reason, we might want to tell the user
                await sendWhatsApp(phoneToSend, "ÔØî N├úo consegui processar seu pedido. Verifique se voc├¬ possui contas/cart├Áes cadastrados ou se o valor est├í correto.");
            }

            return new Response("Multi-Success", { status: 200 });
        }

        return new Response("No Action", { status: 200 });

    } catch (e) {
        console.error("Fatal Error:", e);
        if (logId) await supabaseAdmin.from("whatsapp_logs").update({ processed: true, error_message: String(e) }).eq("id", logId);
        return new Response("Internal Error", { status: 500 });
    }
});


async function sendExtrato(userId: string, phone: string) {
    try {
        const queryLimit = 10;
        const { data: exps } = await supabaseAdmin.from('expenses').select('amount, description, date, created_at').eq('user_id', userId).order('created_at', { ascending: false }).limit(queryLimit);
        const { data: incs } = await supabaseAdmin.from('incomes').select('amount, description, date, type, created_at').eq('user_id', userId).order('created_at', { ascending: false }).limit(queryLimit);
        const { data: ccs } = await supabaseAdmin.from('credit_card_purchases').select('total_amount, description, purchase_date, created_at').eq('user_id', userId).order('created_at', { ascending: false }).limit(queryLimit);

        const trs = [
            ...(exps || []).map((e: any) => ({ ...e, type: 'expense' })),
            ...(incs || []).map((i: any) => ({ ...i, type: 'income' })),
            ...(ccs || []).map((c: any) => ({ amount: c.total_amount, description: c.description, created_at: c.created_at, type: 'expense', isCC: true }))
        ]
            .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
            .slice(0, 7); // Show last 7

        if (!trs.length) {
            await sendWhatsApp(phone, "­ƒôä Nenhuma transa├º├úo recente encontrada.");
        } else {
            let msg = "­ƒôä *EXTRATO RECENTE*\n";
            msg += "ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü\n\n";
            trs.forEach((t: any) => {
                const val = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(t.amount));
                const icon = t.type === 'income' ? '­ƒÆ░' : '­ƒÆ©';
                const dateStr = new Date(t.created_at).toLocaleDateString('pt-BR');
                const suffix = (t as any).isCC ? " ­ƒÆ│" : "";
                msg += `${icon} *${t.description}*${suffix}\n   ${val} ÔÇó _${dateStr}_\n\n`;
            });
            msg += "ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü\n";

            // Add alerts to Extrato too
            const alerts = await getImportantAlerts(userId);
            if (alerts.length > 0) {
                msg += `ÔÜá´©Å *AVISOS IMPORTANTES*\n${alerts.map(a => `ÔÇó ${a}`).join('\n')}\nÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü\n`;
            }

            msg += "_Saldin ÔÇó Controle Total._ Ô£¿";
            await sendWhatsApp(phone, msg);
        }
    } catch (e) {
        console.error("Extrato error:", e);
    }
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
const supabaseAdmin = createClient(SUPABASE_URL, SERVICE_ROLE_KEY);

interface Transaction {
    id: string;
    description: string;
    amount: number;
    date: string;
    category?: string;
    account_name?: string; // Clearer name
    type: 'income' | 'expense';
    transaction_code: string;
    account_balance?: number; // Balance of the specific account used
}

export function generateTransactionCode(): string {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'; // No letters/numbers that look alike (I, O, 0, 1)
    let code = '';
    for (let i = 0; i < 4; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return code;
}

export function formatPremiumMessage(transaction: Transaction, balanceData: any, alerts: string[] = [], isDelete = false): string {
    const { transaction_code, amount, description, category, account_name, type, account_balance } = transaction;
    const formattedAmount = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(amount));

    // Date and Time adjusted for Brazil (UTC-3)
    const now = new Date();
    const dateStr = now.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
    const timeStr = now.toLocaleTimeString('pt-BR', {
        hour: '2-digit',
        minute: '2-digit',
        timeZone: 'America/Sao_Paulo'
    });

    let header = isDelete ? "­ƒùæ´©Å *TRANSA├ç├âO REMOVIDA*" : (type === 'income' ? "­ƒÆ░ *RECEITA REGISTRADA*" : "­ƒÆ© *GASTO CONFIRMADO*");
    const divider = "ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü";

    const details = `
­ƒôØ *${description}*
­ƒÆÁ *${formattedAmount}*

­ƒôé Categoria: _${category || 'Geral'}_
­ƒÅª Origem/Destino: _${account_name || 'Conta Padr├úo'}_
­ƒôà Data: _${dateStr} ├ás ${timeStr}_
­ƒöæ ID: \`${transaction_code}\`
`.trim();

    const impact = `
­ƒôè *RESUMO FINANCEIRO*
Saldo Livre: R$ ${formatCurrency(balanceData.new_balance)}
${account_balance !== undefined ? `Carteira (${account_name}): R$ ${formatCurrency(account_balance)}` : ''}
`.trim();

    let alertsSection = "";
    if (alerts.length > 0) {
        alertsSection = `\n\nÔÜá´©Å *AVISOS IMPORTANTES*\n${alerts.map(a => `ÔÇó ${a}`).join('\n')}\n`;
    }

    return `
${header}

${divider}
${details}
${divider}

${impact}${alertsSection}

_Dica: Se errou algo, clique em *Editar* abaixo ou digite: *excluir ${transaction_code}*_
`.trim();
}

function formatCurrency(val: number) {
    return new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(val);
}


export async function handleExcluirCommand(userId: string, code: string): Promise<{ success: boolean; message: string }> {
    console.log(`­ƒùæ´©Å Processing DELETE for code: ${code}, User: ${userId}`);

    const formattedCode = code.toUpperCase().trim();
    if (!/^[A-Z2-9]{4}$/.test(formattedCode)) {
        console.warn(`ÔÜá´©Å Invalid code format: ${formattedCode}`);
        return { success: false, message: "ÔÜá´©Å C├│digo inv├ílido. O ID deve ter 4 caracteres (ex: A1B2)." };
    }

    // 2. Find Transaction
    const { data: exp } = await supabaseAdmin
        .from('expenses')
        .select('*')
        .eq('transaction_code', formattedCode)
        .eq('user_id', userId)
        .maybeSingle();

    const { data: inc } = await supabaseAdmin
        .from('incomes')
        .select('*')
        .eq('transaction_code', formattedCode)
        .eq('user_id', userId)
        .maybeSingle();

    if (!exp && !inc) {
        console.warn(`ÔØî Transaction ${formattedCode} not found for user ${userId}`);
        return { success: false, message: "ÔÜá´©Å Transa├º├úo n├úo encontrada ou n├úo pertence a voc├¬." };
    }

    const target = exp || inc;
    const type = exp ? 'expense' : 'income'; // 'expense' | 'income'

    if (target.deleted_at) {
        return { success: true, message: "ÔÜá´©Å Esta transa├º├úo j├í foi exclu├¡da anteriormente." };
    }

    // 3. Revert Bank Account Balance if linked
    if (target.bank_account_id) {
        const { data: acc } = await supabaseAdmin
            .from('bank_accounts')
            .select('current_balance')
            .eq('id', target.bank_account_id)
            .single();

        if (acc) {
            const currentBal = Number(acc.current_balance) || 0;
            const amount = Number(target.amount);
            // If it was an expense, we ADD back. If it was income, we SUBTRACT.
            const newBal = type === 'expense' ? (currentBal + amount) : (currentBal - amount);

            await supabaseAdmin
                .from('bank_accounts')
                .update({ current_balance: newBal })
                .eq('id', target.bank_account_id);

            console.log(`­ƒÅª Balance reverted for account ${target.bank_account_id}: ${currentBal} -> ${newBal}`);
        }
    }

    // 4. Soft Delete
    const updatePayload = { deleted_at: new Date().toISOString(), status: 'deleted' };
    const tableName = type === 'expense' ? 'expenses' : 'incomes';

    const { error: updateErr } = await supabaseAdmin
        .from(tableName)
        .update(updatePayload)
        .eq('id', target.id);

    if (updateErr) {
        console.error("Soft delete failed:", updateErr);
        return { success: false, message: "ÔØî Erro ao excluir transa├º├úo." };
    }

    // 5. Log Audit
    await supabaseAdmin.from('transaction_audit_logs').insert({
        transaction_id: target.id,
        transaction_type: type,
        action: 'delete',
        user_id: userId,
        changed_fields: updatePayload
    });

    // 6. Get Updated Total Balance
    const { data: banks } = await supabaseAdmin
        .from('bank_accounts')
        .select('current_balance')
        .eq('user_id', userId)
        .eq('active', true);

    const newBalance = banks?.reduce((acc: number, b: any) => acc + Number(b.current_balance), 0) || 0;
    const formattedBalance = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(newBalance);

    return {
        success: true,
        message: `­ƒùæ´©Å Transa├º├úo ${formattedCode} removida com sucesso.\n\n­ƒÆ░ Saldo atualizado: *${formattedBalance}*`
    };
}


export async function handleEditarCommand(userId: string, code: string): Promise<{ success: boolean; message: string }> {
    const formattedCode = code.toUpperCase().trim();
    // 1. Validate Code
    if (!/^[A-Z2-9]{4}$/.test(formattedCode)) return { success: false, message: "ÔÜá´©Å C├│digo inv├ílido. Use o ID de 4 caracteres (ex: A1B2)." };

    // 2. Verify Existence
    const { data: exp } = await supabaseAdmin.from('expenses').select('*').eq('transaction_code', formattedCode).eq('user_id', userId).maybeSingle();
    const { data: inc } = await supabaseAdmin.from('incomes').select('*').eq('transaction_code', formattedCode).eq('user_id', userId).maybeSingle();

    if (!exp && !inc) return { success: false, message: "ÔÜá´©Å Transa├º├úo n├úo encontrada." };

    // 3. Set State
    await supabaseAdmin.from('conversation_states').upsert({
        user_id: userId,
        step: 'awaiting_edit_selection',
        context: { transaction_code: formattedCode, type: exp ? 'expense' : 'income' },
        updated_at: new Date().toISOString(),
    });

    return {
        success: true,
        message: `O que deseja alterar na transa├º├úo ${formattedCode}?\n\n1 - Valor\n2 - Categoria\n3 - Descri├º├úo\n\nResponda com o n├║mero ou nome da op├º├úo.`
    };
}

export async function processEditStep(userId: string, input: string): Promise<{ success: boolean; message: string; done: boolean }> {
    // 1. Get State
    const { data: state } = await supabaseAdmin.from('conversation_states').select('*').eq('user_id', userId).single();
    if (!state) return { success: false, message: "", done: false };

    const { step, context } = state;
    const { transaction_code, type } = context;

    if (step === 'awaiting_edit_selection') {
        let nextStep = '';
        let prompt = '';

        if (['1', 'valor'].includes(input.toLowerCase())) {
            nextStep = 'awaiting_new_value_amount';
            prompt = 'Digite o novo valor (ex: 50.00):';
        } else if (['2', 'categoria'].includes(input.toLowerCase())) {
            nextStep = 'awaiting_new_value_category';
            prompt = 'Digite a nova categoria:';
        } else if (['3', 'descri├º├úo', 'descricao'].includes(input.toLowerCase())) {
            nextStep = 'awaiting_new_value_description';
            prompt = 'Digite a nova descri├º├úo:';
        } else {
            return { success: false, message: "ÔÜá´©Å Op├º├úo inv├ílida. Escolha 1, 2 ou 3.", done: false };
        }

        await supabaseAdmin.from('conversation_states').update({ step: nextStep }).eq('user_id', userId);
        return { success: true, message: prompt, done: false };
    }

    if (step.startsWith('awaiting_new_value_')) {
        const field = step.replace('awaiting_new_value_', '');
        let updateData: any = {};

        if (field === 'amount') {
            const val = parseFloat(input.replace(',', '.').replace('R$', '').trim());
            if (isNaN(val)) return { success: false, message: "ÔÜá´©Å Valor inv├ílido.", done: false };
            updateData['amount'] = val;
        } else if (field === 'category') {
            // Logic to find category ID might be needed here, or just store text if simple
            // Assuming category ID lookup or text storage based on system design.
            // For simplicity, we might update description or metadata, but 'category_id' usually requires ID lookup.
            // Let's assume we update a text field or perform lookup (omitted for brevity, just treating as text/id)
            updateData['category_source'] = input; // This assumes a generic field or would fail if ID required.
            // Real impl needs category lookup helper.
        } else if (field === 'description') {
            updateData['description'] = input;
        }

        // Perform Update
        const table = type === 'expense' ? 'expenses' : 'incomes';
        const { error } = await supabaseAdmin.from(table).update(updateData).eq('transaction_code', transaction_code);

        if (error) return { success: false, message: "ÔØî Erro ao atualizar transa├º├úo.", done: true };

        // Clear State
        await supabaseAdmin.from('conversation_states').delete().eq('user_id', userId);

        return { success: true, message: `Ô£à Transa├º├úo ${transaction_code} atualizada com sucesso!`, done: true };
    }

    return { success: false, message: "", done: false };
}

